-- Poems batch 294
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2a30a16a-cd8d-4b7e-85d1-9dde71ff4bc9','静夜','司馬光','宋','宋诗','song-poetry','','[]','午夜空齋四悄然，清寒透骨不成眠。',32,'全唐诗/poet.song.29000.json','["午夜空齋四悄然，清寒透骨不成眠。", "秋風故掲疏簾起，正漏月華來枕前。"]'),
('4929e72f-1a29-491e-b7db-b89b4f7ffe55','春','司馬光','宋','宋诗','song-poetry','','[]','紅桃素李競年華，周偏長安萬萬家。',32,'全唐诗/poet.song.29000.json','["紅桃素李競年華，周偏長安萬萬家。", "何事青青庭下柏，東風吹盡亦無花。"]'),
('17c419c7-7518-4dde-9964-32d8a2a6e915','送導江李主簿君俞','司馬光','宋','宋诗','song-poetry','','[]','學海無涯富，辭鋒一戰勛。',120,'全唐诗/poet.song.29000.json','["學海無涯富，辭鋒一戰勛。", "聲華掩終賈，賦頌繼淵雲。", "五斗爲邊吏，千倉飽戍軍。", "明恩美尤異，優秩賞能勤。", "黄祖陰懷怒，張湯巧用文。", "折雖因木秀，燒不變蘭薰。", "迹有窮通異，心無得喪分。", "龍蛇寧久蟄，玉石豈俱焚。", "蜀國花饒思，臨邛酒易醺。", "西風時有意，尺紙慰離羣。"]'),
('241d6229-6be7-4224-87bb-b26d002e9bec','送峽州陳廉秘丞  其一','司馬光','宋','宋诗','song-poetry','','[]','宜都賢太守，治迹古人齊。',48,'全唐诗/poet.song.29000.json','["宜都賢太守，治迹古人齊。", "虎負衆子去，鳳環羣鳥棲。", "行增潁川秩，别降武都泥。", "正恐還朝速，春林未子規。"]'),
('9a434737-9306-4095-8b19-d3665782b8a7','送峽州陳廉秘丞  其二','司馬光','宋','宋诗','song-poetry','','[]','郡府猿聲外，旌旗鳥道邊。',48,'全唐诗/poet.song.29000.json','["郡府猿聲外，旌旗鳥道邊。", "樓高出楚塞，煙霽識巴船。", "襦袴嗟来暮，簪紳惜外遷。", "皇仁矜遠俗，非謂意疏賢。"]'),
('4da1edfd-a003-471e-9b4c-1c9f3f5d9c6a','送峽州陳廉秘丞  其三','司馬光','宋','宋诗','song-poetry','','[]','地險三巴口，江流百折蟠。',48,'全唐诗/poet.song.29000.json','["地險三巴口，江流百折蟠。", "騶珂通峽響，門戟照秋寒。", "翠壁虎牙石，素花狼尾灘。", "孫劉置柵處，細爲寫圖看。"]'),
('31478586-7a76-47a2-a204-d9beea17abd7','武成致齋奉酬吳沖卿寺丞太學宿直見寄二首  其一','司馬光','宋','宋诗','song-poetry','','[]','廣文更直太常齋，咫尺無從盡素懷。',32,'全唐诗/poet.song.29000.json','["廣文更直太常齋，咫尺無從盡素懷。", "不及清風得隨意，夜深容易過天街。"]'),
('fec06097-2f56-4fc4-b184-68c95387d5e2','武成致齋奉酬吳沖卿寺丞太學宿直見寄二首  其二','司馬光','宋','宋诗','song-poetry','','[]','雪後餘冰尚綴簷，月華霜氣入疏簾。',32,'全唐诗/poet.song.29000.json','["雪後餘冰尚綴簷，月華霜氣入疏簾。", "難堪瓊玉驚心骨，坐覺清寒幾倍添。"]'),
('d37e3ad7-238b-4664-8621-8facc54a8bbf','雪中尋友人不遇','司馬光','宋','宋诗','song-poetry','','[]','擁袖犯風雪，驅車行詣誰。',48,'全唐诗/poet.song.29000.json','["擁袖犯風雪，驅車行詣誰。", "朱門不可入，素友復難期。", "依世誠多拙，迷方忽自悲。", "褊心終寡合，吾道易參差。"]'),
('0dd5e69b-27dd-40e6-ab24-0a50374b573a','河邊晚望','司馬光','宋','宋诗','song-poetry','','[]','高浪崩奔捲白沙，悠悠極望入天涯。',32,'全唐诗/poet.song.29000.json','["高浪崩奔捲白沙，悠悠極望入天涯。", "誰能脫落塵中意，乘興東遊坐石槎。"]'),
('044776a2-9b92-4507-b0cc-e5cfb5e6a4ca','早春寄東郡舊同僚','司馬光','宋','宋诗','song-poetry','','[]','樓臺带餘雪，寒色未全收。',48,'全唐诗/poet.song.29000.json','["樓臺带餘雪，寒色未全收。", "久負入關意，空爲同舍羞。", "清樽接勝友，飛蓋從賢侯。", "應恨春來晚，烟林已數游。"]'),
('b2046d9d-2c75-45b3-9c49-641edb89a97a','邊將  其一','司馬光','宋','宋诗','song-poetry','','[]','紅旗一簇聚山椒，霽日清風看射雕。',32,'全唐诗/poet.song.29000.json','["紅旗一簇聚山椒，霽日清風看射雕。", "脫帽少年遙稽首，漢家新將霍嫖姚。"]'),
('375ce42f-e8e3-405f-a7f9-0e04f12d6ca3','邊將  其二','司馬光','宋','宋诗','song-poetry','','[]','月白星稀霜氣多，卷旗束甲涉葱河。',32,'全唐诗/poet.song.29000.json','["月白星稀霜氣多，卷旗束甲涉葱河。", "田家不覺官軍度，夜半只聞風雨過。"]'),
('ab2af278-88f8-4ddf-b453-dba8d35fde56','邊將  其三','司馬光','宋','宋诗','song-poetry','','[]','横吹長笛千萬騎，將軍塞北立功迴。',32,'全唐诗/poet.song.29000.json','["横吹長笛千萬騎，將軍塞北立功迴。", "邊人爭出孤城望，漸見旌旗天外来。"]'),
('cb1a9fbd-f636-43f5-825d-6952d15d2c41','漁父','司馬光','宋','宋诗','song-poetry','','[]','楚岸橘花香，扁舟泛渺茫。',48,'全唐诗/poet.song.29000.json','["楚岸橘花香，扁舟泛渺茫。", "短蓑衝密雨，素髪凈秋霜。", "煙外鳴桹遠，波間擲線長。", "無人識名姓，擊楫入滄浪。"]'),
('0f421366-acee-477d-8f2f-b5c68c48414b','早春  其一','司馬光','宋','宋诗','song-poetry','','[]','梅梢柳萼未全開，日澹風和春意來。',32,'全唐诗/poet.song.29000.json','["梅梢柳萼未全開，日澹風和春意來。", "雨後誰家有桃李，會須多買及時栽。"]'),
('0c9d4c16-2c63-44f3-9c0c-7b0c2e57d666','早春  其二','司馬光','宋','宋诗','song-poetry','','[]','璿霄轉斗車，春意逼梅花。',48,'全唐诗/poet.song.29000.json','["璿霄轉斗車，春意逼梅花。", "熟寐侵街鼓，閑情到酒家。", "晴陽浮地末，寒色斂天涯。", "歸鴈空餘迹，朝來印浦沙。"]'),
('e0e7dfe2-66ec-47a6-a810-2d5902101bd2','山中早春','司馬光','宋','宋诗','song-poetry','','[]','山木欣欣意，春光次第催。',48,'全唐诗/poet.song.29000.json','["山木欣欣意，春光次第催。", "欹巾望歸鴈，伏檻聽新雷。", "巖静聞冰折，巢空喜燕來。", "澗花從寂寞，亦向草堂開。"]'),
('d1f8cc95-d731-4124-b5a7-b005df562935','贈學仙者','司馬光','宋','宋诗','song-poetry','','[]','微逕透重巒，茅堂竹葉冠。',48,'全唐诗/poet.song.29000.json','["微逕透重巒，茅堂竹葉冠。", "方瞳映骨靜，秀氣逼人寒。", "夜火裝丹竈，晴霜醮石壇。", "不須驚淺俗，輕舉入雲端。"]'),
('abb5f6ce-8194-4c28-aa34-2c237d6d8f01','留别友生','司馬光','宋','宋诗','song-poetry','','[]','野際共爲别，客亭芳草新。',48,'全唐诗/poet.song.29000.json','["野際共爲别，客亭芳草新。", "何心更執酒，滿目盡傷春。", "今古無窮路，東西相背塵。", "行行復回首，不欲着鞭頻。"]'),
('13c14693-dc0b-4e6f-8d68-ebfdd7591e03','二月六日初見待漏房前柳色微綠欣然成詠','司馬光','宋','宋诗','song-poetry','','[]','宮城映出絲絲綠，頓覺皇州春意迴。',32,'全唐诗/poet.song.29000.json','["宮城映出絲絲綠，頓覺皇州春意迴。", "從此不辭驅瘦馬，六街終日踏塵埃。"]'),
('473584bb-d8d3-4c68-8837-dd6670196e1b','垂柳','司馬光','宋','宋诗','song-poetry','','[]','天意清和二月初，春風不動整如梳。',32,'全唐诗/poet.song.29000.json','["天意清和二月初，春風不動整如梳。", "陶潛宅外時無此，想更蕭條不易居。"]'),
('f6c56f4f-671f-4962-9882-735ce602e2d2','閑居','司馬光','宋','宋诗','song-poetry','','[]','故人通貴絕相過，門外真堪置雀羅。',32,'全唐诗/poet.song.29000.json','["故人通貴絕相過，門外真堪置雀羅。", "我已幽慵僮更懶，雨來春草一番多。"]'),
('3a5443c1-476a-4d56-a735-1d04ad8bf7e7','中秋陪張龍圖讌射堂初夕陰雲酒行頓解喜而成詠','司馬光','宋','宋诗','song-poetry','','[]','飛蓋共徘徊，西園高宴開。',24,'全唐诗/poet.song.29000.json','["飛蓋共徘徊，西園高宴開。", "秋雲惜明月，留待庾公來。"]'),
('26351089-0e76-47d0-8133-07558fda5543','貽宋四行簡迪','司馬光','宋','宋诗','song-poetry','','[]','離羣如幾辰，屈指十青春。',48,'全唐诗/poet.song.29000.json','["離羣如幾辰，屈指十青春。", "不意輪蹄跡，共兹京洛塵。", "文場投漆契，客路轉蓬身。", "别易相逢闊，過從莫厭頻。"]'),
('1d5318fd-7b26-4ebd-929a-89b1ab1e35e3','自嘲','司馬光','宋','宋诗','song-poetry','','[]','盤飱羅新蔬，充腹不求餘。',48,'全唐诗/poet.song.29000.json','["盤飱羅新蔬，充腹不求餘。", "窮巷晝扃戶，閑軒卧讀書。", "有心齊塞馬，無意羡川魚。", "世道方邀逐，如君術已疏。"]'),
('cf05548c-e6eb-4860-95f7-55ecdfa3da94','醉','司馬光','宋','宋诗','song-poetry','','[]','厚於太古暖於春，耳目無營見道真。',32,'全唐诗/poet.song.29000.json','["厚於太古暖於春，耳目無營見道真。", "果使屈原知醉趣，當年不作獨醒人。"]'),
('cc2fda37-8040-433d-acef-3b78ae1b9eed','雪寒取酒','司馬光','宋','宋诗','song-poetry','','[]','雪意久未就，寒雲低不收。',48,'全唐诗/poet.song.29000.json','["雪意久未就，寒雲低不收。", "飄揚插孤幟，迢遞映高樓。", "試假賢人濁，聊攻客子愁。", "呼僮攜小榼，更凖黑貂裘。"]'),
('d41cf5a9-5ed9-4be1-a477-8f3e26263b6f','虞部劉員外約遊金明光以賤事失期劉惠詩見嘲以詩四首謝之  其一','司馬光','宋','宋诗','song-poetry','','[]','絲管嘈嘈耳不分，綺羅雜踏自成春。',32,'全唐诗/poet.song.29000.json','["絲管嘈嘈耳不分，綺羅雜踏自成春。", "不唯漢帝昆明小，更覺唐家曲水貧。"]'),
('83bda73d-8f58-4492-907e-c3d8d8cd9e01','虞部劉員外約遊金明光以賤事失期劉惠詩見嘲以詩四首謝之  其二','司馬光','宋','宋诗','song-poetry','','[]','絳闕朝歸散玉珂，不遊不飲奈春何。',32,'全唐诗/poet.song.29000.json','["絳闕朝歸散玉珂，不遊不飲奈春何。", "皇仁聼使歡娛極，白簡從君冷峭多。"]'),
('af6c2fbf-9cef-495a-b06c-87294bc803a4','虞部劉員外約遊金明光以賤事失期劉惠詩見嘲以詩四首謝之  其三','司馬光','宋','宋诗','song-poetry','','[]','碧柳紅桃照眼春，綺肴芳醴集朝紳。',32,'全唐诗/poet.song.29000.json','["碧柳紅桃照眼春，綺肴芳醴集朝紳。", "自嫌林野疏頑迹，難預風流席上賓。"]'),
('973c1259-1a67-48b7-a88f-d8b36a7f40ef','虞部劉員外約遊金明光以賤事失期劉惠詩見嘲以詩四首謝之  其四','司馬光','宋','宋诗','song-poetry','','[]','上苑花繁高覆墻，曲堤風暖柳絲長。',32,'全唐诗/poet.song.29000.json','["上苑花繁高覆墻，曲堤風暖柳絲長。", "爐邊應有步兵尉，甕下難尋吏部郎。"]'),
('baecd145-c01e-47ae-8b3a-c8db4c78c88b','孫器之奉使淮浙至江爲書見寄以詩謝之  其一','司馬光','宋','宋诗','song-poetry','','[]','韊矢迎山驛，軺車下帝臺。',24,'全唐诗/poet.song.29000.json','["韊矢迎山驛，軺車下帝臺。", "夜看牛斗分，應有使星来。"]'),
('66010537-b443-490e-b191-79b7e76dfe50','孫器之奉使淮浙至江爲書見寄以詩謝之  其二','司馬光','宋','宋诗','song-poetry','','[]','曉棹旌旗迥，暮河鉦鼓喧。',24,'全唐诗/poet.song.29000.json','["曉棹旌旗迥，暮河鉦鼓喧。", "商船極目避，漢使一何尊。"]'),
('99b4bfb7-814c-49d0-9c89-e4c83fab1b80','孫器之奉使淮浙至江爲書見寄以詩謝之  其三','司馬光','宋','宋诗','song-poetry','','[]','吳釀木蘭春，紅鱸白錦鱗。',24,'全唐诗/poet.song.29000.json','["吳釀木蘭春，紅鱸白錦鱗。", "玉盤聊下筯，初識紫絲蓴。"]'),
('6dd1338a-d10c-48a7-b6a6-9d9af3db2291','孫器之奉使淮浙至江爲書見寄以詩謝之  其四','司馬光','宋','宋诗','song-poetry','','[]','岫貼晴天闊，舟緣石岸深。',24,'全唐诗/poet.song.29000.json','["岫貼晴天闊，舟緣石岸深。", "遙知作書處，纜裊綠波心。"]'),
('7b349e0c-df11-49c5-b767-3796a26b9dee','孫器之奉使淮浙至江爲書見寄以詩謝之  其五','司馬光','宋','宋诗','song-poetry','','[]','沙溆鸖爭飛，波光可染衣。',24,'全唐诗/poet.song.29000.json','["沙溆鸖爭飛，波光可染衣。", "松江異淇水，信美不如歸。"]'),
('59601012-4b09-4e14-ba9a-0cff9fcd6fb4','和國子夏主簿李花','司馬光','宋','宋诗','song-poetry','','[]','儒宮岑寂覺春閑，仙李繁花重壓欄。',64,'全唐诗/poet.song.29000.json','["儒宮岑寂覺春閑，仙李繁花重壓欄。", "碎錦不飛蒙樹合，素雲欹亞舉枝難。", "能詩此日當推謝，捧賜他年足繼桓。", "更約雕盤薦秋實，豈徒穠艷一朝看。"]'),
('6114a5c1-b51a-4136-95fb-732af7d34441','送聶之美攝尉韋城','司馬光','宋','宋诗','song-poetry','','[]','徒勞已足倦，漂泊益栖遑。',144,'全唐诗/poet.song.29000.json','["徒勞已足倦，漂泊益栖遑。", "短劍無三尺，征衣共一囊。", "折腰從事馬，贊謁使君堂。", "併日屢承檄，無時不裹糧。", "官曹大児戲，弓槊小軍行。", "破柱翻偷窟，傾林索盗囊。", "村墟旅顔黑，風日故衫黄。", "暝宿投煙舍，朝餐蔭道桑。", "唯憂課書殿，豈慕薦飛章。", "志氣空磅礴，才華浪激昂。", "鐫鑱圭始瑩，磨拂鑒尤光。", "衣褐仍纒袴，無羞俗吏裝。"]'),
('3a861ca7-bd2b-45ba-805b-99ea2e0eb438','送吳辨叔大名司戶  其一','司馬光','宋','宋诗','song-poetry','','[]','元宰司宮鑰，旌旄壓大河。',48,'全唐诗/poet.song.29000.json','["元宰司宮鑰，旌旄壓大河。", "敢言趨府倦，私歎折腰多。", "機發何妨避，光塵未免和。", "艱難方遠到，慶閥肯蹉跎。"]'),
('98228c64-c48b-4f4a-b2a3-8679852ffe9c','送吳辨叔大名司戶  其二','司馬光','宋','宋诗','song-poetry','','[]','致遠必自近，如君豈椽曹。',48,'全唐诗/poet.song.29000.json','["致遠必自近，如君豈椽曹。", "魚龍試春浪，松栝露秋毫。", "錯落辭華富，硜𥐪氣節高。", "垂天起膚寸，無歎走塵勞。"]'),
('92aa5d2d-aa3d-4a48-be42-be793d62540a','送楊太祝知長洲縣','司馬光','宋','宋诗','song-poetry','','[]','三吳佳縣首，民物舊熙熙。',48,'全唐诗/poet.song.29000.json','["三吳佳縣首，民物舊熙熙。", "專用清談治，非如俗吏爲。", "林疏丹橘迥，稻熟白芒欹。", "宜使民無忘，嚴修太伯祠。"]'),
('c75003fa-a200-46b8-b6a4-532d26bf485b','和邵興宗秋夜學舍宿直','司馬光','宋','宋诗','song-poetry','','[]','直舍逍遙度清夜，暫投逢掖解儒冠。',64,'全唐诗/poet.song.29000.json','["直舍逍遙度清夜，暫投逢掖解儒冠。", "高樓影背星河轉，疏竹氣兼風露寒。", "籬下黄花新蘂亂，門邊碧柳舊株殘。", "折腰把板今無有，勿似陶潛遂棄官。"]'),
('09b26c9d-f461-4cea-8d3f-11e37ae229ce','和吳冲卿病中偶書呈諸同舍光時亦卧疾','司馬光','宋','宋诗','song-poetry','','[]','病來門不掃，秋草翳吾廬。',72,'全唐诗/poet.song.29000.json','["病來門不掃，秋草翳吾廬。", "棄置賢人酒，蕭條長者車。", "冥迷牀鬬蟻，潤溽篋生魚。", "藥物從無繼，簞瓢自有餘。", "形神寂可弔，身世邈相疏。", "何事文園客，痟中亦著書。"]'),
('62c05721-e708-4404-87ce-2b9bf12836de','月下小飲','司馬光','宋','宋诗','song-poetry','','[]','美景賞心相值難，良宵四座盡儒冠。',64,'全唐诗/poet.song.29000.json','["美景賞心相值難，良宵四座盡儒冠。", "月華過冷衣襟潤，酒力易消樽俎寒。", "自有笑談供逸氣，不須絲竹借餘歡。", "坊樓五鼓欲催曙，桂影長先高興闌。"]'),
('084f6a70-418e-4f63-8041-b6d6954967a1','又絕句','司馬光','宋','宋诗','song-poetry','','[]','舉首孤輪不似遙，尊前狂氣出雲霄。',32,'全唐诗/poet.song.29000.json','["舉首孤輪不似遙，尊前狂氣出雲霄。", "常娥不惜惜丹桂，欲就高枝掛酒瓢。"]'),
('4954e826-a8a1-429c-9197-e53e25a9cd3c','馬病','司馬光','宋','宋诗','song-poetry','','[]','羸病何其久，仁心到棧頻。',48,'全唐诗/poet.song.29000.json','["羸病何其久，仁心到棧頻。", "須憐苜蓿歉，當認主人貧。", "客舍同蕭索，山程共苦辛。", "未能逢伯樂，且可自相親。"]'),
('8f087b98-1fad-4aed-91d4-f8992afe3b01','入塞','司馬光','宋','宋诗','song-poetry','','[]','萬騎入榆關，臯蘭苦戰還。',48,'全唐诗/poet.song.29000.json','["萬騎入榆關，臯蘭苦戰還。", "摧鋒佩刀缺，蹋血馬蹄殷。", "鐃吹來風外，牛羊出霧間。", "須知沙塞惡，壯士變衰顔。"]'),
('87b4dc24-45ae-4dca-bd4c-41f92401e18b','喜孫器之來自共城','司馬光','宋','宋诗','song-poetry','','[]','取友不無人，愛君天性真。',48,'全唐诗/poet.song.29000.json','["取友不無人，愛君天性真。", "遠尋窮巷宅，未拂滿衣塵。", "主禮貧尤重，交情别更親。", "誰家釀醇酒，盡醉準衣巾。"]'),
('7bb13806-3f18-47a7-b7fd-42e4279e1780','送韓太祝知錢塘','司馬光','宋','宋诗','song-poetry','','[]','冠佩鬰相映，由来積德家。',48,'全唐诗/poet.song.29000.json','["冠佩鬰相映，由来積德家。", "一時推雋異，四海走聲華。", "圖籍添舟重，江山忘路賖。", "夷塗指霄漢，跼驥不須嗟。"]'),
('c2e3b711-470d-469f-a11f-744d0f13296d','和聶之美鴈','司馬光','宋','宋诗','song-poetry','','[]','汲汲復栖栖，往來誰與期。',48,'全唐诗/poet.song.29000.json','["汲汲復栖栖，往來誰與期。", "映雲纔可見，入霧杳難追。", "羈枕夢初斷，寒閨涕已危。", "冥冥遠繒繳，愧爾獨知時。"]'),
('8b786b17-994c-43bd-a29a-fe69e899e7c1','送王太祝知伊闕','司馬光','宋','宋诗','song-poetry','','[]','百里驩迎新令賢，儒經吏術盡家傳。',64,'全唐诗/poet.song.29000.json','["百里驩迎新令賢，儒經吏術盡家傳。", "天開嶺阜竦雙闕，地雜桑麻隘一川。", "錦雉馴飛春陌上，雪鳬高去夕嵐邊。", "長才久屈君無限，所惜斯民受賜偏。"]'),
('b5578175-12b3-4952-b816-66271219c752','慶曆七年祀南郊禮畢賀赦','司馬光','宋','宋诗','song-poetry','','[]','雷鼓千通破大幽，天開獄鑰縱纍囚。',32,'全唐诗/poet.song.29000.json','["雷鼓千通破大幽，天開獄鑰縱纍囚。", "驛書散出先飛鳥，一日恩流四百州。"]'),
('aa0633d8-5acd-453c-95e7-d1377fab549c','送張太博知岳州','司馬光','宋','宋诗','song-poetry','','[]','嚴風秀木折爲薪，得罪由來爲出羣。',128,'全唐诗/poet.song.29000.json','["嚴風秀木折爲薪，得罪由來爲出羣。", "粥粥黄雞憎鸖介，芄芄青蔓掩蘭薰。", "天資讒嫉多端巧，人極精明不易分。", "飲水豈言吳刺史，謗書翻似馬將軍。", "波濤洶涌動寒野，樓閣嶣嶤壓暮雲。", "紅葉寺深秋暖見，蒼山鐘迥夜清聞。", "何妨絕境聊爲中，正恐中朝亟用君。", "身外百愁俱擲置，放歌沈飲且醺醺。"]'),
('861fd553-df75-45d1-b672-a541fe586c28','和之美河西列岫亭','司馬光','宋','宋诗','song-poetry','','[]','秋山對疏牖，羈客倦登臨。',96,'全唐诗/poet.song.29000.json','["秋山對疏牖，羈客倦登臨。", "雨後嵐光活，晴初落照深。", "素波明别浦，赤葉照衰林。", "佇目寂無語，何人知此心。", "亭臯資遠矚，秋思浩無涯。", "鴈唼牽菱蔓，童歌出荻花。", "壟荒猶叱犢，枝暗稍栖鴉。", "煙靄藏東渚，憑軒莫望家。"]'),
('d13da606-259e-4846-8e80-be64c51f1d4e','書事','司馬光','宋','宋诗','song-poetry','','[]','志士喜功業，感時心易勞。',48,'全唐诗/poet.song.29000.json','["志士喜功業，感時心易勞。", "蘖栽終栝柏，荒蔓任蓬蒿。", "梁竦慵爲吏，蕭咸恥詣曹。", "風霜果不變，會見出雲高。"]'),
('1b69094b-97cc-41f2-9a96-54dd868db99c','釣魚有感  其一','司馬光','宋','宋诗','song-poetry','','[]','垂竿臨晚岸，堅坐據莓苔。',48,'全唐诗/poet.song.29000.json','["垂竿臨晚岸，堅坐據莓苔。", "餌落萍初散，魚驚荷暫開。", "有求雖瑣細，未獲且低回。", "君識磻磎老，曾垂綠髪來。"]'),
('962ab5a4-8b68-477c-9230-00629e0bfba5','釣魚有感  其二','司馬光','宋','宋诗','song-poetry','','[]','野釣披榛竹，無人知往來。',24,'全唐诗/poet.song.29000.json','["野釣披榛竹，無人知往來。", "高空飛不下，鷗鳥已相猜。"]'),
('a4ccf2b9-6a3d-4faf-8cb8-078426f185d7','田家','司馬光','宋','宋诗','song-poetry','','[]','未塞豪人奪，何言公賦收。',48,'全唐诗/poet.song.29000.json','["未塞豪人奪，何言公賦收。", "皇心雖惻隱，蓬戶或焦愁。", "爲吏空多祿，無人能此憂。", "知君坐公府，佗日富民侯。"]'),
('e7a78794-6adf-4521-801b-83e84343b3aa','和人葦花','司馬光','宋','宋诗','song-poetry','','[]','葭菼迷河曲，高秋一番榮。',96,'全唐诗/poet.song.29000.json','["葭菼迷河曲，高秋一番榮。", "齊紈張野白，楚練照川明。", "不夜月長皎，踰時雪未晴。", "萬仙霓帔合，千畝玉苗生。", "漠漠波瀾偃，茫茫沙磧平。", "際空鹽海竭，垂地塞雲横。", "日暖鷗無色，風高鶴有聲。", "逢君得嘲賦，豈愧束薪并。"]'),
('2b1fbd59-6680-461d-a27b-81dacc9570a8','送趙書記之官華州','司馬光','宋','宋诗','song-poetry','','[]','車馬西城外，遙遙未有塵。',48,'全唐诗/poet.song.29000.json','["車馬西城外，遙遙未有塵。", "辭梁猶带雪，過洛漸生春。", "幕府斜依嶽，關山曲抱秦。", "曩来謨畫拙，不必笑前人。"]'),
('f5a2f325-d85d-4f55-ab54-fa251c0eda87','寄題陟屺寺','司馬光','宋','宋诗','song-poetry','','[]','鄭南峰下寺前軒，反景分明見渭川。',32,'全唐诗/poet.song.29000.json','["鄭南峰下寺前軒，反景分明見渭川。", "爲報十年容易别，於今愁悴不如先。"]'),
('7900ecc9-0eb9-46fe-a5f0-7d210bae98ef','寄鄭縣史令千之  其一','司馬光','宋','宋诗','song-poetry','','[]','憐君比比得佳縣，勝概閑情雙有餘。',32,'全唐诗/poet.song.29000.json','["憐君比比得佳縣，勝概閑情雙有餘。", "爲看西溪日沈後，如何南浦月生初。"]'),
('05378fe5-7e5d-4928-a70b-2eb4cb5f5b2d','寄鄭縣史令千之  其二','司馬光','宋','宋诗','song-poetry','','[]','長春宮柳遠扶疏，新樹應多舊已枯。',32,'全唐诗/poet.song.29000.json','["長春宮柳遠扶疏，新樹應多舊已枯。", "蠧柱苔牆偏尋歷，古亭猶有杜詩無。"]'),
('7be37511-3a72-492f-8eb3-4c4c00494c0c','送華亭沈主簿','司馬光','宋','宋诗','song-poetry','','[]','執袂青門道，蕭蕭馬欲東。',48,'全唐诗/poet.song.29000.json','["執袂青門道，蕭蕭馬欲東。", "暮雲零落翠，遠樹淺深紅。", "楚澤吟聲裏，吳山醉眼中。", "相思杳何許，野鶴唳高風。"]'),
('3f1b7317-52df-40de-8d19-8a8b997681f2','閏正月十五日夜監直對月懷諸同舍  其一','司馬光','宋','宋诗','song-poetry','','[]','霧浄金波溢，天開碧幕空。',48,'全唐诗/poet.song.29000.json','["霧浄金波溢，天開碧幕空。", "夜寒雖料峭，春意自冲融。", "熠熠枝上露，翛翛竹杪風。", "暫還林野興，不似畜樊籠。"]'),
('46d1088b-afd8-420e-b566-e7d0351b59c4','閏正月十五日夜監直對月懷諸同舍  其二','司馬光','宋','宋诗','song-poetry','','[]','澹薄春雲散，低昂北斗横。',48,'全唐诗/poet.song.29000.json','["澹薄春雲散，低昂北斗横。", "微分漢津鴈，静識建章更。", "濁酒憐虛爵，高文憶友生。", "前軒空不掩，悵息負孤清。"]'),
('417f8d58-6b16-4377-a1a0-467000ba3fcc','歸鴈','司馬光','宋','宋诗','song-poetry','','[]','亦知南國稻粱肥，水滿春江努力歸。',32,'全唐诗/poet.song.29000.json','["亦知南國稻粱肥，水滿春江努力歸。", "聞道楚人繒繳細，平沙短草盡藏機。"]'),
('1d046524-dbf1-4ead-854f-1d683b363942','憶龐之道','司馬光','宋','宋诗','song-poetry','','[]','疇昔兩垂髫，知音結久要。',48,'全唐诗/poet.song.29000.json','["疇昔兩垂髫，知音結久要。", "何言半塗别，不待歳寒彫。", "幸有才名在，非隨氣運消。", "英靈猶彷彿，宿草已蕭蕭。"]'),
('643e4323-f7c8-4101-a90c-326ee7983f6f','送鄭推官赴邠州  其一','司馬光','宋','宋诗','song-poetry','','[]','形便豳公國，旌旗擁將壇。',48,'全唐诗/poet.song.29000.json','["形便豳公國，旌旗擁將壇。", "秦雲低落日，塞樹怯春寒。", "草檄無留思，投壺不廢歡。", "還應笑黄卷，寂寂守儒官。"]'),
('af5c07eb-8259-4a02-81fd-7568b227feac','送鄭推官赴邠州  其二','司馬光','宋','宋诗','song-poetry','','[]','百榼行春樂，千弓從獵豪。',48,'全唐诗/poet.song.29000.json','["百榼行春樂，千弓從獵豪。", "苦吟邊月冷，飛鏑野風高。", "奇策鞭殊俗，長纓繫不毛。", "輸君躍馬貴，一等着青袍。"]'),
('d2e44500-149e-45a8-901a-221bf757b2d5','送鄭推官赴邠州  其三','司馬光','宋','宋诗','song-poetry','','[]','驕虜已歸計，聖朝方寢兵。',48,'全唐诗/poet.song.29000.json','["驕虜已歸計，聖朝方寢兵。", "時聞候火入，非復塞塵驚。", "秋嶺無南牧，春田恣北耕。", "休窮西海路，辛苦學甘英。"]'),
('049ec64c-e2a1-4eb5-8713-9bc54abd3a2e','興宗約遊會靈久不聞問以詩趣之','司馬光','宋','宋诗','song-poetry','','[]','勝地何妨行樂頻，萬雙白璧不賒春。',32,'全唐诗/poet.song.29000.json','["勝地何妨行樂頻，萬雙白璧不賒春。", "臘醅已老久未壓，楊柳青青不待人。"]'),
('08f9738b-5cf1-4a97-9c20-6f7e7f3c1a13','清明日興宗飲趙道士東軒','司馬光','宋','宋诗','song-poetry','','[]','佳遊得令辰，過此不爲春。',72,'全唐诗/poet.song.29000.json','["佳遊得令辰，過此不爲春。", "一境風光秀，萬家煙火新。", "燕初飛玉殿，草不染香輪。", "逼水蒲牙短，圍堤柳带勻。", "縱談高出古，落筆健生神。", "日暮還醒去，林花應笑人。"]'),
('8c045021-7b97-400e-a240-969687521206','上巳日與太學諸同舍飲王都尉園','司馬光','宋','宋诗','song-poetry','','[]','冠蓋鬰相依，名園花未稀。',48,'全唐诗/poet.song.29000.json','["冠蓋鬰相依，名園花未稀。", "游絲縈復展，狂絮墮還飛。", "積弩遺風陋，蘭亭舊俗微。", "何如詠沂水，春服舞雩歸。"]'),
('93aef283-c79c-44fa-8343-456bb1c38eac','寄題洪州慈濟師西軒','司馬光','宋','宋诗','song-poetry','','[]','登臨傳勝絕，悵息未成遊。',48,'全唐诗/poet.song.29000.json','["登臨傳勝絕，悵息未成遊。", "山氣高凌霽，湖光碧照秋。", "煙疏茶竈迥，燈冷竹房幽。", "安得聊憑檻，蕭然洗客愁。"]'),
('8f230da0-6f17-41d4-9def-ce9b3105eb59','山頭春色','司馬光','宋','宋诗','song-poetry','','[]','天意欲迴煦，羣生稍鬰蒸。',48,'全唐诗/poet.song.29000.json','["天意欲迴煦，羣生稍鬰蒸。", "平田猶未遍，絕嶺獨先升。", "翠色添崖柏，寒聲折澗冰。", "誰爲物外友，挈手共同登。"]'),
('7510a25a-8a26-498e-b690-224e76b5ee2b','三月十五日宿魏雲夫山莊','司馬光','宋','宋诗','song-poetry','','[]','先生嫌俗賓，猶與故鄉親。',120,'全唐诗/poet.song.29000.json','["先生嫌俗賓，猶與故鄉親。", "不惜烟霞地，暫容繮鎻身。", "林廬深有徑，雞犬四無鄰。", "蔌蔌闇花墮，蒼蒼古柏春。", "飯炊松粒細，盤采蕨芽新。", "静覺精神健，閑知氣味真。", "谿泉冷毛髪，山翠濕衣巾。", "竹色消酲易，林聲破夢頻。", "客輪来去轍，驛路古今塵。", "明日空迴首，白雲應笑人。"]'),
('aca57851-8cb4-4319-8670-2e4d3407aeb3','又七言','司馬光','宋','宋诗','song-poetry','','[]','聞道山家門鎮開，獨驅瘦馬出塵埃。',32,'全唐诗/poet.song.29000.json','["聞道山家門鎮開，獨驅瘦馬出塵埃。", "白雲明月先無約，何事今宵亦此来。"]'),
('d24c3399-d865-47e8-942d-e8491239bcff','留别逢吉','司馬光','宋','宋诗','song-poetry','','[]','君念承明臭味稀，相逢惜别重依依。',64,'全唐诗/poet.song.29000.json','["君念承明臭味稀，相逢惜别重依依。", "會稽太守方坐嘯，東郭先生還步歸。", "樂飲林塘留節物，餞行里舍動光輝。", "雙旌迴去行人發，一带長臯煙雨微。"]'),
('b41028b5-d186-413d-a6b9-10fe0233426c','陜城桃李零落已盡硤石山中今方盛開馬上口占','司馬光','宋','宋诗','song-poetry','','[]','西望飛花千樹暗，東来芳蘂一番新。',32,'全唐诗/poet.song.29000.json','["西望飛花千樹暗，東来芳蘂一番新。", "行人不惜泥塗倦，喜見年光兩處春。"]'),
('fc818443-4cd1-4b15-8399-3bce6923c3b2','自澠至洛循糓水行百餘里','司馬光','宋','宋诗','song-poetry','','[]','已煩糓水遠相送，更得嵩峰遙見迎。',32,'全唐诗/poet.song.29000.json','["已煩糓水遠相送，更得嵩峰遙見迎。", "水碧峰青看未足，却愁前到洛陽城。"]'),
('5d2b9031-7c85-4611-b1a1-b9c0bfc95e00','送邵不疑知常州','司馬光','宋','宋诗','song-poetry','','[]','宦學不營身，京華費十春。',72,'全唐诗/poet.song.29000.json','["宦學不營身，京華費十春。", "非貪爲郡樂，意欲與民親。", "祖帳青門道，歸帆揚子津。", "江山舊遊在，煙火故鄉鄰。", "敢惜離群闊，欣聞得吏循。", "嗟余一囊米，溟負鬢絲新。"]'),
('0f0c0462-7214-437e-ae90-a32b1edcc979','送聶之美任雞澤令','司馬光','宋','宋诗','song-poetry','','[]','趙魏高氣俠，到今風俗然。',48,'全唐诗/poet.song.29000.json','["趙魏高氣俠，到今風俗然。", "椎埋吏難禁，擊斷世稱賢。", "明府宜更瑟，罷民庶息肩。", "無如繭絲者，急斂縱敲鞭。"]'),
('bd08e903-4f0a-40f8-a053-dadf89cf9568','送張秘校知分寧','司馬光','宋','宋诗','song-poetry','','[]','百里大夫官不輕，莫嗟領上髪垂星。',64,'全唐诗/poet.song.29000.json','["百里大夫官不輕，莫嗟領上髪垂星。", "人生糓祿偏宜晚，世路艱難不厭經。", "數曲秋江縈縣白，幾峰霽色入簾青。", "于公嚮日多陰德，已有鵷鶵在帝庭。"]'),
('b2ef5f8f-b4a8-431c-a45d-938b33b4fd24','館宿遇雨懷諸同舍','司馬光','宋','宋诗','song-poetry','','[]','佳雨濯煩暑，翛然生曉涼。',48,'全唐诗/poet.song.29000.json','["佳雨濯煩暑，翛然生曉涼。", "森沈殿瓦碧，羃歷井苔蒼。", "院静杉篁秀，人閑鐘鼓長。", "憑誰同把酒，清興窅相望。"]'),
('0453db37-dd72-4a37-863c-ace04200e106','送韓直講鄆州寧親','司馬光','宋','宋诗','song-poetry','','[]','車馬儼何之，東岡舊有陂。',72,'全唐诗/poet.song.29000.json','["車馬儼何之，東岡舊有陂。", "三年别親意，千里達家時。", "去仕元戎幕，來爲太學師。", "寧須負斗米，不復斷機絲。", "物色迎歸鞚，光輝入壽卮。", "人生無此樂，此樂獨君知。"]'),
('7ed6a944-b74b-426c-a53b-58f75b1401db','宣徽使河東經略使鄭文肅公挽歌  其一','司馬光','宋','宋诗','song-poetry','','[]','璿璣敷帝命，金節護邊兵。',48,'全唐诗/poet.song.29000.json','["璿璣敷帝命，金節護邊兵。", "盡付將軍制，真爲儒者榮。", "扶搖方上擊，濛汜忽西傾。", "罷市人相吊，紛紛滿百城。"]'),
('b15dfdab-2742-4f4f-8246-eea72d61f2ab','宣徽使河東經略使鄭文肅公挽歌  其二','司馬光','宋','宋诗','song-poetry','','[]','柳翣喪容盛，江山故國遙。',48,'全唐诗/poet.song.29000.json','["柳翣喪容盛，江山故國遙。", "清時獨長往，何日重来朝。", "事與秋雲斷，榮如曉夢消。", "西風虎丘路，馬鬛又嶕嶢。"]'),
('c0c141e3-124d-4f33-8282-41d195127a1d','又代孫檢討作二首  其一','司馬光','宋','宋诗','song-poetry','','[]','湖澄翠岫孤，勝地古東吳。',48,'全唐诗/poet.song.29000.json','["湖澄翠岫孤，勝地古東吳。", "氣象常時秀，英靈何世無。", "金閨演王綍，玉帳綰兵符。", "煒燁照鄉曲，從兹益重儒。"]'),
('a1e88175-d80c-4d82-9d67-dd6982f8c376','又代孫檢討作二首  其二','司馬光','宋','宋诗','song-poetry','','[]','人爲天地客，處世若浮休。',48,'全唐诗/poet.song.29000.json','["人爲天地客，處世若浮休。", "豈有生長在，祗知名可留。", "露沾寒草晚，風嘯白楊秋。", "地下求文友，應從顧陸遊。"]'),
('9ea51c25-38b4-4b20-a681-5fe1a5f2e6b4','送丁秘丞知雍丘','司馬光','宋','宋诗','song-poetry','','[]','古縣跨河流，人繁軍市稠。',72,'全唐诗/poet.song.29000.json','["古縣跨河流，人繁軍市稠。", "羽飛朝暮驛，鱗疊往來舟。", "兄擅才華久，時推政治尤。", "足猶妨老驥，目不礙全牛。", "從道西来近，能無東望愁。", "時因趨上府，窮巷一相求。"]'),
('16dea759-8ca2-46c0-94c0-02131d65de6a','苦雨','司馬光','宋','宋诗','song-poetry','','[]','積雨欲侵旬，朝晡漫不分。',48,'全唐诗/poet.song.29000.json','["積雨欲侵旬，朝晡漫不分。", "蒼涼微露日，慘澹已生雲。", "地半成泥滓，天應厭垢氛。", "時聞度鶬鴰，空外自爲羣。"]'),
('a790f8ec-99b3-46c3-8bdf-0cf37f46f522','酬師道雪夜見寄','司馬光','宋','宋诗','song-poetry','','[]','玉樹交横雪後天，銀河沉着斗欄干。',64,'全唐诗/poet.song.29000.json','["玉樹交横雪後天，銀河沉着斗欄干。", "筆峰微結冰絲澀，燈暈初成花燼殘。", "太學先生氈苦薄，公車倦客履仍單。", "欲吟佳句到清曉，夜寂愁聞金石寒。"]'),
('dc7f2c1d-d047-4750-907a-18fc20073d65','代叔禮作使北詩','司馬光','宋','宋诗','song-poetry','','[]','人主愛民物，心無彼此情。',48,'全唐诗/poet.song.29000.json','["人主愛民物，心無彼此情。", "約歡同一國，蒙福遍羣生。", "玉帛遙相望，風波寂不驚。", "熙熙南北海，所至盡升平。"]'),
('9ca04deb-536a-4707-a98c-e58ce9dac270','又擊毬','司馬光','宋','宋诗','song-poetry','','[]','肅奉乘軺命，仍陪戲馬遊。',48,'全唐诗/poet.song.29000.json','["肅奉乘軺命，仍陪戲馬遊。", "朋分初迥出，勢合復相收。", "顧盼華星激，縈迴紫電流。", "良因重嘉好，禮接使臣優。"]'),
('6fb31139-75e0-4e52-9346-8a5961a3c16b','送計先輩尉宗城','司馬光','宋','宋诗','song-poetry','','[]','紅塵久帝城，高價動公卿。',48,'全唐诗/poet.song.29000.json','["紅塵久帝城，高價動公卿。", "竹栢寒方茂，驊騮老更成。", "冰霜驅馬瘦，書劍束裝輕。", "丞相虚東閣，遙知倒屣迎。"]'),
('05d9d53d-c31e-4a87-bec1-c3f29995bbb2','送趙殿丞歸成都','司馬光','宋','宋诗','song-poetry','','[]','蜀棧錦衣来，高堂綬笥開。',48,'全唐诗/poet.song.29000.json','["蜀棧錦衣来，高堂綬笥開。", "恩輝同日至，喜色共春回。", "駟馬過鄰社，朝裾捧壽杯。", "吾生無此樂，空使寸心摧。"]'),
('0b114216-fd0f-488b-942d-4e4680e22855','送張都官江南東路提刑','司馬光','宋','宋诗','song-poetry','','[]','楚俗號難治，司刑尤擇賢。',48,'全唐诗/poet.song.29000.json','["楚俗號難治，司刑尤擇賢。", "危疑片言决，舒慘一方專。", "松不彫寒色，絲曾斷直絃。", "清風過江外，應在下車前。"]'),
('a9792c24-c5c8-4b51-a651-f2a5c0a7e8ca','送楊秘丞通判揚州','司馬光','宋','宋诗','song-poetry','','[]','苦聞小杜說揚都，當昔豪華今在無。',64,'全唐诗/poet.song.29000.json','["苦聞小杜說揚都，當昔豪華今在無。", "江勢横来控南楚，地形前不瞰東吳。", "萬商落日船交尾，一市春風酒並壚。", "得意莫忘京國友，踏塵衝雪奉朝趨。"]'),
('8d79999d-6561-4519-a758-08612b7f3dce','送光祿王卿致仕歸荆南','司馬光','宋','宋诗','song-poetry','','[]','九列誰云非顯塗，人生已不負爲儒。',64,'全唐诗/poet.song.29000.json','["九列誰云非顯塗，人生已不負爲儒。", "拂衣長揖夔龍貴，散髪還爲黄綺徒。", "白鶴歸飛心自遠，青霞高舉勢何孤。", "千金盡與鄉人費，不向江頭買木奴。"]'),
('1cff43ce-abb5-49b8-b32f-5030092d35ec','贈清衍','司馬光','宋','宋诗','song-poetry','','[]','我厭俗緣苦，空爲薄宦牽。',48,'全唐诗/poet.song.29000.json','["我厭俗緣苦，空爲薄宦牽。", "如師真達者，於世亦超然。", "敝笠衝塵陌，寒雲擁雪天。", "崎嶇遠相顧，深愧此心專。"]'),
('0a4f73e1-fa87-4ad0-a1df-9f603829fcf5','和道粹春寒趨館馬上口占','司馬光','宋','宋诗','song-poetry','','[]','殘臘尚要春，清寒更著人。',48,'全唐诗/poet.song.29000.json','["殘臘尚要春，清寒更著人。", "雪華猶惜别，物意倍添新。", "雲壓宮城重，風調玉漏勻。", "行遊宜結轡，九陌未多塵。"]'),
('5d85e757-420d-4db7-99ae-59427c0aa9e1','同次道元日宿尚書省聽戒誓寄常州卲不疑','司馬光','宋','宋诗','song-poetry','','[]','椒花獻歳新，瑄玉侍祠頻。',48,'全唐诗/poet.song.29000.json','["椒花獻歳新，瑄玉侍祠頻。", "此夕同華省，非才愧後塵。", "江風迎茜斾，沙雨待朱輪。", "不比齋宮冷，端居棄擲春。"]'),
('147cbe5e-0f4b-4844-a657-4f63865960f2','和子淵除夜','司馬光','宋','宋诗','song-poetry','','[]','緹室重飛玉琯灰，物華全與斗杓回。',64,'全唐诗/poet.song.29000.json','["緹室重飛玉琯灰，物華全與斗杓回。", "依依殘臘無情别，歷歷新春滿眼來。", "強取酒卮浮翠柏，懶開粽葉覓楊梅。", "男兒努力平生志，肯使功名落草萊。"]'),
('7b715de2-1f27-438e-9a3b-5287ebe073dd','春祠致齋寄呈景仁次道','司馬光','宋','宋诗','song-poetry','','[]','比日聚官舍，笑言曾未厭。',48,'全唐诗/poet.song.29000.json','["比日聚官舍，笑言曾未厭。", "暫成揮手别，各有侍祠嚴。", "晴景朝朝麗，春容物物添。", "解齋當共醉，莫遣此期淹。"]'),
('5f9c93ac-e913-48cb-ae0d-4c45ae134a0a','雙井茶寄贈范景仁','司馬光','宋','宋诗','song-poetry','','[]','春睡無端巧逐人，驅訶不去苦相親。',32,'全唐诗/poet.song.29000.json','["春睡無端巧逐人，驅訶不去苦相親。", "欲憑洪井真茶力，試遣刀圭報谷神。"]'),
('4ed7e81a-3db6-48ab-b83b-accf5814f5a6','送王殿丞西京簽判','司馬光','宋','宋诗','song-poetry','','[]','清白世風存，王公復有孫。',48,'全唐诗/poet.song.29000.json','["清白世風存，王公復有孫。", "挺生如玉樹，不竭似淮源。", "日背嵩峰紫，春添洛水喧。", "幕中多勝友，肯使負芳樽。"]'),
('dfede13e-cd78-415c-8e8c-fe3f20a23fa4','和子淵元夕','司馬光','宋','宋诗','song-poetry','','[]','神嶽嶕嶢闕角齊，銀蟾無影玉繩低。',64,'全唐诗/poet.song.29000.json','["神嶽嶕嶢闕角齊，銀蟾無影玉繩低。", "風傳絲管交加發，燈滉星河上下迷。", "清醴横飛金鑿落，香塵不染錦障泥。", "誰知此夕齋祠客，近在宮城槐柳西。"]'),
('70f528b7-0e39-463a-bba4-76aa76effa8d','送謝都官知光化軍','司馬光','宋','宋诗','song-poetry','','[]','廐吏整車馬，匆匆辦曉裝。',48,'全唐诗/poet.song.29000.json','["廐吏整車馬，匆匆辦曉裝。", "青緺出閶闔，朱斾指滄浪。", "野店杏初發，津亭柳已黄。", "行行不可駐，猶及勸耕桑。"]'),
('4953fbef-4f53-426c-a4da-b120842f11f9','送仲更歸澤州','司馬光','宋','宋诗','song-poetry','','[]','太行横擁巨川回，三晉由来産異才。',64,'全唐诗/poet.song.29000.json','["太行横擁巨川回，三晉由来産異才。", "展墓乘春走鄉陌，負書拂曉下蘭臺。", "河陽路側花應合，天井關頭雪未開。", "會使鄉人驚六印，莫羞今日弊裘来。"]'),
('0c0efd81-28ad-47af-b457-b02f0e33d491','二月二日太常致齋晨起呈景仁次道二同舍','司馬光','宋','宋诗','song-poetry','','[]','官舍春蕭瑟，朝來尚薄寒。',48,'全唐诗/poet.song.29000.json','["官舍春蕭瑟，朝來尚薄寒。", "人雖繁陌上，塵不近門端。", "已負踏青約，仍無舉白歡。", "憑君御溝上，試折柳條看。"]'),
('5d40eaf9-cd59-4538-af9c-334ea7a6e3f8','送劉觀察知洺州','司馬光','宋','宋诗','song-poetry','','[]','漢家英俊士，衮衮出金閶。',48,'全唐诗/poet.song.29000.json','["漢家英俊士，衮衮出金閶。", "久襲通侯籍，新腰太守章。", "畛封連故趙，廬井带清漳。", "春色迎鐃吹，應忘道路長。"]'),
('607f4241-3d91-4fcb-aefe-eabdad6dd7c9','寒食御筵口號二首  其一','司馬光','宋','宋诗','song-poetry','','[]','雨意沉沉潑火餘，夔龍盛集退朝初。',64,'全唐诗/poet.song.29000.json','["雨意沉沉潑火餘，夔龍盛集退朝初。", "酒殽絡繹來丹禁，冠劍参差下玉除。", "紫鳳歸飛雲爛漫，黄鸝新囀柳扶疏。", "麥禾滿野邊烽息，佳節何妨賦樂胥。"]'),
('398ce783-6da1-4d84-8689-1accbb082869','寒食御筵口號二首  其二','司馬光','宋','宋诗','song-poetry','','[]','聖主褒優鼎軸臣，金觴玉醴照青春。',64,'全唐诗/poet.song.29000.json','["聖主褒優鼎軸臣，金觴玉醴照青春。", "萬家煙火朝來静，九陌風光雨後新。", "高燕翔飛驚紫綬，餘光點綴託朱輪。", "問牛因得觀民俗，不獨嬉遊惜令辰。"]'),
('d8a78f16-3f3f-474b-8290-cf366d1d76f1','致政楊侍郎挽歌  其一','司馬光','宋','宋诗','song-poetry','','[]','時論歸清德，皇心重老臣。',48,'全唐诗/poet.song.29000.json','["時論歸清德，皇心重老臣。", "祖風終鯁直，家學本深淳。", "便殿談經久，安車就第新。", "如何金未盡，奄忽棄鄉人。"]'),
('ebf656c1-f4d1-4025-86db-8cd41cbdedba','致政楊侍郎挽歌  其二','司馬光','宋','宋诗','song-poetry','','[]','憂國心如石，當朝有古風。',48,'全唐诗/poet.song.29000.json','["憂國心如石，當朝有古風。", "掛冠雖在遠，遺札不忘忠。", "飛旐西歸洛，新阡背倚嵩。", "還令往來客，下馬白楊中。"]'),
('c2b645e8-4c49-4a42-9de2-436bb7b9825f','送晁校理知懷州','司馬光','宋','宋诗','song-poetry','','[]','雞犬相聞桑柘春，風光明潤帝鄉鄰。',64,'全唐诗/poet.song.29000.json','["雞犬相聞桑柘春，風光明潤帝鄉鄰。", "群峰斜轉太行角，萬谷同趨馬頰津。", "簪組傾都邀别袂，壺漿滿路候行塵。", "非君厭薄承明直，天子方今重治人。"]'),
('be119017-82db-4d80-a61e-3e585175cc79','席上賦得榛','司馬光','宋','宋诗','song-poetry','','[]','微物生山澤，蕭條荆棘鄰。',36,'全唐诗/poet.song.29000.json','["微物生山澤，蕭條荆棘鄰。", "何人掇秋實，此日待嘉賓。", "雖無木桃贈，投此寄情親。"]'),
('d57f3033-0bf4-48b3-b2c1-61d30ce6aef1','二月三十日與同舍宴李氏園晚歸馬上賦詩','司馬光','宋','宋诗','song-poetry','','[]','門前蹀躞金羈滿，坐上連翩玉斚飛。',64,'全唐诗/poet.song.29000.json','["門前蹀躞金羈滿，坐上連翩玉斚飛。", "數尺遊絲留客醉，一行垂柳送人歸。", "同邀勝友時難得，重到名園花已稀。", "莫惜芳辰剩行樂，無端風雨横相違。"]'),
('4a3969af-f7a6-441f-be1f-65b535002d34','送師道知長溪因歸覲省','司馬光','宋','宋诗','song-poetry','','[]','羈旅帝城久，逢人青眼稀。',48,'全唐诗/poet.song.29000.json','["羈旅帝城久，逢人青眼稀。", "聞君又當去，使我益思歸。", "佳色鄰鄉樹，高堂望綵衣。", "春流先自疾，心出片帆飛。"]'),
('b920da41-03ac-4469-a428-c77ab54c68df','雙竹詩','司馬光','宋','宋诗','song-poetry','','[]','上苑通丹禁，脩林繞玉堂。',120,'全唐诗/poet.song.29000.json','["上苑通丹禁，脩林繞玉堂。", "周阿紆鏤檻，並榦擢新篁。", "蕭灑駢瑤甃，連翩拂璧璫。", "虯騰雙角直，鯨噴兩鬚長。", "曉泊煙華重，晴留雨氣涼。", "分音成律呂，齊秀待鸞凰。", "碧借雲霞潤，清依日月光。", "物情知有謂，天造固無方。", "比節羣誠合，虚心至道彰。", "吾君愈勤德，不敢有嘉祥。"]'),
('96f528ce-99dc-4a70-90b6-ce98d0766588','和次道奉慈齋宮見寄','司馬光','宋','宋诗','song-poetry','','[]','去住邈如霄與塵，依依欲别更相親。',32,'全唐诗/poet.song.29000.json','["去住邈如霄與塵，依依欲别更相親。", "雖知洛邑饒英俊，莫忘齋廬並直人。"]'),
('73383159-ddac-43e1-98b8-175434462194','送次道通判西京','司馬光','宋','宋诗','song-poetry','','[]','相府新承檄，蘭臺舊校文。',96,'全唐诗/poet.song.29000.json','["相府新承檄，蘭臺舊校文。", "題輿榮得士，把袂惜離羣。", "首夏郊原秀，晴陽草樹曛。", "觚稜日邊遠，關塞霧中分。", "翠嶺林端出，飛泉竹外聞。", "金羈遊爛熳，珠履醉繽紛。", "人服聲光重，官無薄領勤。", "歸期肯留滯，漢主待淵雲。"]'),
('95e34a5a-d7c0-4e7d-9e57-b6fa7a7c629a','送劉儀先輩大名尉','司馬光','宋','宋诗','song-poetry','','[]','潭潭相府開，旌騎擁三臺。',48,'全唐诗/poet.song.29000.json','["潭潭相府開，旌騎擁三臺。", "聞道廷中吏，無非天下才。", "策名新振拔，把板尚低回。", "勿爲卑飛困，青冥盡此來。"]'),
('306d3034-e777-4627-959b-76cc0ff1b5e7','送皇甫寺丞知藍田縣','司馬光','宋','宋诗','song-poetry','','[]','南山三輔劇，百里古諸侯。',48,'全唐诗/poet.song.29000.json','["南山三輔劇，百里古諸侯。", "誰爲絃歌小，不分宵旰憂。", "煙横輞川暝，雲照武關秋。", "安得無羈束，從君一縱遊。"]'),
('3d1c0b69-4d95-45db-af6d-844d56432113','酬次道板橋晚望見寄','司馬光','宋','宋诗','song-poetry','','[]','春來曾約醉河橋，深負垂楊千萬條。',32,'全唐诗/poet.song.29000.json','["春來曾約醉河橋，深負垂楊千萬條。", "今日都門相望處，西風亂葉正蕭蕭。"]'),
('dc30ce92-2a53-4540-8f61-57e6281fcf81','送祁嶠潁陽主簿','司馬光','宋','宋诗','song-poetry','','[]','蒼山臨縣郭，雲木冷蕭騷。',48,'全唐诗/poet.song.29000.json','["蒼山臨縣郭，雲木冷蕭騷。", "人有漁樵樂，官無簿領勞。", "垂天起膚寸，合抱本纖毫。", "志意誠脩立，歸飛羽翼高。"]'),
('20c1e444-6676-46fa-ad6a-611d106ff3df','送李尉以監丞致仕歸閩中','司馬光','宋','宋诗','song-poetry','','[]','行行歌式微，浩歎返荆扉。',48,'全唐诗/poet.song.29000.json','["行行歌式微，浩歎返荆扉。", "却著登山屐，盡焚趨府衣。", "溪清魚影亂，竹闇筍牙肥。", "應悔浮名誤，空將白髪歸。"]'),
('d3301553-620a-4b82-aa6e-832494b1ae3b','和伯鎮再入館','司馬光','宋','宋诗','song-poetry','','[]','甘泉獻賦人，流落浙江濱。',48,'全唐诗/poet.song.29000.json','["甘泉獻賦人，流落浙江濱。", "自嘆三年謫，歸來萬事新。", "銓衡時進對，戶牖日相親。", "明主方思賈，非徒問鬼神。"]'),
('aa5cec79-adba-4402-9bc2-604e35433965','和同舍對菊無酒','司馬光','宋','宋诗','song-poetry','','[]','黄花倚秋色，曄曄爲誰開。',48,'全唐诗/poet.song.29000.json','["黄花倚秋色，曄曄爲誰開。", "更使窺殘榼，空令洗舊杯。", "嗅香行繚繞，撚蘂立徘徊。", "盡日柴門外，白衣來不來。"]'),
('2b43a26a-1aff-4c62-b3e2-37abe42ddde2','文太師挽歌三首  其一','司馬光','宋','宋诗','song-poetry','','[]','汾晉地形美，古今多鉅賢。',48,'全唐诗/poet.song.29000.json','["汾晉地形美，古今多鉅賢。", "况承勛烈後，宜有慶靈傳。", "著位登朝古，聲華出衆先。", "起家從此始，圭組遂蟬聯。"]'),
('bdcf3ff0-5bf5-4a64-aa9f-e04bcf2765b1','文太師挽歌三首  其二','司馬光','宋','宋诗','song-poetry','','[]','美化流民物，薰然遺愛多。',48,'全唐诗/poet.song.29000.json','["美化流民物，薰然遺愛多。", "欒公當日社，邵父至今歌。", "庭有三鱣集，門容駟馬過。", "欲知餘慶在，公鼎格平和。"]'),
('a6cb58a4-00c1-45e7-a1eb-a912242468ba','文太師挽歌三首  其三','司馬光','宋','宋诗','song-poetry','','[]','夏屋封何處，山田有卧牛。',48,'全唐诗/poet.song.29000.json','["夏屋封何處，山田有卧牛。", "蟠根走伊水，回首負嵩丘。", "忠孝家風備，哀榮禮秩優。", "龍鸞舞宸翰，萬古照松楸。"]'),
('c92cc355-ef31-46fe-a7dd-89c908caebf8','送李祠部知滑州','司馬光','宋','宋诗','song-poetry','','[]','東郡堤繇苦，曏来煙火疏。',48,'全唐诗/poet.song.29000.json','["東郡堤繇苦，曏来煙火疏。", "提封百里遠，生齒萬家餘。", "賢守車纔下，疲人意已紓。", "行聞謠五袴，京廪滿郊墟。"]'),
('62d432d2-a6df-41fb-b7f0-b12954b019f4','和王道粹垂拱早朝王范二直閣班列在前戲成小詩','司馬光','宋','宋诗','song-poetry','','[]','霽日扶霜仗，祥煙覆曉班。',48,'全唐诗/poet.song.29000.json','["霽日扶霜仗，祥煙覆曉班。", "帝居回北斗，天闕竦南山。", "紫殿鴻鸞肅，金門虎豹環。", "蓬萊兩仙伯，迥立白雲間。"]'),
('ce8e19a2-0e70-457f-a9bb-f59effe1556c','答劉邍父賀龐公惠炭','司馬光','宋','宋诗','song-poetry','','[]','東郭先生履半穿，禦冬深愧主人賢。',64,'全唐诗/poet.song.29000.json','["東郭先生履半穿，禦冬深愧主人賢。", "應憐道上雪欲積，意使爐中灰復然。", "麴糵暗添寒酒力，圖書共免濕薪煙。", "茅齋斗似饒光彩，客至何憂臘後天。"]'),
('160931c3-b87a-40cc-bc39-7c68bad39cea','送田校理知晉州','司馬光','宋','宋诗','song-poetry','','[]','銓筦萃賢豪，夫君主劇曹。',48,'全唐诗/poet.song.29000.json','["銓筦萃賢豪，夫君主劇曹。", "長才沛餘裕，衆論蔚推高。", "逮此分符貴，知無頓刃勞。", "公卿如有缺，不獨賜金褒。"]'),
('0950a7fe-9f39-4db0-abd8-f8975d0b371b','正月三日與廣淵同出南薫門分趨齋宮塗中有作','司馬光','宋','宋诗','song-poetry','','[]','並轡出都門，蔥蘢日欲昕。',48,'全唐诗/poet.song.29000.json','["並轡出都門，蔥蘢日欲昕。", "野寒餘宿雪，樹闇濕春雲。", "未望郊宮近，先愁馬首分。", "一朝猶戀戀，可復久離羣。"]'),
('efe69e4e-7b76-40bc-9ef0-eeb306245581','寄題常州東山亭二首  其一','司馬光','宋','宋诗','song-poetry','','[]','謝傅英聲高可攀，結茅積土想東山。',64,'全唐诗/poet.song.29000.json','["謝傅英聲高可攀，結茅積土想東山。", "常憂勝概一朝盡，豈信風流千古還。", "麈尾蒲葵供永日，酒樽棋局奉歡顔。", "賢侯心迹遙相望，不使蘭陵風月閑。"]'),
('d5bfee94-aac0-45cd-a7b3-d4c65aa54e97','寄題常州東山亭二首  其二','司馬光','宋','宋诗','song-poetry','','[]','閥閱崔嵬動四方，入門鸞鶴自成行。',64,'全唐诗/poet.song.29000.json','["閥閱崔嵬動四方，入門鸞鶴自成行。", "青緺舊已臨佳郡，墨客新歸耀故鄉。", "醉舞幾應摧屐齒，對棋正欲賭香囊。", "階庭玉樹寒相照，更使東山逸氣長。"]'),
('8aa40ae5-6b84-4867-a611-def1075616dc','送人爲閩宰','司馬光','宋','宋诗','song-poetry','','[]','萬里東甌外，溪山秀出羣。',48,'全唐诗/poet.song.29000.json','["萬里東甌外，溪山秀出羣。", "鄉人皆嗜學，太守復工文。", "正用慈良化，居無牒訴紛。", "誰云遠京國，佳政日相聞。"]'),
('41071e99-4f96-4060-8b7d-b1596cf7b257','送才元守廣安軍歸成都覲省','司馬光','宋','宋诗','song-poetry','','[]','皂蓋五驊騮，今來異昔遊。',48,'全唐诗/poet.song.29000.json','["皂蓋五驊騮，今來異昔遊。", "簞壺交里舍，鐃吹下瀛州。", "壽酒行當舉，歸鞭不可留。", "春光久相待，先在錦江頭。"]'),
('97e2fef7-df9e-4d3c-8c7e-5b16a2b4ce60','送上雒王推官','司馬光','宋','宋诗','song-poetry','','[]','墨綬百里宰，紅蕖幕府僚。',48,'全唐诗/poet.song.29000.json','["墨綬百里宰，紅蕖幕府僚。", "民淳無鬬辯，地勝得逍遙。", "日上雲未散，春深雪不消。", "知音已交薦，勿茹紫芝苗。"]'),
('43f7f016-10e6-4b22-903f-df5cb121f3ef','送瀛州簽判蘇秘丞','司馬光','宋','宋诗','song-poetry','','[]','高陽十萬兵，幕府藉時英。',48,'全唐诗/poet.song.29000.json','["高陽十萬兵，幕府藉時英。", "塞上風猶勁，關南春未生。", "投壺邊柝静，倚馬檄書成。", "不忘塵中客，征鴻可寄聲。"]'),
('a4ccefc0-b8fc-407c-af21-e204b8dd6fba','和宋次道西都元日懷不疑并見寄','司馬光','宋','宋诗','song-poetry','','[]','露冕優分竹，題輿佐畫圻。',48,'全唐诗/poet.song.29000.json','["露冕優分竹，題輿佐畫圻。", "比年攜手樂，兹日賞心違。", "齋祀春來併，娛遊别後稀。", "誰憐從窶卒，草際犯寒歸。"]'),
('63808302-c9da-4981-bd7e-9ff790100088','王金吾北園','司馬光','宋','宋诗','song-poetry','','[]','丞相後園天籞鄰，年年分借上林春。',64,'全唐诗/poet.song.29000.json','["丞相後園天籞鄰，年年分借上林春。", "目前但識禽魚樂，門外何妨車馬塵。", "花蘤祗疑名品盡，圖書方驗古今貧。", "將軍朝下無餘事，端爲風煙作主人。"]'),
('c7f71af8-82ee-49fc-9b49-21753bd7d9f5','二月二十四日館宿興宗舍後桃花盛開偶書牖上','司馬光','宋','宋诗','song-poetry','','[]','金馬春寂寂，穠桃隨意開。',24,'全唐诗/poet.song.29000.json','["金馬春寂寂，穠桃隨意開。", "夕風零落盡，不待主人來。"]'),
('acf09d42-f45b-46c4-b880-6a6a2a801a84','送周寺丞畋知洛南','司馬光','宋','宋诗','song-poetry','','[]','太華指商於，中間百里餘。',48,'全唐诗/poet.song.29000.json','["太華指商於，中間百里餘。", "稍行山驛遠，漸與世塵疏。", "楚塞參差接，秦民錯雜居。", "惜哉非綮肯，不足試投虚。"]'),
('8abe4fa6-8fc6-4600-bb53-f71dbe57a8cd','送齊學士知荆南','司馬光','宋','宋诗','song-poetry','','[]','漢家太守治才高，楚國山川氣象豪。',64,'全唐诗/poet.song.29000.json','["漢家太守治才高，楚國山川氣象豪。", "旗斾逶迤蟠夢澤，樓船贔屭壓江濤。", "雄名誰復知宣武，遺愛猶應祀叔敖。", "何必三年求奏計，詔書朝夕賜金褒。"]'),
('e0001bda-294c-4670-bedf-c66c6aa0792c','送王待制知陜府','司馬光','宋','宋诗','song-poetry','','[]','疇昔誠相契，間關分不渝。',96,'全唐诗/poet.song.29000.json','["疇昔誠相契，間關分不渝。", "絕絃悲宿草，撫首念諸孤。", "位略尊榮間，年忘德齒殊。", "清陰容息足，重語辱嘘枯。", "鶠閣騫雲表，虹旌拂海隅。", "明光新出綍，陜陌重分符。", "豐潤還桑梓，讙謳復路衢。", "寧須更條教，耆舊已簞壺。"]'),
('1145e4be-774f-494d-a8bc-6be404271e8d','送張景淳知邵武軍','司馬光','宋','宋诗','song-poetry','','[]','閩嶺窅何在，東南千里遙。',48,'全唐诗/poet.song.29000.json','["閩嶺窅何在，東南千里遙。", "仳離傷草草，會合更迢迢。", "隋岸微吹絮，吳江欲上潮。", "肯無同舍念，回首弭輕橈。"]'),
('e1bcc2d4-957f-4774-91e3-abb60f67fe88','送章伯鎮知湖州','司馬光','宋','宋诗','song-poetry','','[]','江外饒佳郡，吳興天下稀。',48,'全唐诗/poet.song.29000.json','["江外饒佳郡，吳興天下稀。", "蓴羮紫絲滑，鱸膾雪花肥。", "星斗寒相照，煙波碧四圍。", "柳侯還作牧，草樹轉清輝。"]'),
('006de75c-d07f-49ea-8ac1-790c61c4ac8c','送王伯初通判婺州','司馬光','宋','宋诗','song-poetry','','[]','煜爚屏星駕，迢遙婺女區。',48,'全唐诗/poet.song.29000.json','["煜爚屏星駕，迢遙婺女區。", "嵐光晴向背，溪溜暖縈紆。", "萬室鳴機杼，千艘隘舶艫。", "若逢耆舊問，能說隱侯無。"]'),
('4cdcd911-afee-416b-844d-6f7d3d101f3d','送張少卿學士知洪州','司馬光','宋','宋诗','song-poetry','','[]','相府典刑在，朝閨望實高。',96,'全唐诗/poet.song.29000.json','["相府典刑在，朝閨望實高。", "紬書榮史觀，典樂重卿曹。", "夷路迎飛鞚，桑林應奏刀。", "家籝傳舊學，廟鼎刻前勞。", "袨服屯千騎，連檣閲萬艘。", "劍芒衝夜氣，閣影動秋濤。", "風色傳花信，煙光拂酒膏。", "使君專問俗，無意在遊遨。"]'),
('d5e3ceaa-f718-43c9-9a84-a47a63701e4e','送昭遠兄歸陜','司馬光','宋','宋诗','song-poetry','','[]','種種親頭白，帝城難少留。',48,'全唐诗/poet.song.29000.json','["種種親頭白，帝城難少留。", "倚門應有望，列鼎本無求。", "清夜多歸夢，紅塵厭久遊。", "此行殊捧檄，轅下五驊騮。"]'),
('2f95f39a-9dd6-4d16-b54c-c62ed3f96fe9','寄清逸魏處士','司馬光','宋','宋诗','song-poetry','','[]','鄉樹三搖落，臨風歌式微。',48,'全唐诗/poet.song.29000.json','["鄉樹三搖落，臨風歌式微。", "徒嗟俗緣重，端使素心違。", "茅閣松杉冷，山園藥草肥。", "不能如海燕，歲歲一西飛。"]'),
('19d9d004-1937-4420-a9f9-dd837852d149','送雲卿知衞州','司馬光','宋','宋诗','song-poetry','','[]','汗簡成新令，褰帷刺劇州。',48,'全唐诗/poet.song.29000.json','["汗簡成新令，褰帷刺劇州。", "韋平家法在，邵杜治聲優。", "野竹交淇水，秋瓜蔓帝邱。", "三年歸奉計，肯顧石渠遊。"]'),
('5e27c19b-0d28-4ab2-a8d2-2623722c1486','送昌言知宿州','司馬光','宋','宋诗','song-poetry','','[]','煒煒符離守，中流簇鼓旂。',48,'全唐诗/poet.song.29000.json','["煒煒符離守，中流簇鼓旂。", "柳陰濃不斷，舟勢激如飛。", "魏闕行歸奏，承明秪暫違。", "星軺晨夜度，尺素勿令稀。"]'),
('40d1ac3b-66ab-4eb1-a184-b34281b1bd2d','送濟川知漢州二首  其一','司馬光','宋','宋诗','song-poetry','','[]','金馬從容樂，問君何所之。',48,'全唐诗/poet.song.29000.json','["金馬從容樂，問君何所之。", "客心彯若梗，親髪暠如絲。", "舊學已孤陋，素交仍别離。", "執經時有問，使我復從誰。"]'),
('53e4e976-b77e-4684-8bbf-5d3640b61116','送濟川知漢州二首  其二','司馬光','宋','宋诗','song-poetry','','[]','千騎擁朱轓，青霞晝繡還。',48,'全唐诗/poet.song.29000.json','["千騎擁朱轓，青霞晝繡還。", "復尋題柱迹，重過棄繻關。", "曉棧流雲濕，秋湖脫葉殷。", "久遊今得意，真不愧江山。"]'),
('32ecb93b-73ba-47b1-8245-262dfba3daff','哭公素  其一','司馬光','宋','宋诗','song-poetry','','[]','負書遊上國，拾芹取榮名。',48,'全唐诗/poet.song.29000.json','["負書遊上國，拾芹取榮名。", "雅度津涯闊，高文風雨驚。", "忘懷飜得謗，縱酒遂傷生。", "忍使泉臺客，悁悁不自明。"]'),
('60f8d897-a621-4e3c-b71b-4ee67350da5e','哭公素  其二','司馬光','宋','宋诗','song-poetry','','[]','丹旌倚輤車，榮辱盡虚無。',48,'全唐诗/poet.song.29000.json','["丹旌倚輤車，榮辱盡虚無。", "半道驊騮頓，先秋蘭雨枯。", "兒癡纔過齓，親老不勝扶。", "家事今蕭瑟，寧將未第殊。"]'),
('2682d7f8-13c0-4b79-9822-8b030a0ec307','送程端明知成都','司馬光','宋','宋诗','song-poetry','','[]','高陽將幕開，濯錦使旌来。',48,'全唐诗/poet.song.29000.json','["高陽將幕開，濯錦使旌来。", "欲識關頭雪，正如江上梅。", "宵衣矜遠俗，露冕寄良才。", "豈待三年最，脩梧茂帝臺。"]'),
('417bc102-fdff-4ea5-b60e-87483bc66a58','丁尚書挽詞二首  其一','司馬光','宋','宋诗','song-poetry','','[]','鳳蹕遊汾曲，非熊得偉人。',48,'全唐诗/poet.song.29000.json','["鳳蹕遊汾曲，非熊得偉人。", "閨臺尤顯重，訓誥愈深淳。", "論道參黄閣，横經侍紫宸。", "如何天不愸，志業未全伸。"]'),
('1a0dc1f3-39ba-438e-855d-fb3f8002a97c','丁尚書挽詞二首  其二','司馬光','宋','宋诗','song-poetry','','[]','丹闕晨趨退，蕭然忘世榮。',48,'全唐诗/poet.song.29000.json','["丹闕晨趨退，蕭然忘世榮。", "閑齋虚自白，永日澹無營。", "脫落簪纓累，沈冥丘壑情。", "貪夫誠有激，千載素風清。"]'),
('1391ec00-0a7a-4272-9e8b-0c7388b48a8b','奉和濟川代書三十韻寄諸同舍','司馬光','宋','宋诗','song-poetry','','[]','金馬延羣儁，芸香聚衆書。',288,'全唐诗/poet.song.29000.json','["金馬延羣儁，芸香聚衆書。", "杳疑神境絕，深與世塵疏。", "氣逼煙霄爽，光分日月餘。", "不材叨誤選，故友幸聯居。", "雲蓋森胡騎，天閽謹契魚。", "後先陪賈馬，左右揖嚴徐。", "朱閣霜清外，璇題日上初。", "辭林精采擷，藝圃縱遊漁。", "决勝楸枰暝，窮歡綺席舒。", "朝昏升紫闥，咫尺待彫輿。", "玉壘俄鄉思，銅符忽詔除。", "綵衣承几杖，華轂照園廬。", "四郭柑垂蔭，千塍稻散渠。", "壺漿迎露冕，鐃吹擁高旟。", "有德能仁虎，無欺恥怒狙。", "道途繁揖讓，犴獄絕淪胥。", "滯穗棲場圃，鳴桴靜里閭。", "貧寧費官燭，饑不茹家蔬。", "翁子懷青綬，文園駕赤車。", "古今相與校，勝負定何如。", "上正開宣室，人方誦子虚。", "追鋒行入謁，委佩復傳臚。", "撫已聊晞驥，臨民遽起予。", "居然耗廩祿，豈不愧簪裙。"]'),
('432be189-6b39-4fda-8ee8-32e1430d02c2','和始平公貽一二賓僚','司馬光','宋','宋诗','song-poetry','','[]','儒冠藹藹從平津，東閣由來盛衆賓。',64,'全唐诗/poet.song.29000.json','["儒冠藹藹從平津，東閣由來盛衆賓。", "終始何嘗忘教育，高卑曾不間疏親。", "共陪樽俎無虚日，空喜谿山得主人。", "白雪屢歌殊未和，自知羞愧後車塵。"]'),
('bfefa5af-3011-453d-a3cd-0eac628bd3a5','留客','司馬光','宋','宋诗','song-poetry','','[]','酒煙漠漠自生春，舞袖飄颻拍拍新。',32,'全唐诗/poet.song.29000.json','["酒煙漠漠自生春，舞袖飄颻拍拍新。", "須信客歸絲竹散，清風白月解愁人。"]'),
('1ce8280f-53e7-4317-9c14-85b475dbf287','和始平公長句寄漢州何學士','司馬光','宋','宋诗','song-poetry','','[]','勢交倐忽易蕭條，賴有伊人尚建標。',64,'全唐诗/poet.song.29000.json','["勢交倐忽易蕭條，賴有伊人尚建標。", "須信松筠凌雪茂，肯爲蒲柳望秋凋。", "欽賢高館三年別，廣漢專城百舍遙。", "書紙如雲詩叩玉，數憑疾翼度青霄。"]'),
('187935e7-741a-4785-9197-9677054542b6','濟川有書見貽云以親老須守遠郡以便祿養不得如光在主人幕下因以詩答','司馬光','宋','宋诗','song-poetry','','[]','千騎駸駸簇畫輈，高旌大蓋五驊騮。',64,'全唐诗/poet.song.29000.json','["千騎駸駸簇畫輈，高旌大蓋五驊騮。", "齋中酒美連翩醉，湖上花繁爛漫遊。", "雞犬相聞通故里，旨甘不絕奉晨羞。", "只應朝夕平津閣，得向君前立勝籌。"]'),
('3940c095-2959-4758-a1f3-d2da3b5840fe','閼逢敦牂二月十一日與一二僚友遊叔禮園亭以詩戲呈','司馬光','宋','宋诗','song-poetry','','[]','下馬久徘徊，林芳殊未開。',24,'全唐诗/poet.song.29000.json','["下馬久徘徊，林芳殊未開。", "春風真有意，須待主翁來。"]'),
('e5c6243f-f3c1-4b89-bb27-30f2808a4913','十四日小園置茶招宗聖應之皆辭以醉爲詩贈之','司馬光','宋','宋诗','song-poetry','','[]','草樹弄春暉，家家倒載歸。',24,'全唐诗/poet.song.29000.json','["草樹弄春暉，家家倒載歸。", "誰憐獨醒客，日暝掩雙扉。"]'),
('f4072e19-e10a-43dd-a466-db420254f0ce','同僚有獨遊東遊者小詩寄之  其一','司馬光','宋','宋诗','song-poetry','','[]','車馬東城路，芬芳數里塵。',24,'全唐诗/poet.song.29000.json','["車馬東城路，芬芳數里塵。", "風光不相待，愁殺未遊人。"]'),
('0ad03ca7-ab7a-42e9-8bc6-5a3f0e8db875','同僚有獨遊東遊者小詩寄之  其二','司馬光','宋','宋诗','song-poetry','','[]','咫尺東園樂，無如簿領何。',24,'全唐诗/poet.song.29000.json','["咫尺東園樂，無如簿領何。", "春風連夜惡，聞道落花多。"]'),
('f7486ea4-4bfc-4ba3-9f66-bd848a4d1862','同僚有獨遊東遊者小詩寄之  其三','司馬光','宋','宋诗','song-poetry','','[]','城樓傳晚鼓，稍稍訟庭稀。',24,'全唐诗/poet.song.29000.json','["城樓傳晚鼓，稍稍訟庭稀。", "起拂衣中土，還騎款段歸。"]'),
('89b221c8-0160-4d76-93a0-b735bfe4acb2','小詩招僚友晚遊後園二首  其一','司馬光','宋','宋诗','song-poetry','','[]','五陵年少競春暉，肥馬銀鞍白玉羈。',32,'全唐诗/poet.song.29000.json','["五陵年少競春暉，肥馬銀鞍白玉羈。", "何似松間煮新茗，更來花底覆殘棋。"]'),
('93097cc1-65fc-42be-98e7-ebe2d3d6c646','小詩招僚友晚遊後園二首  其二','司馬光','宋','宋诗','song-poetry','','[]','麥田小雨隴微青，草樹欣欣照晚晴。',32,'全唐诗/poet.song.29000.json','["麥田小雨隴微青，草樹欣欣照晚晴。", "花下客來醒亦好，猶勝閉戶過清明。"]'),
('894f12a4-8975-44be-bb8c-09ff7eee756d','小園晚飲','司馬光','宋','宋诗','song-poetry','','[]','公府豐暇豫，真成棄擲春。',48,'全唐诗/poet.song.29000.json','["公府豐暇豫，真成棄擲春。", "招邀俱勝友，爛漫醉芳辰。", "花艶穠無敵，文鋒健有神。", "猶勝擁朱墨，終日坐埃塵。"]'),
('50bc787d-9d04-46d9-9915-03138fa395cf','李花','司馬光','宋','宋诗','song-poetry','','[]','嘉李繁相倚，園林淡泊春。',48,'全唐诗/poet.song.29000.json','["嘉李繁相倚，園林淡泊春。", "齊紈剪衣薄，吳紵下機新。", "色與晴光亂，香和露氣勻。", "望中皆玉樹，環堵不爲貧。"]'),
('69bc24e5-a62e-47b4-8966-79b1e2c4a554','東窗','司馬光','宋','宋诗','song-poetry','','[]','臨風梳短髪，蕭颯晚凉新。',48,'全唐诗/poet.song.29000.json','["臨風梳短髪，蕭颯晚凉新。", "不識市朝客，何如江海人。", "沈吟憑棐几，欹側带紗巾。", "濁世事無盡，東窗聊放神。"]'),
('14602fa5-6afe-4052-a77b-d6718be94d0b','奉和始平公酬大資政吳侍郎  其一','司馬光','宋','宋诗','song-poetry','','[]','道盛經綸業，文高翰墨場。',48,'全唐诗/poet.song.29000.json','["道盛經綸業，文高翰墨場。", "雍容偃藩地，密邇釣璜鄉。", "回首紅塵遠，清心白日長。", "山形抱城堞，谿影照公堂。"]'),
('c46df5b9-ec83-4e1a-889d-ac0591962161','奉和始平公酬大資政吳侍郎  其二','司馬光','宋','宋诗','song-poetry','','[]','䆉稏千塍碧，芙蕖萬頃香。',48,'全唐诗/poet.song.29000.json','["䆉稏千塍碧，芙蕖萬頃香。", "跨波横略彴，逼地亞篔簹。", "大野禾麻溢，高齋几席凉。", "夔龍屢賡唱，東壁正垂光。"]'),
('2def0465-8411-4692-a228-dd056b5bdc12','晚行後園見菊戲宜甫','司馬光','宋','宋诗','song-poetry','','[]','野菊荒無數，班班初見花。',24,'全唐诗/poet.song.29000.json','["野菊荒無數，班班初見花。", "徑須求一醉，試遣問東家。"]'),
('78ca835a-244a-4a39-84ac-3265f72efb9b','野菊','司馬光','宋','宋诗','song-poetry','','[]','野菊未嘗種，秋花何處來。',48,'全唐诗/poet.song.29000.json','["野菊未嘗種，秋花何處來。", "羞隨衆草没，故犯早霜開。", "寒蝶舞不去，夜蛬吟更哀。", "幽人自移席，小摘泛青杯。"]'),
('77f960fc-1ff2-420a-870d-6ac1c1726584','秋夜','司馬光','宋','宋诗','song-poetry','','[]','城上調秋角，煙間發暝鐘。',48,'全唐诗/poet.song.29000.json','["城上調秋角，煙間發暝鐘。", "風枝搖宿鳥，霜草覆寒蛬。", "久負觀書樂，端愁束带恭。", "暫因羣吏散，還得遂幽慵。"]'),
('886179d6-bc42-46f8-9981-79a2cb232ae0','再呈宜甫','司馬光','宋','宋诗','song-poetry','','[]','西家壺已倒，次第向東鄰。',24,'全唐诗/poet.song.29000.json','["西家壺已倒，次第向東鄰。", "朱戶如堅閉，黄花惡笑人。"]'),
('d97b4a40-3306-4da5-ad99-040bb3670749','宜甫家有金鈴菊客未之識因代菊贈宜甫','司馬光','宋','宋诗','song-poetry','','[]','主人倦邀客，寂寞委蒼苔。',24,'全唐诗/poet.song.29000.json','["主人倦邀客，寂寞委蒼苔。", "此日開無益，明年不復開。"]'),
('8bac73aa-7f90-490d-80bb-18d0e3f010dd','深夜','司馬光','宋','宋诗','song-poetry','','[]','疏星映戶月流天，羣動收聲四寂然。',32,'全唐诗/poet.song.29000.json','["疏星映戶月流天，羣動收聲四寂然。", "嗟爾寒蛬怨何事，悲吟徹曙亦無眠。"]'),
('5818fd13-22f5-408c-b056-a0721a7809d8','奉和始平公喜聞昌言修注','司馬光','宋','宋诗','song-poetry','','[]','鳳口除書下九閽，簪紳拭目仰殊恩。',64,'全唐诗/poet.song.29000.json','["鳳口除書下九閽，簪紳拭目仰殊恩。", "曉提麟筆依華蓋，日就螭坳記聖言。", "桃李新陰方藹藹，驊騮老志更軒軒。", "主人喜見相如達，趣召鄒枚洗玉樽。"]'),
('bdffac02-9844-4843-b390-e6e3ff02bdb8','秋雨霽倏聞宗聖案伎應之飲酒詩呈宜甫','司馬光','宋','宋诗','song-poetry','','[]','寒風細雨未晴天，密似輕塵薄似煙。',64,'全唐诗/poet.song.29000.json','["寒風細雨未晴天，密似輕塵薄似煙。", "一室獨吟圖史亂，四鄰高會綺羅鮮。", "鴈飛斜柱絃隨指，蟹薦新螯酒滿船。", "自笑不歌仍不飲，昏昏只解枕牀眠。"]'),
('272e3e78-f27a-4c1b-b84e-1cae642353a1','宜甫東樓晚飲','司馬光','宋','宋诗','song-poetry','','[]','賓主俱歡醉，高樓迥倚空。',48,'全唐诗/poet.song.29000.json','["賓主俱歡醉，高樓迥倚空。", "形忘羈檢外，酒散笑談中。", "晚市煙初白，秋園葉半紅。", "登臨不厭數，朝夕是寒風。"]'),
('ede64321-9254-4754-a742-40c328b4ed7d','送魏寺丞赴辟秦州判官','司馬光','宋','宋诗','song-poetry','','[]','征西大府開，後乘得高才。',48,'全唐诗/poet.song.29000.json','["征西大府開，後乘得高才。", "區脫烽煙静，渠搜職貢來。", "隴雲低玉帳，羌舞奉金罍。", "信美從軍樂，脩梧茂帝臺。"]'),
('ab6d02ff-681c-41dd-a655-a0ac3596f8d8','昌言謫官符離有病鶴折翼舟載以行及還修注始平公以詩問之命光同賦二首  其一','司馬光','宋','宋诗','song-poetry','','[]','曾下青田啄玉苗，泥沙病羽久蕭條。',32,'全唐诗/poet.song.29000.json','["曾下青田啄玉苗，泥沙病羽久蕭條。", "謫仙不欲留塵世，依舊提攜上碧霄。"]'),
('4839695c-1bed-450d-952e-a5726872bb57','昌言謫官符離有病鶴折翼舟載以行及還修注始平公以詩問之命光同賦二首  其二','司馬光','宋','宋诗','song-poetry','','[]','相閣書傳紫闥深，破緘先問九臯禽。',32,'全唐诗/poet.song.29000.json','["相閣書傳紫闥深，破緘先問九臯禽。", "不令一物傷天理，仁愛方知真宰心。"]'),
('65d4aaea-bb6c-4621-bc10-44d364a73f60','和聶之美重遊東郡二首  其一','司馬光','宋','宋诗','song-poetry','','[]','躍馬津亭未幾何，宦遊容易十年過。',64,'全唐诗/poet.song.29000.json','["躍馬津亭未幾何，宦遊容易十年過。", "飄颻空似隨流梗，寂寞猶爲掛壁梭。", "西嶺應餘當日翠，南湖真減幾分波。", "輸君尚得飛征蓋，重向春園聽舊歌。"]'),
('9be92b81-abfd-469b-8205-98bee8887648','和聶之美重遊東郡二首  其二','司馬光','宋','宋诗','song-poetry','','[]','南湖重過又逢春，官柳雖疏亦解新。',32,'全唐诗/poet.song.29000.json','["南湖重過又逢春，官柳雖疏亦解新。", "臺榭傾欹賓友散，臨風愁殺獨遊人。"]'),
('3357f411-aa66-4fbe-8ff8-8352ab249b7d','大熱','司馬光','宋','宋诗','song-poetry','','[]','山澤欲焦枯，炎光滿太虚。',24,'全唐诗/poet.song.29000.json','["山澤欲焦枯，炎光滿太虚。", "不知天地外，暑氣復何如。"]'),
('e6f8ec91-21eb-44b1-b177-92167bf194fb','夷齊','司馬光','宋','宋诗','song-poetry','','[]','夷齊雙骨已成塵，獨有清名日日新。',32,'全唐诗/poet.song.29000.json','["夷齊雙骨已成塵，獨有清名日日新。", "餓死溝中人不識，可憐今古幾何人。"]'),
('8790b54f-56c8-4a21-b96f-23af347fecac','清風臺','司馬光','宋','宋诗','song-poetry','','[]','太守金閨客，天朝應對才。',48,'全唐诗/poet.song.29000.json','["太守金閨客，天朝應對才。", "非因板輿戀，寧駕使車來。", "水鑑秋毫盡，霜鋒錯節開。", "清風偏千里，不獨此高臺。"]'),
('3ba730bd-fdd6-470c-940e-436f63a5244b','佇月亭','司馬光','宋','宋诗','song-poetry','','[]','燈火動魚磯，湖邊過鳥稀。',48,'全唐诗/poet.song.29000.json','["燈火動魚磯，湖邊過鳥稀。", "孤蟾久未上，五馬不成歸。", "長嘯風生座，高吟露滿衣。", "閑情無日厭，岸幘對清暉。"]'),
('60ce51e6-3b64-453b-b827-72235fc1e1aa','藥圃','司馬光','宋','宋诗','song-poetry','','[]','三蜀膏腴地，偏於藥物宜。',48,'全唐诗/poet.song.29000.json','["三蜀膏腴地，偏於藥物宜。", "小畦千種聚，春雨一番滋。", "山相慚多識，桐君未偏知。", "佗年似胡廣，飬壽復扶衰。"]'),
('be591d25-b893-41fb-b84a-902fb384ff87','竹塢','司馬光','宋','宋诗','song-poetry','','[]','二何迹相繼，竹塢日陰森。',48,'全唐诗/poet.song.29000.json','["二何迹相繼，竹塢日陰森。", "欲識飬民意，先觀愛物心。", "低垂樽俎冷，密映管絃深。", "勿怪湖光少，年來碧影侵。"]'),
('c9902f20-a024-4d6f-b88a-e7275af125a8','射堋','司馬光','宋','宋诗','song-poetry','','[]','疊鼓花前急，紅旌竹外高。',48,'全唐诗/poet.song.29000.json','["疊鼓花前急，紅旌竹外高。", "驚飈分白羽，餘響振烏號。", "壯觀傾春陌，讙聲湧夜濤。", "因兹刑禮俗，豈獨事遊遨。"]'),
('bf734439-81da-4ccc-8c0a-2a5e2b05b8ec','玉徽亭','司馬光','宋','宋诗','song-poetry','','[]','房公昔漂泊，置酒此鳴琴。',48,'全唐诗/poet.song.29000.json','["房公昔漂泊，置酒此鳴琴。", "人事有憂樂，山光無古今。", "風流俱寂寞，結構尚蕭森。", "松竹含虚籟，猶疑絃上音。"]'),
('c9690f70-4d73-419c-a4e9-5f907ff32e55','書樓','司馬光','宋','宋诗','song-poetry','','[]','使君有書癖，記覽浩無涯。',48,'全唐诗/poet.song.29000.json','["使君有書癖，記覽浩無涯。", "况此孤楼迥，端無外物譁。", "横肱欹曲几，搔首落烏紗。", "此趣人誰識，長吟窗日斜。"]'),
('c02ba22d-6801-47dd-9e67-595f06d07346','朔會堂','司馬光','宋','宋诗','song-poetry','','[]','朔旦集俺吏，兹堂簪組繁。',48,'全唐诗/poet.song.29000.json','["朔旦集俺吏，兹堂簪組繁。", "舞空孤鶴下，映日兩鳬翻。", "花散東方騎，萍浮北海樽。", "須知太守貴，鐃吹引朱輪。"]'),
('5b18580a-54c4-4864-b557-45c10a52bc3c','浮醳亭','司馬光','宋','宋诗','song-poetry','','[]','曲水華榱下，浮觴去復還。',48,'全唐诗/poet.song.29000.json','["曲水華榱下，浮觴去復還。", "浪搖花影碎，日射酒缸殷。", "滅沒遙尋客，徘徊怯度灣。", "窮歡不知醉，清泚照心顔。"]'),
('a8bc7df3-b31f-4dd9-b5f8-d7c0e99345d4','清燕亭','司馬光','宋','宋诗','song-poetry','','[]','波澄蔭羣木，永日湛清華。',48,'全唐诗/poet.song.29000.json','["波澄蔭羣木，永日湛清華。", "碧篠静秋色，白蘋低晚花。", "松聲工醒酒，泉味最便茶。", "外事付丞掾，無妨風景嘉。"]'),
('93c63a64-eff7-4a8a-9709-950f31bc6d6e','流芳橋','司馬光','宋','宋诗','song-poetry','','[]','橋下流芳度，餘春日夕催。',48,'全唐诗/poet.song.29000.json','["橋下流芳度，餘春日夕催。", "呼人洗樽斚，招客藉莓苔。", "倚柱時流滯，隨波乍往迴。", "仙家如不近，安得此花來。"]'),
('a9d6d81c-2fdb-4832-9c3b-80d5381642cb','曉景亭','司馬光','宋','宋诗','song-poetry','','[]','簾櫳分曉色，遠樹子規啼。',48,'全唐诗/poet.song.29000.json','["簾櫳分曉色，遠樹子規啼。", "濃露侵衣冷，晴煙壓水低。", "神遊靈境徤，身入畫圖迷。", "衙吏無煩報，河洲鷺正棲。"]'),
('99ab3d5e-b459-4e45-a8b3-575d13718181','假山','司馬光','宋','宋诗','song-poetry','','[]','廣漢土平遠，已嫌丘壑疏。',48,'全唐诗/poet.song.29000.json','["廣漢土平遠，已嫌丘壑疏。", "呼工刻巖洞，應手出庭除。", "縹渺神仙宅，嵌空虎豹居。", "人功與天力，秀絕兩何如。"]'),
('e92154ba-449c-47fc-adf4-24ba673f0a39','探花橋','司馬光','宋','宋诗','song-poetry','','[]','橋邊春意近，五馬屢徘徊。',48,'全唐诗/poet.song.29000.json','["橋邊春意近，五馬屢徘徊。", "湖水旦暮淥，林花早晚開。", "適因嘗酒到，又爲賦詩来。", "借問雙華表，經過日幾回。"]'),
('7c55343c-eb59-42aa-8958-8c2aed3c4a74','樂軒','司馬光','宋','宋诗','song-poetry','','[]','繁絃凝綠水，疊鼓摻漁陽。',48,'全唐诗/poet.song.29000.json','["繁絃凝綠水，疊鼓摻漁陽。", "風結舞初急，塵飛歌正長。", "鳬鷖爭上下，棟宇爲低昂。", "太守且安坐，新聲未遽央。"]'),
('a8e32111-9ca2-4c84-b843-2b026577878d','坐船','司馬光','宋','宋诗','song-poetry','','[]','使君張皂蓋，高宴碧湖心。',48,'全唐诗/poet.song.29000.json','["使君張皂蓋，高宴碧湖心。", "苒蒻牽菱蔓，夷猶泊柳陰。", "晚風侵坐冷，春浪沒篙深。", "倒載歸何晚，波間夕照沈。"]'),
('01c82c60-d54e-4685-aea6-99c90eadea92','枇杷洲','司馬光','宋','宋诗','song-poetry','','[]','周官歛珍味，漢苑結芳根。',48,'全唐诗/poet.song.29000.json','["周官歛珍味，漢苑結芳根。", "何意荒洲上，猶餘嘉樹存。", "犯寒花已發，迎暑實尤繁。", "願逐蒲萄使，離宮奉至尊。"]'),
('27165cc8-8124-4849-bac3-0407ef36f47c','寓泊鄭圃寄獻昌言舍人','司馬光','宋','宋诗','song-poetry','','[]','旅食緇衣館，飄蓬怳自迷。',48,'全唐诗/poet.song.29000.json','["旅食緇衣館，飄蓬怳自迷。", "樹横寒霧遠，山隱古原低。", "愁暮空庭雀，驚晨别墅雞。", "故人何處在，依約玉繩西。"]'),
('f2e9f02a-c119-4563-9116-523cc60f76d5','奉和始平公憶東平  其一','司馬光','宋','宋诗','song-poetry','','[]','相印東臨汶水陽，兩看春葉與秋霜。',64,'全唐诗/poet.song.29000.json','["相印東臨汶水陽，兩看春葉與秋霜。", "登山置酒延鄒湛，上馬回鞭問葛強。", "溪竹低垂寒滴翠，露荷相倚凈交香。", "宵衣深念長城固，肯得從容傲醉鄉。"]'),
('02fb33b9-ccfc-4e78-8f20-31558adc684b','奉和始平公憶東平  其二','司馬光','宋','宋诗','song-poetry','','[]','千巖秀色擁晴川，萬頃陂光上下天。',64,'全唐诗/poet.song.29000.json','["千巖秀色擁晴川，萬頃陂光上下天。", "委地魚鹽隨處市，蔽空桑柘不容田。", "訟庭虚静官曹樂，儒服寛長邑里賢。", "不爲從知方負羽，獨乘魚艇老風煙。"]'),
('fd13613c-9d2b-4bb0-8f85-8e5c4a5395da','和運使舍人北園餞别行憩三交僧舍冒雪宿百井關見寄','司馬光','宋','宋诗','song-poetry','','[]','驪駒北上雪孱顔，韊矢前驅度漢關。',64,'全唐诗/poet.song.29000.json','["驪駒北上雪孱顔，韊矢前驅度漢關。", "僧室松杉清照眼，驛亭煙火迥依山。", "馬銜邊草枯猶瘦，鴈怯胡雲冷未還。", "賤子不須回首問，鬢毛蕭颯簿書間。"]'),
('511d6cbb-e8f5-4642-a031-ab7ccd7af421','又和留題定襄驛','司馬光','宋','宋诗','song-poetry','','[]','按節羊腸阪，褰帷並塞州。',48,'全唐诗/poet.song.29000.json','["按節羊腸阪，褰帷並塞州。", "仁風熙愛日，清德凛高秋。", "甘澤隨征蓋，華星近戍楼。", "佗年叱馭事，直筆寄歆彪。"]'),
('5d65cd2f-ca7c-48f0-afa7-0fa8ba848370','又寄獻','司馬光','宋','宋诗','song-poetry','','[]','承明共直廬，瞬息八年餘。',48,'全唐诗/poet.song.29000.json','["承明共直廬，瞬息八年餘。", "幸託屏星駕，前迎使者車。", "跡雖殊貴賤，心不置親疏。", "青眼披情素，猶如相見初。"]'),
('a40a30d1-76cb-47b1-8fae-7b21497dd683','自嘲','司馬光','宋','宋诗','song-poetry','','[]','英名愧終賈，高節謝巢由。',48,'全唐诗/poet.song.29000.json','["英名愧終賈，高節謝巢由。", "直取雲山笑，空爲簪組羞。", "浮沈乖俗好，隱顯拙身謀。", "惆悵臨清鑑，霜毛不待秋。"]'),
('3d701579-7d88-44a3-b192-713afc284a36','晉陽三月未有春色','司馬光','宋','宋诗','song-poetry','','[]','天心均煦嫗，物態異芬芳。',48,'全唐诗/poet.song.29000.json','["天心均煦嫗，物態異芬芳。", "上國花應爛，邊城柳未黄。", "清明空改火，元已漫浮觴。", "仍說秋寒早，年年八月霜。"]'),
('38a32f1e-5334-4eba-b8bc-9135d2f2ac03','柳溪對雪','司馬光','宋','宋诗','song-poetry','','[]','春風不勝雪，散漫度龍沙。',48,'全唐诗/poet.song.29000.json','["春風不勝雪，散漫度龍沙。", "密映緣谿柳，爭飛亂眼花。", "鴟夷賒美酒，油壁繫輕車。", "塞下芳菲晚，聊將當物華。"]'),
('870115d9-bbce-4d35-99f9-d8d468dcc126','酪羮','司馬光','宋','宋诗','song-poetry','','[]','軍廚重羊酪，饗士舊風傳。',48,'全唐诗/poet.song.29000.json','["軍廚重羊酪，饗士舊風傳。", "不數紫蓴滑，徒誇素鮪鮮。", "𤐣蠡煩挏取，勺藥助烹煎。", "莫與吳兒說，還令笑茂先。"]'),
('a7d7e1d8-509f-4273-b30b-52f07709a3fb','奉同道矩謝始平公惠硯','司馬光','宋','宋诗','song-poetry','','[]','爵臺今已傾，飄瓦出蕪城。',48,'全唐诗/poet.song.29000.json','["爵臺今已傾，飄瓦出蕪城。", "還入縑緗用，尤資筆墨精。", "相君憐古物，內史擅書名。", "聊用飛軍檄，何愁楯鼻平。"]'),
('ec2db02a-a887-4d04-8fee-cdbf46729e38','陪始平公燕柳谿','司馬光','宋','宋诗','song-poetry','','[]','谿光不動柳風輕，玉帳森沈擁萬兵。',64,'全唐诗/poet.song.29000.json','["谿光不動柳風輕，玉帳森沈擁萬兵。", "鷗入煙中閑自舞，魚翻波面喜相迎。", "樓船下視晴天碧，鼓吹前驅遠陌清。", "桃李歸時應盛發，薫然和氣滿春城。"]'),
('b463c59c-7e8b-4af0-9bd7-405350b19f88','送王都官官滿還都','司馬光','宋','宋诗','song-poetry','','[]','粹美清廟器，可嗟沉下僚。',48,'全唐诗/poet.song.29000.json','["粹美清廟器，可嗟沉下僚。", "優遊仲舉坐，洋溢海沂謠。", "奏課應居首，知音况滿朝。", "從今黄鵠舉，眼冷看青霄。"]'),
('a72da23b-6e8e-41a6-9997-aedef6a25e3a','到并州已復數月率爾成詩','司馬光','宋','宋诗','song-poetry','','[]','忽忽此何地，經時更自猜。',48,'全唐诗/poet.song.29000.json','["忽忽此何地，經時更自猜。", "深疑醉裏得，復似夢中來。", "薄宦真何益，浮生信可咍。", "鵬蜩定有分，不若寸心灰。"]'),
('d3d02611-a237-4b10-a558-93ff7297c21d','和道矩送客汾西村舍杏花盛開置酒其下','司馬光','宋','宋诗','song-poetry','','[]','田家繁杏壓枝紅，遠勝桃夭與李穠。',64,'全唐诗/poet.song.29000.json','["田家繁杏壓枝紅，遠勝桃夭與李穠。", "何事偏宜閑處植，無端復向别時逢。", "林間暫繫黄金勒，花下聊飛碼碯鍾。", "會待重來醉嘉樹，只愁風雨不相容。"]'),
('fb184a0e-d8a6-4555-b853-017602706109','北軒老杏其大十圍春色向晚止開一花予憫其憔悴作詩嘲之','司馬光','宋','宋诗','song-poetry','','[]','春木爭秀發，嗟君獨不材。',48,'全唐诗/poet.song.29000.json','["春木爭秀發，嗟君獨不材。", "須慚一花少，強逐衆芳開。", "頑艶人誰采，微香蝶不來。", "直爲無用物，空爾費栽培。"]'),
('878fdc46-bc2f-4184-9c9a-086644a8cced','杏解嘲','司馬光','宋','宋诗','song-poetry','','[]','造物本非我，榮枯那足言。',48,'全唐诗/poet.song.29000.json','["造物本非我，榮枯那足言。", "但餘良幹在，何必艶花繁。", "壯麗華林苑，歡娛梓澤園。", "芳菲如可采，豈得侍君軒。"]'),
('c92e4a19-b4fe-471f-852a-3a06e256b7a9','寄陜西提刑江學士','司馬光','宋','宋诗','song-poetry','','[]','明主於庶獄，選才從本朝。',48,'全唐诗/poet.song.29000.json','["明主於庶獄，選才從本朝。", "鄼侯三尺律，漢使一封軺。", "郡國清名滿，關河古意饒。", "淒涼乘障客，華髪日蕭蕭。"]'),
('47a04e4d-fe45-485a-a358-14237993dd07','從始平公城西大閲','司馬光','宋','宋诗','song-poetry','','[]','滄溟浴日照春臺，組練光中玉帳開。',64,'全唐诗/poet.song.29000.json','["滄溟浴日照春臺，組練光中玉帳開。", "汾水騰凌金鼓震，西山宛轉斾旌迴。", "逍遙靜散晴空雨，叱咤横飛迥野雷。", "坐鎮四夷真漢相，武侯空復道英才。"]'),
('73e121f7-a0d8-4f4f-bdcd-47d5d86b55ce','陪諸君北園樂飲','司馬光','宋','宋诗','song-poetry','','[]','浩歌縱飲任天機，莫使歡娛與性違。',64,'全唐诗/poet.song.29000.json','["浩歌縱飲任天機，莫使歡娛與性違。", "玉枕醉人從獨卧，金羈倦客聽先歸。", "須知會府閑時少，況復邊城樂事稀。", "花卉正濃風日好，今年已不負春暉。"]'),
('6bf81e25-12a7-40cc-b34e-67640adcdcb3','和道矩紅梨花二首  其一','司馬光','宋','宋诗','song-poetry','','[]','繁枝細葉互低昂，香敵酴醾艶海棠。',32,'全唐诗/poet.song.29000.json','["繁枝細葉互低昂，香敵酴醾艶海棠。", "應爲窮邊太寥落，併將春色付穠芳。"]'),
('3e3537b0-d11f-4168-91d3-423b66632679','和道矩紅梨花二首  其二','司馬光','宋','宋诗','song-poetry','','[]','蜀江新錦濯朝陽，楚國纖腰傅薄粧。',32,'全唐诗/poet.song.29000.json','["蜀江新錦濯朝陽，楚國纖腰傅薄粧。", "何事白花零落早，同時不改鬭芬芳。"]'),
('d42fdf71-d9c1-4834-b75c-4f83c7a3b333','和懋賢聞道矩小園置酒助以酒果副之以詩','司馬光','宋','宋诗','song-poetry','','[]','芙蓉幕下惜餘閑，不使芳華取次殘。',32,'全唐诗/poet.song.29000.json','["芙蓉幕下惜餘閑，不使芳華取次殘。", "珍果醇醪與新句，併將佳味助清歡。"]'),
('c09ebb33-304b-4e7c-b4c5-88b001a4a805','數日不至後圃今晚偶來芳物都盡率然成詩','司馬光','宋','宋诗','song-poetry','','[]','爛漫不解賞，飄零空慘悽。',24,'全唐诗/poet.song.29000.json','["爛漫不解賞，飄零空慘悽。", "殘紅正滿地，不忍踏芳蹊。"]'),
('0067eaab-a345-4a9d-bf3e-5e9ca7f4dbb3','和樂道自河外南轅過宜芳雨晴和氣景物可愛馬上偶成','司馬光','宋','宋诗','song-poetry','','[]','京洛春應老，河邊初解顔。',48,'全唐诗/poet.song.29000.json','["京洛春應老，河邊初解顔。", "碧浮煙際草，翠滴雨餘山。", "目極褰帷外，詩成攬轡間。", "滿川桃李色，共喜傳車還。"]'),
('5783d747-0933-49ad-8b08-7f116a03045d','夏日','司馬光','宋','宋诗','song-poetry','','[]','窮邊已深夏，氣色耿清秋。',48,'全唐诗/poet.song.29000.json','["窮邊已深夏，氣色耿清秋。", "鮮旭開山郭，涼煙澹戍樓。", "兠鈴烽火息，區脫虜塵收。", "迨此軍中暇，無妨文雅遊。"]'),
('0c947fba-5e08-4201-9001-523f76621d07','晨發故關寄逢吉','司馬光','宋','宋诗','song-poetry','','[]','畫戟衣中趨絳帳，驛亭門外拂征鞍。',64,'全唐诗/poet.song.29000.json','["畫戟衣中趨絳帳，驛亭門外拂征鞍。", "已嗟漂泊三年别，更負從容十日歡。", "暖席未窮談笑樂，陟岡相望滯留難。", "揚鞭策馬幾多意，原上秋風作曉寒。"]'),
('37fc6b59-96d1-45a1-8fdf-94eca2723b9a','中秋夕始平公命與考校諸君置酒賦詩','司馬光','宋','宋诗','song-poetry','','[]','月華秋色雨鮮新，萬里澄空不受塵。',64,'全唐诗/poet.song.29000.json','["月華秋色雨鮮新，萬里澄空不受塵。", "兔濯素毛騰浩露，桂飄香實下飛輪。", "光侵酒面寒無力，清入詩豪健有神。", "坐客何須辭醉倒，相君應不惜車茵。"]'),
('b8e1bb04-f40a-468f-b668-8758a0ba6d19','病酒呈晉州李八丈','司馬光','宋','宋诗','song-poetry','','[]','身如五嶺炎蒸裏，心似三江高浪中。',32,'全唐诗/poet.song.29000.json','["身如五嶺炎蒸裏，心似三江高浪中。", "誰道醉鄉風土好，舟車常願不相通。"]'),
('0aebe675-7690-4c09-b43a-8eb16bf51614','和李八丈小雪同會有懷鄰幾','司馬光','宋','宋诗','song-poetry','','[]','天祿淹回德齒尊，暫留汾曲兩朱轓。',64,'全唐诗/poet.song.29000.json','["天祿淹回德齒尊，暫留汾曲兩朱轓。", "閑軒坐嘯正飛雪，同舍倦遊來及門。", "空嘆高歌如郢客，愧無佳賦似文園。", "坐中猶欠鄰幾在，深負棋枰與酒樽。"]'),
('0920ec40-b69c-44db-b018-67af135fe2bd','三月晦日登豐州故城','司馬光','宋','宋诗','song-poetry','','[]','春盡蕪城天一涯，白榆生莢柳生花。',32,'全唐诗/poet.song.29000.json','["春盡蕪城天一涯，白榆生莢柳生花。", "滿川戰骨知誰罪，深屬來人戒覆車。"]'),
('4c70aa7e-d9fc-4f37-98ea-2598021b8d63','送張學士兩浙提點刑獄','司馬光','宋','宋诗','song-poetry','','[]','朝家重典刑，書府借時英。',48,'全唐诗/poet.song.29000.json','["朝家重典刑，書府借時英。", "鉦鼓喧江下，雲山拂眼清。", "秋風鱸鱠美，書日錦衣榮。", "勿似朱翁子，空令守邸驚。"]'),
('71408a75-282a-4ca9-82c0-ce443864a539','寄聶之美','司馬光','宋','宋诗','song-poetry','','[]','去歲雙毛白，今春一齒零。',48,'全唐诗/poet.song.29000.json','["去歲雙毛白，今春一齒零。", "人生浮似葉，客宦泛如萍。", "塞上貂裘弊，天涯海氣腥。", "何當占箕潁，蕭散並柴扃。"]'),
('ad3f005d-10a0-4244-b973-cfdfb5e9b1b4','又寄','司馬光','宋','宋诗','song-poetry','','[]','心目悠悠逐去鴻，别來容易四秋風。',32,'全唐诗/poet.song.29000.json','["心目悠悠逐去鴻，别來容易四秋風。", "莫嗟密密書連紙，萬里經年信一通。"]'),
('cde236f5-89f9-4a4e-ad22-846ae1d2a641','送昌言舍人得告還蜀三首  其一','司馬光','宋','宋诗','song-poetry','','[]','迢遞銅梁道，凝嚴青瑣闈。',48,'全唐诗/poet.song.29000.json','["迢遞銅梁道，凝嚴青瑣闈。", "負書當日去，鳴玉此時歸。", "鄉樹迎朱轂，江花照錦衣。", "臨邛不足並，榮耀古今稀。"]'),
('57352406-2b43-438a-90a8-27e608bd7741','送昌言舍人得告還蜀三首  其二','司馬光','宋','宋诗','song-poetry','','[]','悽愴懷桑梓，劬勞詠蓼莪。',48,'全唐诗/poet.song.29000.json','["悽愴懷桑梓，劬勞詠蓼莪。", "樹風今遠矣，鼎食奈悲何。", "劍閣登車近，秦關屈指過。", "騰裝纔首路，夕夢已江沱。"]'),
('0febf00d-fc1b-49aa-baad-f418c47104ef','送昌言舍人得告還蜀三首  其三','司馬光','宋','宋诗','song-poetry','','[]','富貴動歸思，由来光里閭。',48,'全唐诗/poet.song.29000.json','["富貴動歸思，由来光里閭。", "戒門羞主父，負弩笑相如。", "外物有榮悴，中心無戚疏。", "遙知見親舊，不改布衣初。"]'),
('74c36228-de6a-44da-b9e2-3a2134d19d49','祁國正獻公挽歌三首  其一','司馬光','宋','宋诗','song-poetry','','[]','舟楫才猷大，冰霜德操堅。',48,'全唐诗/poet.song.29000.json','["舟楫才猷大，冰霜德操堅。", "陶鈞成茂業，書史樂高年。", "瞻望簪紳共，吁嗟館舍捐。", "舉時無異論，方信令名全。"]'),
('597718b5-bca4-4680-a33c-d45f23c3ebad','祁國正獻公挽歌三首  其二','司馬光','宋','宋诗','song-poetry','','[]','鈞玉吳臺舊，誅茅梁苑新。',48,'全唐诗/poet.song.29000.json','["鈞玉吳臺舊，誅茅梁苑新。", "位登華衮貴，家似布衣貧。", "直道高當世，清風遺後人。", "千秋寒照目，竹帛不棲塵。"]'),
('59f00593-81bb-4ee2-b7b4-e5dbdf9524d2','祁國正獻公挽歌三首  其三','司馬光','宋','宋诗','song-poetry','','[]','先子同烏府，知音誠皦然。',48,'全唐诗/poet.song.29000.json','["先子同烏府，知音誠皦然。", "脫縗来拜伏，撫首辱哀憐。", "迨此泉扃掩，空悲塵網牽。", "無由懷酒絮，撇涕望新阡。"]'),
('bbcde7fe-237b-452f-b27a-f43d1793aa9a','侍讀王文公挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','石室書編富，金華講席重。',48,'全唐诗/poet.song.29000.json','["石室書編富，金華講席重。", "薦神歸愽洽，鳴玉稱雍容。", "貳負纍囚象，尸臣古瑑蹤。", "老成今已矣，咨訪欲誰從。"]'),
('3b3e6e7d-0c3f-4599-85c2-5f0a591d8dbc','侍讀王文公挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','杖底潛蛇影，門陰集戴鵀。',48,'全唐诗/poet.song.29000.json','["杖底潛蛇影，門陰集戴鵀。", "玉樓新記就，石槨舊銘沈。", "篋有封巒札，籝無遺子金。", "寂寥封馬鬛，秋色凈松林。"]'),
('58c62cee-7df3-4da2-ae91-493305cb7304','相國廣平文簡程公挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','明直君臣合，安危將相兼。',48,'全唐诗/poet.song.29000.json','["明直君臣合，安危將相兼。", "金章四輔貴，玉帳萬兵嚴。", "禦侮長城隱，臨繁利刃銛。", "南山霣巖石，何以慰民瞻。"]'),
('1f931207-6dff-4f3a-9063-25c816c39bbe','相國廣平文簡程公挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','帝誥封泥紫，皇墳殺簡青。',48,'全唐诗/poet.song.29000.json','["帝誥封泥紫，皇墳殺簡青。", "坐談安玉壘，專對讋龍庭。", "黼黻昭文理，冰霜瑩典刑。", "英靈入箕尾，終古作天星。"]'),
('fe2e5734-8911-44e5-8fc4-9bc34557a342','送王書記之官永興','司馬光','宋','宋诗','song-poetry','','[]','白髪添新鑷，紅塵滿弊衣。',48,'全唐诗/poet.song.29000.json','["白髪添新鑷，紅塵滿弊衣。", "人生適未值，吾道豈云非。", "鞏洛風煙遠，函秦草樹微。", "長安春酒美，行樂勿令希。"]'),
('64137567-446a-4be1-9340-ffc81c093a19','和錢學士呈邵興宗','司馬光','宋','宋诗','song-poetry','','[]','霜露蒼蒼宰樹高，累茵列鼎重鴻毛。',64,'全唐诗/poet.song.29000.json','["霜露蒼蒼宰樹高，累茵列鼎重鴻毛。", "蒹葭自幸猶依玉，髖髀何能學奏刀。", "才薄無由禆覆燾，命奇不得報劬勞。", "平生念此心先亂，蓼蓼難分莪與蒿。"]'),
('05551700-3ed6-4bbb-996f-9f24b01b6b8b','曉思','司馬光','宋','宋诗','song-poetry','','[]','束带朝尚早，蓬門未脫扃。',48,'全唐诗/poet.song.29000.json','["束带朝尚早，蓬門未脫扃。", "短籬潛落月，老樹带孤星。", "隱几貂裘黑，開編竹簡青。", "子雲非執戟，何以得窮經。"]'),
('7cc1ce61-d749-4243-ba42-db5e5b62d820','送朱職方提舉江淮運鹽','司馬光','宋','宋诗','song-poetry','','[]','熬漉滄波耗，征輸澤國貧。',48,'全唐诗/poet.song.29000.json','["熬漉滄波耗，征輸澤國貧。", "嬰羅矜赤子，運筴借能臣。", "拜手觚稜曉，浮舟狼湯春。", "東南待蘇息，别酒莫逡巡。"]'),
('321fc672-9569-4169-9429-6c69c169eac2','送次道知太平州','司馬光','宋','宋诗','song-poetry','','[]','狼湯春流滿，蕪湖候吏迎。',48,'全唐诗/poet.song.29000.json','["狼湯春流滿，蕪湖候吏迎。", "旌旟曉日麗，鉦鼓野風清。", "暫喜紅塵遠，休嗟素髪生。", "專城方四十，自古以爲榮。"]'),
('f7bde166-d77f-4529-9ce5-4e0fbf103ef7','送蘇屯田知單州','司馬光','宋','宋诗','song-poetry','','[]','佳郡望都城，相聞擊柝聲。',48,'全唐诗/poet.song.29000.json','["佳郡望都城，相聞擊柝聲。", "賓朋纔執别，耆舊已前迎。", "綵服當年戲，驪駒此日榮。", "絃歌應盡在，琴調不須更。"]'),
('79ad79c6-51bd-41ab-bb30-ee5f1725e9c5','錢君倚示詩有歸吳之興爲詩三十二韻以贈','司馬光','宋','宋诗','song-poetry','','[]','吳越爲君土，崤函是我家。',288,'全唐诗/poet.song.29000.json','["吳越爲君土，崤函是我家。", "濯纓從吏事，傾蓋聚京華。", "奕世交朋重，同僚分誼加。", "聲光嘗耳剽，臭味辱肩差。", "選士參縣石，烝髦應椓罝。", "帝畿圍日月，蓬堵積煙霞。", "咨訪傾肝膽，推褒借齒牙。", "後來慚瓦礫，旁倚愧蒹葭。", "談論寥天一，詼諧老柏槎。", "虚舟坦莫逆，璞玉瑩無瑕。", "信美陪遊衍，胡爲起咄嗟。", "勞歌盡鄉思，旅夢各天涯。", "誠厭簪紳累，難堪獄訟譁。", "缿筩朝插蝟，貫索暮如麻。", "霢霂霑朝服，蜩螗沸尹衙。", "宿姦牢窟宅，弊俗費鞭撾。", "鮆鱠思吹絮，羊羮憶卧沙。", "梅林連雨熟，梨味得霜佳。", "秋色城臨水，春風路入花。", "稻肥初斷蟹，桑密不通鴉。", "蹙衂浮盤芡，鈎聯卧壠瓜。", "江蓴半卷葉，石蕨乍舒芽。", "風物隨鄉樂，山川苦道遐。", "若人才有裕，修已德無邪。"]'),
('752f057d-1f76-429d-9b2d-a6b522515ec8','喜張聖民得登州','司馬光','宋','宋诗','song-poetry','','[]','晝日少閑暇，中宵夢亦勞。',48,'全唐诗/poet.song.29000.json','["晝日少閑暇，中宵夢亦勞。", "符移空浩浩，榜楚鎮謷謷。", "敢說今求郡，番思昔坐曹。", "羨君乘五馬，東去一何高。"]'),
('0d0d3516-f68e-426b-ba71-e8009535d1eb','詩寄雲夫處士老兄兼呈知府待制八丈','司馬光','宋','宋诗','song-poetry','','[]','一鶚曾飛奏，中林下鶴書。',48,'全唐诗/poet.song.29000.json','["一鶚曾飛奏，中林下鶴書。", "今乘使君馬，重到逸人居。", "松竹過從久，閭閻惠愛餘。", "只應棠樹影，比舊更扶疏。"]'),
('23b4f009-7e73-4043-b110-ed6712664b14','和任屯田感舊敘懷','司馬光','宋','宋诗','song-poetry','','[]','結交英俊樂如何，風誼敦明寄詠歌。',96,'全唐诗/poet.song.29000.json','["結交英俊樂如何，風誼敦明寄詠歌。", "自致青雲今有幾，化爲異物已居多。", "櫝中本自沽良價，毫末安能滑至和。", "鄰笛不堪頻嘆息，酒爐那得重經過。", "年華易度窗塵影，人事難期海水波。", "賢業著鞭猶可在，況君壯齒未蹉跎。"]'),
('b48e9409-5548-411c-968f-f044d05715ce','送李學士使北','司馬光','宋','宋诗','song-poetry','','[]','征蓋霜空迥，飄飄迎塞鴻。',48,'全唐诗/poet.song.29000.json','["征蓋霜空迥，飄飄迎塞鴻。", "虜牙侵海角，漢節下天中。", "酒薄陰山雪，裘寒易水風。", "邊聲不可聽，歸思浩無窮。"]'),
('d23c0969-f875-475f-a6c4-a87608b18af4','送薛水部十丈通判并州','司馬光','宋','宋诗','song-poetry','','[]','十萬貔貅士，旌旗晉水陽。',48,'全唐诗/poet.song.29000.json','["十萬貔貅士，旌旗晉水陽。", "元戎倚耆碩，别乘選才良。", "秀直寒松節，精明利劍鋩。", "知君留滯久，從此欲騰驤。"]'),
('b8d91460-4297-4c8d-be58-1bcbda65149f','送祖澤之守陜','司馬光','宋','宋诗','song-poetry','','[]','聲教空巖穴，夫君集帝庭。',144,'全唐诗/poet.song.29000.json','["聲教空巖穴，夫君集帝庭。", "辭華動丹扆，光價塞青冥。", "俊德爭推轂，榮塗易建瓴。", "陸離寒水玉，磊落曙天星。", "得喪誰先識，艱虞困屢經。", "蹉跎渥洼足，漂泊鳳凰翎。", "粉署疏恩紀，甘棠寄典刑。", "仁風思布濩，疲俗待綏寧。", "賤子良多愧，餘光每乞靈。", "題名聯士版，占籍備民丁。", "種種顛毛白，蕭蕭壟栢青。", "陌頭瞻皁蓋，獨立涕飄零。"]'),
('e6cc347c-3a38-42ed-a8bd-60edf419710a','奉和江鄰幾六月七日文德殿觀文武百官等上尊號十五韻','司馬光','宋','宋诗','song-poetry','','[]','舜禹曾何與，羲農實強名。',180,'全唐诗/poet.song.29000.json','["舜禹曾何與，羲農實強名。", "含靈徒叶贊，造物始無情。", "閶闔非煙澹，觚稜曉氣清。", "葳蕤大衢隘，殷轔外朝盈。", "鮮旭分衣繪，薫風拂佩瓊。", "華顛方內集，殊俗海隅傾。", "棨戟金閨奥，囊書赭案横。", "敷言齊列位，稽首從羣卿。", "不報乾坤施，難圖日月明。", "仁心由性得，治體與時行。", "金石皆中款，丹青豈外榮。", "功歸元首重，澤及草茅輕。", "業業冲虚意，區區愛戴誠。", "何爲猶讓德，不以慰懷生。", "退復歌天保，期於采頌聲。"]'),
('b138f1ab-5b15-4b5b-a250-dbe277b19ac1','和始平公郡齋偶書二首  其一','司馬光','宋','宋诗','song-poetry','','[]','文武從容兩有餘，公槐將幕往來居。',64,'全唐诗/poet.song.29000.json','["文武從容兩有餘，公槐將幕往來居。", "已安四海如三傑，欲散千金比二疏。", "今日監邊親跪轂，佗年入殿賜乘車。", "武侯暫爲蒼生起，長憶隆中卧舊廬。"]'),
('dff22446-a758-4149-a7a2-701bd112624a','和始平公郡齋偶書二首  其二','司馬光','宋','宋诗','song-poetry','','[]','平安候火出雲間，區脫無塵刁斗閑。',64,'全唐诗/poet.song.29000.json','["平安候火出雲間，區脫無塵刁斗閑。", "漢相威聲遙制敵，胡兵遠迹夜開關。", "赤松雅意思輕舉，黄閣羣心望復還。", "玉帳牙旗空壯觀，謝公高興在東山。"]'),
('b85a7340-16ec-4f11-bc9b-be7165172504','感興寄聶之美','司馬光','宋','宋诗','song-poetry','','[]','平生百無可，強爲一官縻。',48,'全唐诗/poet.song.29000.json','["平生百無可，強爲一官縻。", "世味偏予薄，心期獨子知。", "林猿愁玉瑣，櫪馬患金羈。", "年事今華髪，求榮欲爲誰。"]'),
('e63b7bfc-e051-4b50-b0e2-3b8787238c6e','八月七日夜省直苦雨三首  其一','司馬光','宋','宋诗','song-poetry','','[]','夜色槐陰重，雨聲官舍寒。',48,'全唐诗/poet.song.29000.json','["夜色槐陰重，雨聲官舍寒。", "野農安敢問，環堵未能完。", "盡日流雲度，何時大塊乾。", "正愁開霽晚，霜霧滿紅欄。"]'),
('c92cc64a-673f-4dc6-a1ab-8227e2d82333','八月七日夜省直苦雨三首  其二','司馬光','宋','宋诗','song-poetry','','[]','悵望中秋月，於今已上弦。',48,'全唐诗/poet.song.29000.json','["悵望中秋月，於今已上弦。", "明生圭様小，影露桂花偏。", "幽思邈難致，浮雲去不還。", "何當出陰翳，清徹照中天。"]'),
('a12df7b6-2529-4553-89b3-6249e722c849','八月七日夜省直苦雨三首  其三','司馬光','宋','宋诗','song-poetry','','[]','菊蘂如排粟，青青見葉心。',48,'全唐诗/poet.song.29000.json','["菊蘂如排粟，青青見葉心。", "未嘗窺白日，何以散黄金。", "欹側疏籬短，綿延蔓草深。", "寒蛩爾何與，終夕亦悲吟。"]'),
('5b8e1f4e-f3e3-40fd-a490-a7d5d40e3d7e','次韻和鄰幾秋雨十六韻','司馬光','宋','宋诗','song-poetry','','[]','氣象殊朝夕，興居錯晦明。',192,'全唐诗/poet.song.29000.json','["氣象殊朝夕，興居錯晦明。", "混元初不宰，霪雨浩無程。", "蟄隘寧天意，咨嗟固物情。", "曣㬈方有望，薈蔚已隨生。", "杲杲升還隱，悽悽斷復行。", "亂莎長被徑，荒蘚綠緣甍。", "轍迹康莊絕，潢汙壠畝平。", "茅茨不足庇，禾黍若爲成。", "蟋蟀頽牆泣，蛜蝛壞竈盈。", "乘時衆鷗舞，得意怒蛙鳴。", "牛馬誰分異，蕭蘭已混并。", "居閑猶叵度，負重況遐征。", "舟泊川無渚，輪摧路有阬。", "轑羹愁病婦，煬竈擁寒嬰。", "災不妨明德，神應格至誠。", "淳光終下燭，時藿久心傾。"]'),
('c99338b2-7965-49ac-9d67-c3e2da24b497','紫微石舍人挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','地勝岷峨秀，時清雋乂生。',48,'全唐诗/poet.song.29000.json','["地勝岷峨秀，時清雋乂生。", "揚雄晚得祿，何武少知名。", "性有圖書癖，心忘紱冕榮。", "前年歸諭蜀，不使里人驚。"]'),
('60d75aba-1602-45d4-8f61-5aca8255f210','紫微石舍人挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','顧我非君比，最爲相得歡。',48,'全唐诗/poet.song.29000.json','["顧我非君比，最爲相得歡。", "平生遊處久，美行始終完。", "長夜忍埋玉，秋霜不借蘭。", "西風濕襟袖，空有淚闌干。"]'),
('2578fb9f-acdb-4400-a704-f30aac0899ef','次韻和沖卿中秋朧月','司馬光','宋','宋诗','song-poetry','','[]','豈無錦幄翠簾垂，匝樹明燈正赫曦。',64,'全唐诗/poet.song.29000.json','["豈無錦幄翠簾垂，匝樹明燈正赫曦。", "共惜月華方滿夜，更當秋色中分時。", "烏皮几穩風侵鬢，白玉樓高冷透肌。", "千里浮雲何處斷，北來試問鴈應知。"]'),
('af9e06bd-771c-40ea-a850-03453fcd8dd7','次韻和江鄰幾九月五日省直','司馬光','宋','宋诗','song-poetry','','[]','羣騶布路歆，瘦馬解鞍迴。',48,'全唐诗/poet.song.29000.json','["羣騶布路歆，瘦馬解鞍迴。", "雨闋蟲聲樂，秋深菊意催。", "圖書紛自適，僚友邈誰陪。", "何以消寒夜，殘醪不滿杯。"]'),
('ee6dfbe8-f8ec-4357-88a6-265e042c2f59','吳正肅公挽歌辭三首  其一','司馬光','宋','宋诗','song-poetry','','[]','皇家延茂異，鶚立迥無倫。',48,'全唐诗/poet.song.29000.json','["皇家延茂異，鶚立迥無倫。", "高議誰能奪，英才自有真。", "驊騮寧受縶，水鑑不棲塵。", "試爲咨清論，風流第幾人。"]'),
('38c20a1d-e378-40d0-856c-bb9c4c877221','吳正肅公挽歌辭三首  其二','司馬光','宋','宋诗','song-poetry','','[]','辭華已獨步，政治復無前。',48,'全唐诗/poet.song.29000.json','["辭華已獨步，政治復無前。", "吏不容三宂，民皆戴二天。", "於今知和寡，自古愧才偏。", "惆悵棠陰下，仁風尚藹然。"]'),
('0a2c3554-ccf4-4719-864d-4eed74bf8642','吳正肅公挽歌辭三首  其三','司馬光','宋','宋诗','song-poetry','','[]','念昔少年日，謬登君子堂。',48,'全唐诗/poet.song.29000.json','["念昔少年日，謬登君子堂。", "重言何以稱，厚德不能忘。", "玉麈聲容在，泉臺歲月長。", "憑誰寄清淚，爲我灑松岡。"]'),
('a1855a69-bfcc-49d1-b863-8421dd366071','和江鄰幾金鈴菊','司馬光','宋','宋诗','song-poetry','','[]','何處見佳菊，秋風汶水陽。',48,'全唐诗/poet.song.29000.json','["何處見佳菊，秋風汶水陽。", "酒浮金鐸細，露泛蜜房香。", "不謂紅塵地，相逢君子堂。", "依然故人意，不減舊芬芳。"]'),
('f07c85a6-0383-4d78-8377-218c644bdaf2','送賢良陳著作簽書壽州判官','司馬光','宋','宋诗','song-poetry','','[]','海隅方萬里，豪雋幾何人。',48,'全唐诗/poet.song.29000.json','["海隅方萬里，豪雋幾何人。", "百汰求才盡，三薰得士新。", "聲華四方聳，器業一朝伸。", "佗日蒼生望，非徒澤壽春。"]'),
('a2e7866a-9900-40e9-a04a-46ae876b9c26','致政邵少卿挽詞','司馬光','宋','宋诗','song-poetry','','[]','北固啟佳城，東吳霣德星。',48,'全唐诗/poet.song.29000.json','["北固啟佳城，東吳霣德星。", "繐帷長寂寞，羽扇遂飄零。", "泉燭千年碧，霜松數寸青。", "餘慶知有在，玉樹滿階庭。"]'),
('628b4e99-1700-4791-8475-21e236381cda','之美訪及不獲展奉以詩爲謝','司馬光','宋','宋诗','song-poetry','','[]','昔君來闕下，定館必吾廬。',48,'全唐诗/poet.song.29000.json','["昔君來闕下，定館必吾廬。", "今者雖相值，依然是索居。", "不堪休沐少，便使往還疏。", "深愧原思巷，空迴長者車。"]'),
('bc9a699a-2515-42eb-be0c-7546b6b8ff2a','送聶秘丞宰桐城二首  其一','司馬光','宋','宋诗','song-poetry','','[]','問子青雲器，胡爲不少留。',48,'全唐诗/poet.song.29000.json','["問子青雲器，胡爲不少留。", "未能充祿養，安散及身謀。", "卓爾千人俊，居然百里憂。", "連城價終在，自是玉工羞。"]'),
('849f0c7c-7f3d-48b3-91ba-42fcca229590','送聶秘丞宰桐城二首  其二','司馬光','宋','宋诗','song-poetry','','[]','七載一相見，怳然如路衢。',48,'全唐诗/poet.song.29000.json','["七載一相見，怳然如路衢。", "形骸漸枯槁，志業轉荒蕪。", "往事雲過眼，新愁雪染鬚。", "明朝又分首，上馬即重湖。"]'),
('f07988f3-d841-476d-98ba-74ccdc83c110','送蒲中舍霜致政歸蜀  其一','司馬光','宋','宋诗','song-poetry','','[]','厭苦折腰久，飄然黄鵠飛。',48,'全唐诗/poet.song.29000.json','["厭苦折腰久，飄然黄鵠飛。", "田園未蕪沒，鄰曲有光輝。", "昔奮儒衣去，今紆朝紱歸。", "人生貴知足，得此已爲稀。"]'),
('d16b537f-b120-46d7-80ab-6d27f0f64d3f','送蒲中舍霜致政歸蜀  其二','司馬光','宋','宋诗','song-poetry','','[]','念昔兩髦日，烏奴同燕遊。',48,'全唐诗/poet.song.29000.json','["念昔兩髦日，烏奴同燕遊。", "随時自有樂，何物可爲愁。", "豈意今頭白，相逢欲涕流。", "憑君訪題壁，好在水西樓。"]'),
('62d3ef89-45aa-4ab1-8d60-f2128073ceb5','蘇門先生','司馬光','宋','宋诗','song-poetry','','[]','長嘯蘇門石，行藏世莫知。',48,'全唐诗/poet.song.29000.json','["長嘯蘇門石，行藏世莫知。", "逍遙心迹遠，寂寞姓名誰。", "郷在無何有，時方不可爲。", "麒麟本神物，安得係而羈。"]'),
('af14ce20-e909-448a-ac9d-59c877c53154','和沖卿喜雨偶成','司馬光','宋','宋诗','song-poetry','','[]','萬里風隨快雨來，塵昏消伏旱光開。',64,'全唐诗/poet.song.29000.json','["萬里風隨快雨來，塵昏消伏旱光開。", "物情濯熱參差喜，天意爲仁容易迴。", "簾映薄寒燈有暈，窗含虚白麝成煤。", "君侯雅有江湖興，蕭灑何須氣象催。"]'),
('330ae91c-8607-444a-bf63-70e30c5646d6','寄贈致仕劉都官','司馬光','宋','宋诗','song-poetry','','[]','星郎年未至，辭祿一何高。',96,'全唐诗/poet.song.29000.json','["星郎年未至，辭祿一何高。", "目瑩棲靈氣，眉疏出秀毫。", "胸中自有樂，身外盡徒勞。", "回首紅塵地，紛紛笑我曹。", "解紱沱江外，誅茅井絡邊。", "老萊夫婦隱，韋孟子孫賢。", "浮蟻邀旁舍，蹲鴟種薄田。", "不須親几杖，想望已蕭然。"]'),
('79165597-19b4-4c97-86c7-0f348005741e','和宋郎中孟秋省直','司馬光','宋','宋诗','song-poetry','','[]','夜久殘暑盡，好風來滿襟。',48,'全唐诗/poet.song.29000.json','["夜久殘暑盡，好風來滿襟。", "牀空唯置枕，冠小不施簪。", "竹影亂凉月，林梢轉曉參。", "人心有喧寂，何必欲雲岑。"]'),
('b7bb63f8-5f74-45e3-8d29-4928968bbbd8','八月五日夜省直','司馬光','宋','宋诗','song-poetry','','[]','大火已西落，温風猶襲人。',48,'全唐诗/poet.song.29000.json','["大火已西落，温風猶襲人。", "留連惜紈扇，散誕脫紗巾。", "蟾影夜色淺，蛩聲秋意新。", "圖書足自適，何物更關身。"]'),
('29536955-48fa-45f2-9cd4-4bc4d286b841','送王著作西京簽判','司馬光','宋','宋诗','song-poetry','','[]','古來都邑美，孰與雒陽先。',48,'全唐诗/poet.song.29000.json','["古來都邑美，孰與雒陽先。", "况復元侯貴，兼之從事賢。", "玦離横闕塞，珠曲逗伊川。", "慰眼登臨樂，送君空惘然。"]'),
('a125856d-10f9-4e21-8850-ec4f2bf9c288','夢稚子','司馬光','宋','宋诗','song-poetry','','[]','窮泉纖骨已成塵，幽草閑花二十春。',32,'全唐诗/poet.song.29000.json','["窮泉纖骨已成塵，幽草閑花二十春。", "昔日相逢猶是夢，今宵夢裏更非真。"]'),
('af25f8e0-c673-4f9d-9e05-a025a3cf4ce2','梅聖俞挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','兵形窮勝負，史法貫興衰。',48,'全唐诗/poet.song.29000.json','["兵形窮勝負，史法貫興衰。", "落落雖殊衆，恂恂不迕時。", "位卑名自重，才大命須奇。", "世俗那能識，傷嗟止爲詩。"]'),
('076ca609-28df-4ce7-86ae-d353e1dd736b','梅聖俞挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','漆燈無復曙，柏徑不知春。',48,'全唐诗/poet.song.29000.json','["漆燈無復曙，柏徑不知春。", "南紀光華减，中朝俊秀貧。", "淒清千古韻，寂寞一丘塵。", "異日昭亭下，方多瀝酒人。"]'),
('116c396d-d049-4377-b4a5-341b9fbd2c10','次韻和王勝之十二月十五日朝退馬上作','司馬光','宋','宋诗','song-poetry','','[]','瓦溝微白雪光清，闕角初紅海日騰。',64,'全唐诗/poet.song.29000.json','["瓦溝微白雪光清，闕角初紅海日騰。", "塵息長街千騎入，鞘鳴深殿六龍昇。", "雲巖有客空回首，圭蓽何人尚曲肱。", "自笑鯫生章綬縛，不容逃去正如罾。"]'),
('6f439c81-b9d9-47fd-b8d7-1f17a944e2d3','又和雪','司馬光','宋','宋诗','song-poetry','','[]','四簷冰管未全晞，一夕陰風雪又飛。',64,'全唐诗/poet.song.29000.json','["四簷冰管未全晞，一夕陰風雪又飛。", "客卧牛衣憂死别，人留玉塞望生歸。", "公車歳晚憐東郭，遼海雲深失令威。", "頗憶當年映書否，物華如舊鬢毛非。"]'),
('d7c9e938-6334-4b3e-80c6-075aca59ff4d','送裴中舍赴太原幕府','司馬光','宋','宋诗','song-poetry','','[]','元戎台鼎舊，大府節旄新。',48,'全唐诗/poet.song.29000.json','["元戎台鼎舊，大府節旄新。", "邊候正無事，賓筵况得人。", "山寒太行曉，水碧晉祠春。", "齋釀蒲萄熟，飛觴不厭頻。"]'),
('225cc1d1-5db1-4ea6-86ae-3843ff86e86a','和吳省副梅花半開招憑由張司封飲','司馬光','宋','宋诗','song-poetry','','[]','帝鄉春色嶺頭梅，高壓年華犯雪開。',64,'全唐诗/poet.song.29000.json','["帝鄉春色嶺頭梅，高壓年華犯雪開。", "正與嘉賓思共醉，不須芳物重相催。", "從車貯酒傳呼出，側弁簪花倒載迴。", "風雨難期王事劇，未知休沐幾旬來。"]'),
('03338d53-56c8-44a4-bac2-39a401db4369','郭氏園送張仲通出刺棣州','司馬光','宋','宋诗','song-poetry','','[]','名園送嘉客，冠蓋去傾朝。',48,'全唐诗/poet.song.29000.json','["名園送嘉客，冠蓋去傾朝。", "小雨塵微斂，餘寒酒易消。", "鴈歸春近塞，日上海生潮。", "北道平如掌，東風五馬驕。"]'),
('c25a1fc4-36f5-4e4a-8241-aced3137b11b','賞花釣魚二首  其一','司馬光','宋','宋诗','song-poetry','','[]','飛廉通上苑，鳷鵲带天淵。',72,'全唐诗/poet.song.29000.json','["飛廉通上苑，鳷鵲带天淵。", "樹色含春霧，波光静曉烟。", "香飄仙仗外，花舞御卮前。", "籊籊文竿裊，簁簁素鮪鮮。", "誤陪金馬籍，愧奉栢梁篇。", "願獻南山壽，宸遊侍億年。"]'),
('a0bc8136-00f7-4acd-8b3a-0198ba2f1bd7','賞花釣魚二首  其二','司馬光','宋','宋诗','song-poetry','','[]','日麗芙蓉闕，春榮太液波。',72,'全唐诗/poet.song.29000.json','["日麗芙蓉闕，春榮太液波。", "苑門鳴玉集，輦路翠華過。", "芳樹周阿密，嘉魚在渚多。", "浮英入樽斚，頒首出蒲荷。", "人樂熙熙德，臣賡旦旦歌。", "萬生同鼓舞，相與醉天和。"]'),
('3e978c99-20a5-45a0-b0c4-d822addafb16','御製後苑賞花釣魚七言四韻詩一首奉聖旨次韻','司馬光','宋','宋诗','song-poetry','','[]','馺娑蜚廉次第開，鳴鞘傳蹕自天來。',64,'全唐诗/poet.song.29000.json','["馺娑蜚廉次第開，鳴鞘傳蹕自天來。", "雲隨綵仗低臨幄，柳壓金堤翠入杯。", "檻倚柔風絲縹渺，花翻麗日影徘徊。", "上林春色長如舊，玉輦嬉遊歳歳陪。"]'),
('ebe5d504-7e18-42f3-92c0-548113f8deb3','秦人','司馬光','宋','宋诗','song-poetry','','[]','楚旗獵獵蓋山紅，回首咸陽一炬空。',32,'全唐诗/poet.song.29000.json','["楚旗獵獵蓋山紅，回首咸陽一炬空。", "惆悵秦人虛用意，幾年辛苦得山東。"]'),
('552260c5-76a4-4f2f-b978-443ad03eccca','送致仕朱郎中令孫','司馬光','宋','宋诗','song-poetry','','[]','世間榮利無窮物，奔走勞勞何所之。',64,'全唐诗/poet.song.29000.json','["世間榮利無窮物，奔走勞勞何所之。", "仕宦爲郎非不達，功名有命待無時。", "橐中雖乏千金直，膝下常攜兩綬兒。", "細校人生能此少，好從閭里樂期頤。"]'),
('741fe173-4004-4248-8d5d-93a741c7faa0','依韻和仲庶省壁畫山水','司馬光','宋','宋诗','song-poetry','','[]','畫工執筆已心遊，稍稍蘅皋引杜洲。',64,'全唐诗/poet.song.29000.json','["畫工執筆已心遊，稍稍蘅皋引杜洲。", "堆案煩文猶倦暑，滿軒新意忽驚秋。", "天生賢者非無謂，官遇明時未易休。", "正恐怒飛朝暮事，丹青難得久淹留。"]'),
('c0bc8108-cfad-4a62-8a10-4ebc553f01e7','太博同年葉兄以詩及建茶爲貺家有蜀牋二軸輒敢繫詩二章獻於左右亦投桃報李之意也  其一','司馬光','宋','宋诗','song-poetry','','[]','閩山草木未全春，破纇真茶采擷新。',32,'全唐诗/poet.song.29000.json','["閩山草木未全春，破纇真茶采擷新。", "雅意不忘同臭味，先分疇昔桂堂人。"]'),
('7dcebcec-09c3-4527-b867-c78fe6214a7f','太博同年葉兄以詩及建茶爲貺家有蜀牋二軸輒敢繫詩二章獻於左右亦投桃報李之意也  其二','司馬光','宋','宋诗','song-poetry','','[]','西來萬里浣花牋，舒卷雲霞照手鮮。',32,'全唐诗/poet.song.29000.json','["西來萬里浣花牋，舒卷雲霞照手鮮。", "書笥久藏無可稱，願投詩客助新編。"]'),
('7d1f34ad-98d6-4b6d-8795-94a7e15cd762','送宋郎中知鳳翔府','司馬光','宋','宋诗','song-poetry','','[]','昔解陳倉印，於今二十秋。',48,'全唐诗/poet.song.29000.json','["昔解陳倉印，於今二十秋。", "雙鳬久東上，五馬重西遊。", "鐃騎行關外，壺漿擁道周。", "民心已化服，條教不更修。"]'),
('479267aa-355a-4d82-a74e-f152d6a2feaf','秋夕不寐呈諌長樂道龍圖','司馬光','宋','宋诗','song-poetry','','[]','雨氣生燈暈，霜寒入漏聲。',72,'全唐诗/poet.song.29000.json','["雨氣生燈暈，霜寒入漏聲。", "疏籬過螢影，腐葉掩蟲鳴。", "丘壑違初願，簪裾徇外榮。", "丹心終夜苦，白髪詰朝生。", "恩與乾坤大，身如草木輕。", "何階見明主，垂拱視升平。"]'),
('f2237ddf-db58-4e27-aa83-8c82846a93f5','始平公以光得免使北賜之以詩謹依韻酬和','司馬光','宋','宋诗','song-poetry','','[]','皇華將命得人難，專對非才輒自言。',64,'全唐诗/poet.song.29000.json','["皇華將命得人難，專對非才輒自言。", "幸免驅車涉沙漠，尚容載筆侍宣温。", "不唯羞屈穹廬膝，無奈常遊魏闕魂。", "衮職區區未能補，何時餘論奉清樽。"]'),
('2755ad8d-2052-4716-ae39-97ed58c78eb0','孟嘗','司馬光','宋','宋诗','song-poetry','','[]','冠蓋盈門意氣豪，海魚兼雨未充庖。',32,'全唐诗/poet.song.29000.json','["冠蓋盈門意氣豪，海魚兼雨未充庖。", "歸來散盡三千客，方悟時人市道交。"]'),
('6117baf0-e7de-479b-b86d-cd1926751fd3','喜李侍郎得西京留臺','司馬光','宋','宋诗','song-poetry','','[]','賤子何爲者，栖栖今二毛。',48,'全唐诗/poet.song.29000.json','["賤子何爲者，栖栖今二毛。", "滄波浮片葉，大塊載秋毫。", "利物物何補，營身身已勞。", "羨君遺世網，脫屣一何高。"]'),
('210156e4-42d2-4550-9f2a-0a3a5f797289','始平公新作雙樗庵命光爲詩','司馬光','宋','宋诗','song-poetry','','[]','間氣生王佐，多才秉國鈞。',48,'全唐诗/poet.song.29000.json','["間氣生王佐，多才秉國鈞。", "棟隆憑杞梓，節勁仰松筠。", "底績承平業，遺榮壽考身。", "結廬依散木，退讓樂天真。"]'),
('fe59db38-fca4-4a5d-8069-c971fa08b83e','忝職諌垣日負憂畏緬思雲夫處士老兄蕭然物外何樂如之因成浮槎詩寄獻以抒鄙懷','司馬光','宋','宋诗','song-poetry','','[]','秋水浮槎客，漂如一葉輕。',48,'全唐诗/poet.song.29000.json','["秋水浮槎客，漂如一葉輕。", "鷗羣須仗信，鯨口幾忘生。", "耿耿天津闊，滔滔海浪驚。", "何時還故土，懷糈問君平。"]'),
('11e5a853-5921-4ef8-a7aa-539fe71e93d3','邇英閣讀畢後漢書蒙恩賜御筵詩','司馬光','宋','宋诗','song-poetry','','[]','赤伏開興運，昆陽定壮圖。',216,'全唐诗/poet.song.29000.json','["赤伏開興運，昆陽定壮圖。", "官儀還舊物，郊兆建新都。", "杲日羣陰破，油雲萬類蘇。", "鑾輿陟喬嶽，璽綬撫匈奴。", "厚祿優諸將，嘉猷訪大儒。", "重明紹堂構，奕葉奉規摹。", "叔世條綱紊，遺風節義扶。", "袁安空隕涕，楊震卒蒙辜。", "佞指車前鹿，人瞻屋上烏。", "炎精盡河渚，黄眚兆當塗。", "青簡傳良直，金華侍燕娛。", "興衰炳轍迹，淑慝粲龜符。", "赫赫天光照，孳孳睿思紆。", "方齊建武治，不啻永平俱。", "化盛文明正，恩隆飲食需。", "晞陽慚杞棘，濡咮愧鵜鶘。", "帝力生成大，臣功報效無。", "先民誠可監，願不忘斯須。"]'),
('8f7043f7-3b9d-47b4-a161-3f8706815dcd','送李侍郎西京留臺','司馬光','宋','宋诗','song-poetry','','[]','先公勛烈盛鹽梅，清白仍聞世濟才。',64,'全唐诗/poet.song.29000.json','["先公勛烈盛鹽梅，清白仍聞世濟才。", "華省拂衣辭簿領，長衢回首謝塵埃。", "嵩峰排霧依稀出，洛水迎人迤邐来。", "寄語馬前頭白吏，何殊昔日李西臺。"]'),
('cbadaa80-474d-4e54-9f6a-abbfb8d27573','送元待制出牧福唐','司馬光','宋','宋诗','song-poetry','','[]','甌越東南美，田肥果稼饒。',48,'全唐诗/poet.song.29000.json','["甌越東南美，田肥果稼饒。", "况懷新賜綬，重過舊題橋。", "食足姦回熄，風移獄犴銷。", "長才報政速，鈴閣日逍遙。"]'),
('ea1ab542-cf61-4057-a241-6c2642acc609','送吳駕部知真州','司馬光','宋','宋诗','song-poetry','','[]','曏託屏星駕，同隨丞相車。',48,'全唐诗/poet.song.29000.json','["曏託屏星駕，同隨丞相車。", "終朝容懶拙，經歲庇迂疏。", "共此趨雲闕，旋聞建隼旟。", "江淮一都會，遊刃必多餘。"]'),
('0e342aed-538b-4ce0-b197-8a3ef5e1c236','和趙子輿龍州吏隱堂','司馬光','宋','宋诗','song-poetry','','[]','四望逶迤萬疊山，微通雲棧落塵寰。',64,'全唐诗/poet.song.29000.json','["四望逶迤萬疊山，微通雲棧落塵寰。", "誰知吏道自可隱，未必仙家有此閑。", "酒熟何人能共醉，詩成無事復相關。", "浮生適意即爲樂，安用腰金鼎鼐間。"]'),
('2b528f57-eb96-4881-9921-d11d7c2d4064','寄題錢君倚明州重修衆樂亭','司馬光','宋','宋诗','song-poetry','','[]','横橋通廢島，華宇出荒榛。',48,'全唐诗/poet.song.29000.json','["横橋通廢島，華宇出荒榛。", "風日逢知已，湖山得主人。", "使君如獨樂，衆庶必深顰。", "何以知家給，笙歌滿水濱。"]'),
('fd238b26-4d12-48d9-990f-1a2b9b36f39c','張元常挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','爲吏文無害，臨民政不苛。',48,'全唐诗/poet.song.29000.json','["爲吏文無害，臨民政不苛。", "渾金生自美，古井澹無波。", "方喜風鵬舉，旋聞隙駟過。", "善人宜壽考，報施定如何。"]'),
('8e780b0a-4a6e-45c1-95c1-9e6fbf4b0d98','張元常挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','秀眉無足驗，結轖遽爲災。',48,'全唐诗/poet.song.29000.json','["秀眉無足驗，結轖遽爲災。", "鄉曲三年别，江山萬里迴。", "林閭飛旐入，書劍逐舟来。", "墳草枯還綠，重泉不復開。"]'),
('ea2b16c2-611a-4573-9df6-772b637741f9','冬夜','司馬光','宋','宋诗','song-poetry','','[]','冬夜何其永，寒光四泬寥。',48,'全唐诗/poet.song.29000.json','["冬夜何其永，寒光四泬寥。", "鴈横星歷歷，人靜漏迢迢。", "破屋霜應重，荒庭雪未消。", "不眠何所念，達曉思無憀。"]'),
('7e5d80e1-4272-4908-9997-1aac502bdd5b','奉和御製龍圖等閣觀三聖御書','司馬光','宋','宋诗','song-poetry','','[]','積厚丕丕業，重光郁郁文。',48,'全唐诗/poet.song.29000.json','["積厚丕丕業，重光郁郁文。", "寶書垂列宿，玉字切浮雲。", "散帙鳴鑾駐，充庭雜珮分。", "願移天縱藝，似續聖功勤。"]'),
('976f5cda-e203-4a28-8b1c-f7c0cdcd2ee9','和范景仁夜讀試卷','司馬光','宋','宋诗','song-poetry','','[]','案前官燭墮花頻，滿目高文妙入神。',64,'全唐诗/poet.song.29000.json','["案前官燭墮花頻，滿目高文妙入神。", "勇氣先登勢無敵，巧心後發語尤新。", "好賢何啻三薫貴，求寶方知百汰真。", "愚魯自非憑驥髪，崑山千里到無因。"]'),
('0dca363f-de1b-4419-85e3-17ba4f0ba259','又和雪霽','司馬光','宋','宋诗','song-poetry','','[]','南宮來幾時，挾纊易春衣。',48,'全唐诗/poet.song.29000.json','["南宮來幾時，挾纊易春衣。", "意謂花將晚，何言雪尚飛。", "夜聲通旅枕，曉色弄晴暉。", "繼日勞王事，離離鴈已歸。"]'),
('0dfd6525-7042-4223-90b6-c5436c33026b','又和二月五日夜風雪','司馬光','宋','宋诗','song-poetry','','[]','春風正豪怒，夜雪復飄揚。',48,'全唐诗/poet.song.29000.json','["春風正豪怒，夜雪復飄揚。", "勿使羈愁亂，自知清興長。", "簾疏聲淅瀝，燈冷暈微茫。", "此夕牛衣客，成名不可忘。"]'),
('d30bef48-7807-49ed-acd4-a2ffe350e82c','仁宗皇帝挽歌詞二首  其一','司馬光','宋','宋诗','song-poetry','','[]','聲教萬餘里，文明四十春。',48,'全唐诗/poet.song.29000.json','["聲教萬餘里，文明四十春。", "茂勛留信史，盛德滿生民。", "共適禽魚樂，安知橐籥仁。", "百年龍馭遠，空復仰威神。"]'),
('c3b7a393-8892-43fe-90c5-b1f55d432c24','仁宗皇帝挽歌詞二首  其二','司馬光','宋','宋诗','song-poetry','','[]','霧曉銅魚躍，霜寒閶闔開。',48,'全唐诗/poet.song.29000.json','["霧曉銅魚躍，霜寒閶闔開。", "哀聲際海發，靈仗拂天来。", "别寢嚴虚位，重閽閟夜臺。", "柏城空有路，無復屬車回。"]'),
('252cd112-bb5d-4bd9-b110-4da82b0b8c9d','故相國潁公挽歌辭三首  其一','司馬光','宋','宋诗','song-poetry','','[]','儒衣臨絕塞，廟略運奇兵。',48,'全唐诗/poet.song.29000.json','["儒衣臨絕塞，廟略運奇兵。", "緩带羌塵靜，靈旗海霧清。", "公心結明主，陰德庇羣生。", "名遂身仍退，人間五福并。"]'),
('10a8896c-5b00-4e36-b428-d3a0e95ac99e','故相國潁公挽歌辭三首  其二','司馬光','宋','宋诗','song-poetry','','[]','銘旌遠明滅，騎吹去低昂。',48,'全唐诗/poet.song.29000.json','["銘旌遠明滅，騎吹去低昂。", "三鼎功名大，重泉日月長。", "鶴飛来弔客，牛臥卜連岡。", "車馬還城郭，悲風滿白楊。"]'),
('72962847-47fd-456c-a544-701ba5450955','故相國潁公挽歌辭三首  其三','司馬光','宋','宋诗','song-poetry','','[]','滄波與鄧林，魚鳥久飛沉。',48,'全唐诗/poet.song.29000.json','["滄波與鄧林，魚鳥久飛沉。", "一旦成陳迹，何人識寸心。", "高山亡景行，流水失知音。", "淚盡離東閣，歸来破故琴。"]'),
('7873f138-532b-4c60-800d-30aa352939d6','讀潁公清風集  其一','司馬光','宋','宋诗','song-poetry','','[]','伊臯垂訓皆王度，周召陳詩盡國風。',32,'全唐诗/poet.song.29000.json','["伊臯垂訓皆王度，周召陳詩盡國風。", "非獨立言方不朽，相君功業自無窮。"]'),
('1c96422a-86f2-4b04-8e01-d72532869862','讀潁公清風集  其二','司馬光','宋','宋诗','song-poetry','','[]','人生百歲隙中光，唯有高名久不忘。',32,'全唐诗/poet.song.29000.json','["人生百歲隙中光，唯有高名久不忘。", "千古但令編簡在，清風養物一何長。"]'),
('1115376b-c1cd-43b4-bb35-fe455aa6ecea','讀潁公清風集  其三','司馬光','宋','宋诗','song-poetry','','[]','佳城鬰鬰閟英靈，幸有文章見典型。',32,'全唐诗/poet.song.29000.json','["佳城鬰鬰閟英靈，幸有文章見典型。", "開卷未終雙袖濕，目前彷彿對淵庭。"]'),
('09f04f47-681c-450f-9ca4-e4bd2115a6bd','讀潁公清風集  其四','司馬光','宋','宋诗','song-poetry','','[]','一言華衮足爲榮，况託文編久愈明。',32,'全唐诗/poet.song.29000.json','["一言華衮足爲榮，况託文編久愈明。", "鄒湛不逢羊叔子，世間何處復知名。"]'),
('a252bb52-4b21-4dfa-bbb0-87e51c2bc03e','寄題興州晁都官東沼沼上有唐鄭都官詩刻石','司馬光','宋','宋诗','song-poetry','','[]','名郎遊勝地，心跡繼風流。',48,'全唐诗/poet.song.29000.json','["名郎遊勝地，心跡繼風流。", "昔爲題詩著，今因好事修。", "四山相照映，五馬屢淹留。", "想見波光凈，依然一片秋。"]'),
('71303d12-59b9-4406-b51f-73c9fb3afdba','送周密學真定安撫使','司馬光','宋','宋诗','song-poetry','','[]','玉帳前茅舉，銅魚左契分。',48,'全唐诗/poet.song.29000.json','["玉帳前茅舉，銅魚左契分。", "平生公望著，期月政聲聞。", "陌上壺漿溢，潭邊花氣曛。", "遙知待新將，民物兩欣欣。"]'),
('8962cb09-caf8-4a07-92ee-7c27ab7a39e7','贈狄節推','司馬光','宋','宋诗','song-poetry','','[]','天馬雲孫在，終然骨相奇。',48,'全唐诗/poet.song.29000.json','["天馬雲孫在，終然骨相奇。", "泥塗辱雖久，霜雪志難移。", "白髪無嗟老，青衫莫厭卑。", "爲山已九仞，高節肯中衰。"]'),
('bd6ea70e-dbcf-4d83-85c3-250d4b0ea23f','送丁正臣知蔡州','司馬光','宋','宋诗','song-poetry','','[]','䟃𧽼汝水濱，千騎擁朱輪。',48,'全唐诗/poet.song.29000.json','["䟃𧽼汝水濱，千騎擁朱輪。", "懸瓠遺基古，鞶囊吉夢新。", "丹心留紫闥，清耳遠紅塵。", "須識明君意，先應試治民。"]'),
('cb1c4762-bbe8-4d16-9b72-3a35e96c8fb0','感春','司馬光','宋','宋诗','song-poetry','','[]','積草滿春庭，衡門永晝扃。',48,'全唐诗/poet.song.29000.json','["積草滿春庭，衡門永晝扃。", "波頭何事白，柳眼爲誰青。", "榮落浮雲度，悲歡熟醉醒。", "繁華非我物，隨意任飄零。"]'),
('4ad935ae-d75a-4be1-8371-1e58e33a50ca','不寐','司馬光','宋','宋诗','song-poetry','','[]','四遠寂然羣動收，只餘嚴鼓度坊樓。',32,'全唐诗/poet.song.29000.json','["四遠寂然羣動收，只餘嚴鼓度坊樓。", "無由更續三更夢，何處飛来一點愁。"]'),
('7d23a2f1-c484-466e-a744-15571a8e407b','雞','司馬光','宋','宋诗','song-poetry','','[]','羽短籠深不得飛，久留寧爲稻粱肥。',32,'全唐诗/poet.song.29000.json','["羽短籠深不得飛，久留寧爲稻粱肥。", "膠膠風雨鳴何苦，滿室高眠正掩扉。"]'),
('cb5fbe47-b1c8-4d22-b0f0-4dc7a2049861','光皇祐二年謁告歸鄉里至治平二年方得再来愴然感懷詩以紀事','司馬光','宋','宋诗','song-poetry','','[]','十六載重歸，順塗歌式微。',48,'全唐诗/poet.song.29000.json','["十六載重歸，順塗歌式微。", "青松弊廬在，白首故人稀。", "外飾服章改，流光顔貎非。", "巫咸舊山色，相見尚依依。"]'),
('e4e349a6-4f14-42f8-b77a-9e7b42335996','辭墳','司馬光','宋','宋诗','song-poetry','','[]','十年一展墓，旬浹復東旋。',48,'全唐诗/poet.song.29000.json','["十年一展墓，旬浹復東旋。", "豈負襁褓愛，横遭章綬纒。", "更来知幾日，遺恨恐終天。", "慟哭出松徑，悲風爲颯然。"]'),
('e78a4076-e84a-4128-ae02-c2778b4c9202','謁三門禹祠  其一','司馬光','宋','宋诗','song-poetry','','[]','信矣禹功美，獨兼人鬼謀。',48,'全唐诗/poet.song.29000.json','["信矣禹功美，獨兼人鬼謀。", "長山忽中斷，巨浸失横流。", "迹與天地久，民無魚鼈憂。", "誰能報盛德，空爾薦醪羞。"]'),
('4b904359-6b96-483c-9da1-9107846b34bb','謁三門禹祠  其二','司馬光','宋','宋诗','song-poetry','','[]','贔屭青崖裂，喧豗白浪豪。',48,'全唐诗/poet.song.29000.json','["贔屭青崖裂，喧豗白浪豪。", "客舟浮木葉，生理脫鴻毛。", "栢映孤峰短，銘書絕壁高。", "河師不耕織，容易戲風濤。"]'),
('6057879d-1779-47f1-ad1c-a16aa24c0c6e','遊三門開化寺','司馬光','宋','宋诗','song-poetry','','[]','山石古来色，河流無盡聲。',48,'全唐诗/poet.song.29000.json','["山石古来色，河流無盡聲。", "行船自往返，羣木幾枯榮。", "狂象調難伏，空華滅復生。", "我来何所得，聊此濯塵纓。"]'),
('f9ba1a10-79a7-4d5b-b67d-e674397c85f1','送僧歸吳','司馬光','宋','宋诗','song-poetry','','[]','高枕聊成夢，晴空忽見花。',48,'全唐诗/poet.song.29000.json','["高枕聊成夢，晴空忽見花。", "浮生盡是客，何處得爲家。", "旅食帝城久，歸舟澤國賖。", "勿因菰菜味，回首浩無涯。"]'),
('72990819-eb0e-4e0f-893b-4ad9f94b6a84','次韻和韓子華寒食休沐與諸公同會趙令園暮歸馬上偶成','司馬光','宋','宋诗','song-poetry','','[]','冠蓋連翩陌上来，風光爛漫擁樓臺。',64,'全唐诗/poet.song.29000.json','["冠蓋連翩陌上来，風光爛漫擁樓臺。", "玉卮貯酒隨宜飲，綺席尋花觸處開。", "小雨前宵先撥火，季春明日又吹灰。", "須知勝集人間少，惆悵金羈容易迴。"]'),
('2cf61984-88f6-4357-9fdd-14f557c8353e','送晁秘丞通判雄州','司馬光','宋','宋诗','song-poetry','','[]','少傅名德重，蔚然人物師。',48,'全唐诗/poet.song.29000.json','["少傅名德重，蔚然人物師。", "群孫滿丹穴，嘉瑞盡長離。", "勿嘆毛羽短，已驚文采奇。", "勉哉勤志業，餘慶未應衰。"]'),
('67c13433-467f-4b37-a498-3d8a9205ba29','光頃爲諸生常受經於錢丈學賦於張丈今乃叨忝同爲侍臣蒙錢丈置酒張丈賜詩不勝愧悚之深言志爲謝','司馬光','宋','宋诗','song-poetry','','[]','疇昔勝冠日，曾爲絳帳生。',48,'全唐诗/poet.song.29000.json','["疇昔勝冠日，曾爲絳帳生。", "九言聞至教，一顧得虚聲。", "不意叨嚴近，於今接老成。", "寧須詩酒賜，侍坐導知榮。"]'),
('b086e999-a833-4709-880a-1d151a10bba1','宋相國公挽辭二首  其一','司馬光','宋','宋诗','song-poetry','','[]','仁聖初承緒，敷天籲雋賢。',48,'全唐诗/poet.song.29000.json','["仁聖初承緒，敷天籲雋賢。", "得人兹最盛，射策獨居先。", "禁省英聲遠，巖廊至化宣。", "辭榮還故第，三事究高年。"]'),
('6d1aeca0-c428-4b2c-8c80-c15f9923a318','宋相國公挽辭二首  其二','司馬光','宋','宋诗','song-poetry','','[]','邦光華衮襚，家寶素書陳。',48,'全唐诗/poet.song.29000.json','["邦光華衮襚，家寶素書陳。", "東閣簪裾散，西芒宅兆新。", "泉臺無復曉，柏逕不知春。", "獨有高文在，芬芳繼古人。"]'),
('2269a3ce-d420-4eeb-bc92-147af8261e22','英宗皇帝挽歌辭三首  其一','司馬光','宋','宋诗','song-poetry','','[]','盛德師堯舜，英姿肖祖宗。',48,'全唐诗/poet.song.29000.json','["盛德師堯舜，英姿肖祖宗。", "太陽光徧照，滄海量兼容。", "鴻業知能繼，齊民望可封。", "如何未五載，已上鼎湖龍。"]'),
('d9b74e32-da0b-44db-874c-4821b89dcff9','英宗皇帝挽歌辭三首  其二','司馬光','宋','宋诗','song-poetry','','[]','虹瑞流朱邸，童髦侍紫宸。',48,'全唐诗/poet.song.29000.json','["虹瑞流朱邸，童髦侍紫宸。", "簡心天與子，授位帝知人。", "學古功時敏，鉤深道日新。", "宜然三百載，民物仰威神。"]'),
('1f4ea33c-7b58-413b-907a-b303858037e5','英宗皇帝挽歌辭三首  其三','司馬光','宋','宋诗','song-poetry','','[]','諫省臣無狀，龍鱗昔屢嬰。',48,'全唐诗/poet.song.29000.json','["諫省臣無狀，龍鱗昔屢嬰。", "恩深忘位賤，義重覺生輕。", "不正誅鋤法，仍蒙奬嘆榮。", "百身何足報，天造固難名。"]'),
('a7107b13-45be-4186-ae4c-535443cdaf82','送燕諫議知潭州','司馬光','宋','宋诗','song-poetry','','[]','長沙地饒美，賈誼獨傷悲。',48,'全唐诗/poet.song.29000.json','["長沙地饒美，賈誼獨傷悲。", "自古臨榮辱，幾人無怨咨。", "使君擁符節，大艦出江湄。", "意氣陶然樂，應無弔屈辭。"]'),
('0bbab9d2-2e03-4863-8418-93165b167fd3','送李益之侍郎致政歸廬山  其一','司馬光','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','儒業金華貴，歸心白鶴孤。',48,'全唐诗/poet.song.29000.json','["儒業金華貴，歸心白鶴孤。", "江山依舊在，軒冕曏来無。", "嘯詠誰當共，登臨未索扶。", "浩然知此樂，迥與世人殊。"]'),
('b6cf1b99-1423-4302-b44d-be303f753a5c','送李益之侍郎致政歸廬山  其二','司馬光','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','水底元無月，衣中自有珠。',48,'全唐诗/poet.song.29000.json','["水底元無月，衣中自有珠。", "六塵皆外物，萬法盡迷塗。", "瀑布寒雲濕，觚稜瑞氣扶。", "遙知至樂地，不異在京都。"]'),
('366a524e-2370-444b-9880-c8ad785256cb','資善堂宴餞應詔','司馬光','宋','宋诗','song-poetry','','[]','士論歸清德，皇心重老成。',48,'全唐诗/poet.song.29000.json','["士論歸清德，皇心重老成。", "陳謨侍經席，得謝解塵纓。", "坐密金章並，行徐玉醴清。", "都門昔供帳，疏傅未爲榮。"]'),
('3d805959-7a31-4a78-b186-2b0ad8ee49ea','胡太傅挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','行冠鄉人品，文爲學者師。',48,'全唐诗/poet.song.29000.json','["行冠鄉人品，文爲學者師。", "黄裳藴厚德，玉律儼清規。", "大節人難奪，嘉謨世莫知。", "儀型不可見，遺烈滿豐碑。"]'),
('e8964594-5434-4d2e-8bf6-2fdca876f141','胡太傅挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','裴回游內禁，密勿贊鴻樞。',48,'全唐诗/poet.song.29000.json','["裴回游內禁，密勿贊鴻樞。", "陰德加民物，清名服士夫。", "天方遺一老，星忽隕三吳。", "疑從龍髯去，乘雲在帝都。"]'),
('93050efd-04f7-457c-b57b-59f0fd40c76f','送惠思歸錢塘','司馬光','宋','宋诗','song-poetry','','[]','孤岫平湖外，禪房老栢陰。',48,'全唐诗/poet.song.29000.json','["孤岫平湖外，禪房老栢陰。", "倦遊諳濁世，獨往遂初心。", "夜雨燈窗迥，秋苔屐齒深。", "勿鉏山徑草，便有俗人尋。"]'),
('884f9c1d-4ddd-4280-a5f3-ff8680d31860','鄭侍郎挽歌辭','司馬光','宋','宋诗','song-poetry','','[]','雲夢氣回復，比肩生雋豪。',48,'全唐诗/poet.song.29000.json','["雲夢氣回復，比肩生雋豪。", "司農家學富，廷尉里門高。", "騏驥昔千里，鳳凰今一毛。", "即邱餘慶在，終應呂虔刀。"]'),
('620de905-dabf-4ca6-9053-9de13a3b8521','和吴仲庶寄吴瑛比部安道之子壯年致政歸隱蘄春','司馬光','宋','宋诗','song-poetry','','[]','負米承親願已賒，恥隨雞鶩啄泥沙。',64,'全唐诗/poet.song.29000.json','["負米承親願已賒，恥隨雞鶩啄泥沙。", "一朝投紱真高士，萬卷藏書舊世家。", "齒髪未衰非藥物，山林不返爲雲霞。", "龐眉尚有郎潛者，徇祿憂生直可嗟。"]'),
('8af58123-be3a-45d1-9436-238356ed89b8','送吳仲庶知江寧','司馬光','宋','宋诗','song-poetry','','[]','江南佳麗地，人物自風流。',48,'全唐诗/poet.song.29000.json','["江南佳麗地，人物自風流。", "青骨靈祠在，黄旗王氣收。", "衣冠餘舊俗，歌頌樂賢侯。", "正恐還朝速，江山未遍遊。"]'),
('87e4286d-43e2-4790-a0c0-16f40c0ffaaf','蘇才翁子美有贈扶溝白鶴觀黄道士詩紀于屋壁歲久漫滅今縣宰周同年得完本於民間抵予求詩','司馬光','宋','宋诗','song-poetry','','[]','潦倒黄冠無足論，白頭嗜酒住荒村。',64,'全唐诗/poet.song.29000.json','["潦倒黄冠無足論，白頭嗜酒住荒村。", "狂名偶爲留詩著，陳迹仍因好事存。", "金石鏘洋虚殿寂，龍蛇灑落古牆昏。", "飛黄滅沒浮雲外，疲馬何能望駿奔。"]'),
('2b342cba-cf57-4cdc-b6fd-fadee7bbcbec','長垣道中作','司馬光','宋','宋诗','song-poetry','','[]','極目王畿四坦然，方輿如地蓋如天。',32,'全唐诗/poet.song.29000.json','["極目王畿四坦然，方輿如地蓋如天。", "始知恃險不如德，去殺勝殘已百年。"]'),
('42eefd04-eff4-43dd-8dcb-fb93aa944b9d','再使河北','司馬光','宋','宋诗','song-poetry','','[]','桑麥青青四月初，皇華使者又脂車。',32,'全唐诗/poet.song.29000.json','["桑麥青青四月初，皇華使者又脂車。", "爲臣豈得辭王事，壽昌侍郎巽之子。"]'),
('897a40b3-ae32-4c7d-9360-d43f4a311867','河北道中作  其一','司馬光','宋','宋诗','song-poetry','','[]','綠柳陰中白浪花，河邊日日暗風沙。',32,'全唐诗/poet.song.29000.json','["綠柳陰中白浪花，河邊日日暗風沙。", "解鞍縱馬悄無事，隱几看書隨處家。"]'),
('f5579674-a600-499d-aaee-b81564476949','河北道中作  其二','司馬光','宋','宋诗','song-poetry','','[]','河勢東迴今幾年，濃陰滿目盡桑田。',32,'全唐诗/poet.song.29000.json','["河勢東迴今幾年，濃陰滿目盡桑田。", "川原變化無終極，一氣不爲常寂然。"]'),
('3d971d5c-9435-49fa-9859-af553b488028','河北道中作  其三','司馬光','宋','宋诗','song-poetry','','[]','原上纍纍古冢高，昔時意氣盡賢豪。',32,'全唐诗/poet.song.29000.json','["原上纍纍古冢高，昔時意氣盡賢豪。", "斷碑名姓已磨滅，永日東風吹野蒿。"]'),
('c477fd69-e0fa-42ec-bb54-4881ad1718bf','夜發長垣','司馬光','宋','宋诗','song-poetry','','[]','長塗暑氣劇，永日卧郵亭。',48,'全唐诗/poet.song.29000.json','["長塗暑氣劇，永日卧郵亭。", "畫伏如牆鼠，宵行似野螢。", "歇鞍沙月白，拂面柳風醒。", "歷歷瞻雲漢，誰爲二使星。"]'),
('6e20589c-9fd4-443c-9a51-9502c01b0ae8','送丁正臣通判復州','司馬光','宋','宋诗','song-poetry','','[]','得失固有命，世人空自勞。',48,'全唐诗/poet.song.29000.json','["得失固有命，世人空自勞。", "冬温少霜雪，松短沒蓬蒿。", "孤宦千里遠，榮名一旦高。", "回看碌碌者，太華與秋毫。"]'),
('a75f80a5-8c80-4cb7-a15c-71170a241945','致政王侍郎挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','弱冠獻奇策，居然終賈才。',48,'全唐诗/poet.song.29000.json','["弱冠獻奇策，居然終賈才。", "賦成平樂館，歌奉柏梁杯。", "麗藻留昭世，英遊隔夜臺。", "土中埋美玉，誰見不興哀。"]'),
('2a5f2d47-4cc7-4c6c-b671-8f0d9501da23','致政王侍郎挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','振鷺辭靈沼，冥鴻翔太虚。',48,'全唐诗/poet.song.29000.json','["振鷺辭靈沼，冥鴻翔太虚。", "清朝解鳴玉，舊里掛安車。", "詩酒江山勝，園林俸祿餘。", "所忠今不往，誰奏茂陵書。"]'),
('1e281b7e-e081-45d5-8728-08789e22559a','景仁招遊東園馬上口占','司馬光','宋','宋诗','song-poetry','','[]','適野自可愛，况逢佳主人。',48,'全唐诗/poet.song.29000.json','["適野自可愛，况逢佳主人。", "馬穿官柳影，衣拂帝城塵。", "物外誰知樂，樽前别有春。", "年華己消歇，歷歷見松筠。"]'),
('d61130a3-5971-4b69-aef2-a36fa3e571cc','依前韻奉送才元和甫使北','司馬光','宋','宋诗','song-poetry','','[]','析木带天津，華星隨去人。',48,'全唐诗/poet.song.29000.json','["析木带天津，華星隨去人。", "揚旍踰絕漠，負弩候前塵。", "出塞風霜苦，歸塗楊柳春。", "會書專對美，燁燁滿秋筠。"]'),
('51227116-f4ea-406b-8d23-1d9defb9693d','哭劉仲邍  其一','司馬光','宋','宋诗','song-poetry','','[]','天下才無幾，夫君獨患多。',48,'全唐诗/poet.song.29000.json','["天下才無幾，夫君獨患多。", "高文粲列宿，英辯瀉長河。", "榮宦成朝夢，浮生度尺波。", "舊僚空執酒，相與淚滂沱。"]'),
('aeb5b0bf-1491-4600-acde-5e37971850de','哭劉仲邍  其二','司馬光','宋','宋诗','song-poetry','','[]','昔醉金明渚，今来慧辯祠。',48,'全唐诗/poet.song.29000.json','["昔醉金明渚，今来慧辯祠。", "當年笑相視，此日哭殊悲。", "天迥川原凈，風高草木衰。", "江梅靈氣在，泉下復相知。"]'),
('1ba2fae2-063c-4c29-9baf-4106eefd98ab','送向防禦知陳州','司馬光','宋','宋诗','song-poetry','','[]','千騎去翩翩，專城上少年。',48,'全唐诗/poet.song.29000.json','["千騎去翩翩，專城上少年。", "韋平家好學，陰馬世稱賢。", "官用才能進，恩非雨露偏。", "想聞河潤遠，封畛帝畿連。"]'),
('39c2d609-23f5-4f78-aec9-777c393829c5','春貼子詞 皇帝閣六首 其一','司馬光','宋','宋诗','song-poetry','','[]','肇履璿璣曆，重飛緹室灰。',24,'全唐诗/poet.song.29000.json','["肇履璿璣曆，重飛緹室灰。", "寒隨土牛盡，暖應斗車回。"]'),
('305e15b4-4bf4-4ced-8565-a60cc96b86fe','春貼子詞 皇帝閣六首 其二','司馬光','宋','宋诗','song-poetry','','[]','鸞路迎長日，農祥正曉天。',24,'全唐诗/poet.song.29000.json','["鸞路迎長日，農祥正曉天。", "九垓同燠沐，萬物向蕃鮮。"]'),
('9a353e15-5f80-4318-bb52-23d624aa17de','春貼子詞 皇帝閣六首 其三','司馬光','宋','宋诗','song-poetry','','[]','盛德方迎木，柔風漸布和。',24,'全唐诗/poet.song.29000.json','["盛德方迎木，柔風漸布和。", "省耕將效駕，擊壤已聞歌。"]'),
('52c619d7-068d-441a-ae8c-0421df0243d7','春貼子詞 皇帝閣六首 其四','司馬光','宋','宋诗','song-poetry','','[]','候鴈来歸北，寒魚陟負冰。',24,'全唐诗/poet.song.29000.json','["候鴈来歸北，寒魚陟負冰。", "相烏風色改，暘谷日華升。"]'),
('563eebce-cb9e-4318-94fd-36893b9aef57','春貼子詞 皇帝閣六首 其五','司馬光','宋','宋诗','song-poetry','','[]','浮陽滿野白溶溶，澤底山椒淑氣通。',32,'全唐诗/poet.song.29000.json','["浮陽滿野白溶溶，澤底山椒淑氣通。", "草木豈能知造化，一華一葉盡天功。"]'),
('15e7aa98-07b5-41e6-8477-0c063f8cd0c0','春貼子詞 皇帝閣六首 其六','司馬光','宋','宋诗','song-poetry','','[]','漠然天造與時新，根著浮流一氣均。',32,'全唐诗/poet.song.29000.json','["漠然天造與時新，根著浮流一氣均。", "萬物不須雕刻巧，正如恭已布深仁。"]'),
('da2cdade-fa5d-41cf-9b36-4b01a0e9a115','春貼子詞 太皇太后閣六首 其一','司馬光','宋','宋诗','song-poetry','','[]','盛德初臨震，陽和已動坤。',24,'全唐诗/poet.song.29000.json','["盛德初臨震，陽和已動坤。", "發生天施大，厚載母儀尊。"]'),
('582e531b-a078-4f5a-b7dd-70e8d8aa5902','春貼子詞 太皇太后閣六首 其二','司馬光','宋','宋诗','song-poetry','','[]','種桃臨玉井，裁勝刻金花。',24,'全唐诗/poet.song.29000.json','["種桃臨玉井，裁勝刻金花。", "借問此何處，崑山王母家。"]'),
('af92218b-fb58-4c18-b394-e77bdb702595','春貼子詞 太皇太后閣六首 其三','司馬光','宋','宋诗','song-poetry','','[]','長樂曉鐘殘，皇輿入問安。',24,'全唐诗/poet.song.29000.json','["長樂曉鐘殘，皇輿入問安。", "東風猶料峭，冒絮禦餘寒。"]'),
('856349cc-457e-454a-9ac8-af5a8af5ff7f','春貼子詞 太皇太后閣六首 其四','司馬光','宋','宋诗','song-poetry','','[]','慶壽風煙接未央，飛樓複道鬰相望。',32,'全唐诗/poet.song.29000.json','["慶壽風煙接未央，飛樓複道鬰相望。", "春来無以銷長日，閑取經書教小王。"]'),
('e10877ee-2ce5-4bb2-af87-ac70134f04e6','春貼子詞 太皇太后閣六首 其五','司馬光','宋','宋诗','song-poetry','','[]','冰澌半解波先綠，柳葉未生條已黄。',32,'全唐诗/poet.song.29000.json','["冰澌半解波先綠，柳葉未生條已黄。", "四海澄清天子孝，朝回日奉萬年觴。"]'),
('73597eb8-8f58-486f-a892-e7853305ce31','春貼子詞 太皇太后閣六首 其六','司馬光','宋','宋诗','song-poetry','','[]','東宮歸政五年餘，隱几時觀黄老書。',32,'全唐诗/poet.song.29000.json','["東宮歸政五年餘，隱几時觀黄老書。", "禁闥無爲民自化，熙熙不獨在春初。"]'),
('2ae6deb0-f909-4842-a58b-4ce0b3bb459d','春貼子詞 皇太后閣六首 其一','司馬光','宋','宋诗','song-poetry','','[]','母德思齊盛，天心奮豫初。',24,'全唐诗/poet.song.29000.json','["母德思齊盛，天心奮豫初。", "青暉凝輦路，佳氣擁宸居。"]'),
('0d2f49cc-6f87-4861-8673-0aea66d3eaa4','春貼子詞 皇太后閣六首 其二','司馬光','宋','宋诗','song-poetry','','[]','暖日初添刻，柔風乍襲衣。',24,'全唐诗/poet.song.29000.json','["暖日初添刻，柔風乍襲衣。", "弄孫時哺果，觀織屢臨機。"]'),
('69d5e948-5e6d-4bd1-a7a7-27b506acb5eb','春貼子詞 皇太后閣六首 其三','司馬光','宋','宋诗','song-poetry','','[]','膾肉紛銀縷，蘭芽蔟紫茸。',24,'全唐诗/poet.song.29000.json','["膾肉紛銀縷，蘭芽蔟紫茸。", "太官遵舊俗，歲歲與今同。"]'),
('0de77cbf-964c-4906-83c4-f5e1658c63f1','春貼子詞 皇太后閣六首 其四','司馬光','宋','宋诗','song-poetry','','[]','釵上花開海燕飛，紅繒翦萼蠟粘枝。',32,'全唐诗/poet.song.29000.json','["釵上花開海燕飛，紅繒翦萼蠟粘枝。", "風前飄蕩參差羽，還似瑤箱呈瑞時。"]'),
('c526e3a2-700c-4f75-98aa-35ebd8359665','春貼子詞 皇太后閣六首 其五','司馬光','宋','宋诗','song-poetry','','[]','玉漏聲殘金殿開，乘輿清蹕問安来。',32,'全唐诗/poet.song.29000.json','["玉漏聲殘金殿開，乘輿清蹕問安来。", "盡將草木欣欣意，同與新春入壽杯。"]'),
('a5fadeb6-971c-43d0-b8ec-98b03a941d08','春貼子詞 皇太后閣六首 其六','司馬光','宋','宋诗','song-poetry','','[]','裁縫大練成春服，慈儉由来性所鍾。',32,'全唐诗/poet.song.29000.json','["裁縫大練成春服，慈儉由来性所鍾。", "肯使外家矜侈靡，車如流水馬如龍。"]'),
('bd99db89-5e34-4f08-9240-795e21dd7f35','春貼子詞 皇后閣五首 其一','司馬光','宋','宋诗','song-poetry','','[]','穜稑獻新種，禕褕澣舊衣。',24,'全唐诗/poet.song.29000.json','["穜稑獻新種，禕褕澣舊衣。", "玉鈎隨步輦，行看采桑歸。"]'),
('4e2cf87e-a0d5-4f81-85b9-c3a8558a7935','春貼子詞 皇后閣五首 其二','司馬光','宋','宋诗','song-poetry','','[]','樛木猶藏葉，夭桃未作花。',24,'全唐诗/poet.song.29000.json','["樛木猶藏葉，夭桃未作花。", "六宮歌逮下，四海詠宜家。"]'),
('602f6c27-642c-460f-88d6-d10cd60010da','春貼子詞 皇后閣五首 其三','司馬光','宋','宋诗','song-poetry','','[]','溝暖冰初斷，牎晴雪半消。',24,'全唐诗/poet.song.29000.json','["溝暖冰初斷，牎晴雪半消。", "餘寒不足畏，塗壁盡芳椒。"]'),
('e73bfdfa-20bf-421b-b8c9-b5dedd49f7ec','春貼子詞 皇后閣五首 其四','司馬光','宋','宋诗','song-poetry','','[]','寶勝金幡巧鬬功，綵花蠟燕颺和風。',32,'全唐诗/poet.song.29000.json','["寶勝金幡巧鬬功，綵花蠟燕颺和風。", "玉盤翠苣映紅蓼，捧案朝来獻兩宮。"]'),
('88db143a-0501-417d-800b-054eaa370cec','春貼子詞 皇后閣五首 其五','司馬光','宋','宋诗','song-poetry','','[]','春衣不用蕙蘭薰，領緣無煩刺繡文。',32,'全唐诗/poet.song.29000.json','["春衣不用蕙蘭薰，領緣無煩刺繡文。", "曾在蠶宮親織紞，方知縷縷盡辛勤。"]'),
('546ea5b5-bce5-4eba-b907-a95ee544907f','春貼子詞 夫人閣四首 其一','司馬光','宋','宋诗','song-poetry','','[]','壁带非煙潤，金鋪霽景鮮。',24,'全唐诗/poet.song.29000.json','["壁带非煙潤，金鋪霽景鮮。", "繡功添采縷，和氣入繁絃。"]'),
('b63fac7c-5b7f-406f-a726-58ec6599a113','春貼子詞 夫人閣四首 其二','司馬光','宋','宋诗','song-poetry','','[]','翦綵催花發，開簾望燕歸。',24,'全唐诗/poet.song.29000.json','["翦綵催花發，開簾望燕歸。", "藏鬮新過臘，習舞競裁衣。"]'),
('c8cd71fc-cfad-426a-8829-3eb627485124','春貼子詞 夫人閣四首 其三','司馬光','宋','宋诗','song-poetry','','[]','綺窗繡戶又東風，丹掖遊陪歲歲同。',32,'全唐诗/poet.song.29000.json','["綺窗繡戶又東風，丹掖遊陪歲歲同。", "但願太平無限樂，何須三十六離宮。"]'),
('7937a2ec-f84d-42f1-bfa3-e5e1dee4a55c','春貼子詞 夫人閣四首 其四','司馬光','宋','宋诗','song-poetry','','[]','聖主終朝勤萬幾，燕居專事養希夷。',32,'全唐诗/poet.song.29000.json','["聖主終朝勤萬幾，燕居專事養希夷。", "千門永晝春岑寂，不用車前插竹枝。"]'),
('48d9ca22-1dd8-4f24-8366-e7e6adc165aa','和景仁瓊林席上偶成','司馬光','宋','宋诗','song-poetry','','[]','念昔瓊林賜宴歸，綵衣綠綬正相宜。',64,'全唐诗/poet.song.29000.json','["念昔瓊林賜宴歸，綵衣綠綬正相宜。", "將雛雖復慰心喜，負米翻成觸目悲。", "殿角花猶紅勝火，樽前髪自白如絲。", "桂林衰朽何須恨，幸有新枝續舊枝。"]'),
('9fac047b-0b17-4fab-a3fb-1be6b8d9372e','早朝書事','司馬光','宋','宋诗','song-poetry','','[]','太白明如李，東方三丈高。',48,'全唐诗/poet.song.29000.json','["太白明如李，東方三丈高。", "晨光孤照闕，霧氣濕侵袍。", "槐柳經霜慘，驊騮得路豪。", "素餐無小補，俛仰愧金鼇。"]'),
('07d17d53-502a-4935-becd-8263498d8dcc','登長安見山樓','司馬光','宋','宋诗','song-poetry','','[]','到官今十日，纔得一朝閑。',24,'全唐诗/poet.song.29000.json','["到官今十日，纔得一朝閑。", "歲晚愁雲合，登樓不見山。"]'),
('a0eb3df9-9eeb-46ba-9d51-7bac24c7e48a','長安送李堯夫同年','司馬光','宋','宋诗','song-poetry','','[]','昔歲瓊林花氣曛，今朝長樂柳梢春。',64,'全唐诗/poet.song.29000.json','["昔歲瓊林花氣曛，今朝長樂柳梢春。", "事隨流水滔滔度，鬢結繁霜戢戢新。", "世路飽諳都是夢，人生可貴莫如身。", "會須築室臨清洛，相與攜筇戴葛巾。"]'),
('d1909f26-5479-4a92-a5d8-201187c4d4cf','五哀詩 故殿中侍御史滎陽鄭公','王禹偁','宋','宋诗','song-poetry','','[]','柱史有名跡，清才自天縱。',216,'全唐诗/poet.song.3000.json','["柱史有名跡，清才自天縱。", "構思慶雲合，落筆醴泉湧。", "歌詩與文賦，錚錚人口諷。", "揚袂入澤宮，鵠心一箭中。", "恃才善戲謔，負氣好侮弄。", "大志有誰知，細行乖自訟。", "小諫事世宗，惕惕佩光寵。", "太祖方歷試，握兵權已重。", "上書范魯公，先見不能用。", "曆數不在周，謳謠卒歸宋。", "汗漫失屠龍，接輿遂歌鳳。", "行荷伯倫鍤，高卧畢卓甕。", "神德不爲嫌，優待臺諫俸。", "晚求萬泉令，吏隠官資冗。", "一旦隨朝露，識者彌哀痛。", "無子嗣家聲，身世若一夢。", "文編多散失，人口時傳誦。", "空持一器酒，何處澆孤冢。"]'),
('35f33db7-c4c6-4f03-8ed5-06882daf036a','五哀詩 故國子博士郭公','王禹偁','宋','宋诗','song-poetry','','[]','汾陽飽經術，賦性甚坦率。',240,'全唐诗/poet.song.3000.json','["汾陽飽經術，賦性甚坦率。", "在昔舉神童，廣場推傑出。", "尚書誦在口，何論落自筆。", "總角取科名，弱冠紆纓紱。", "早佐湘陰幕，漢鼎入周室。", "失志罷屠龍，佯狂遂捫蝨。", "周行亦黽勉，吏隠多放逸。", "滑稽東方朔，圖畫王摩詰。", "古文識科斗，奧學辨萍實。", "字窮蒼頡本，篆證陽冰失。", "王績醉爲鄉，伯倫居無匹。", "俸錢乏一囊，宦路從三黜。", "朱衣多不著，白髮仍慵櫛。", "漸老覊旅年，方見昇平日。", "忽以伎術召，此意殊鬰鬰。", "放口忤無鬚，何門求造膝。", "遁逃終見捕，譴逐道中卒。", "遺孤落閭閻，荒冢鳴蟋蟀。", "手澤漸難求，誰家耀箱帙。", "投弔焚此詩，九原應有物。"]'),
('ae10db23-dd6a-4c54-9b1a-1ab071a95a27','五哀詩 故太子中允知洛陽縣潁公','王禹偁','宋','宋诗','song-poetry','','[]','洛陽富文彩，峭拔四子流。',192,'全唐诗/poet.song.3000.json','["洛陽富文彩，峭拔四子流。", "提筆入廣場，辭氣干斗牛。", "擢第在芸閣，言事觸冕旒。", "左降宰百里，道勝心無憂。", "才高恥吏役，放蕩不檢脩。", "起應賢良科，下筆不見休。", "青宮尚淹恤，赤縣且優游。", "輕財糞土賤，高義雲天浮。", "懸磬任貧窶，盈樽長獻酬。", "知己彼何人，鳳閣與鼇頭。", "推挽終不起，壯志將焉收。", "晚年圯橋役，關市良可羞。", "忽然爲異物，寒草封一丘。", "孀嫠應凍餓，交友誰尋求。", "遺孫方稚齒，爽秀已遒遒。", "皇天若有憑，必使光貽謀。"]'),
('cd42fda2-d1f9-45bb-ac0a-845485958bc4','太一宮祭迴馬上偶作寄韓德純道士','王禹偁','宋','宋诗','song-poetry','','[]','去年暨今夏，承詔祠天神。',192,'全唐诗/poet.song.3000.json','["去年暨今夏，承詔祠天神。", "昔當摇落時，宮葉紅紛紛。", "此來芳春暮，宮草青蓁蓁。", "三日奉齋潔，百骸祛垢氛。", "御署致恭虔，天香何絪縕。", "監祀黄門郎，攝官紫微臣。", "松枝拂劍佩，樹影光搢紳。", "燈燭晃白晝，香花藹清芬。", "金殿禮神仙，瑶壇醮星辰。", "至誠不爲己，玄鑒當福仁。", "質明祀事畢，復命趨紫宸。", "揚鞭入村落，緩轡聊逡巡。", "麥田少時雨，蠶月無閒人。", "自慚懷祿仕，蠹此力穡民。", "又拋三洞趣，來入九衢塵。", "不如韓道士，長此養天真。"]'),
('c39c410d-53f1-4fae-855a-150e49672e00','送筇杖與劉湛然道士','王禹偁','宋','宋诗','song-poetry','','[]','有客遺竹杖，九節共一枝。',216,'全唐诗/poet.song.3000.json','["有客遺竹杖，九節共一枝。", "鶴脰老更長，龍骨乾且奇。", "我問何所來，來從西南夷。", "因思漢武帝，求此民力疲。", "明明聖天子，德教加四維。", "蠻貊盡臣妾，縣道皆覊縻。", "僰僮與笮馬，入貢何纍纍。", "此竹日已賤，輕視如蒿藜。", "我年三十七，血氣未全衰。", "况在紫微垣，動爲簪笏覊。", "倚壁如長物，歲月無所施。", "寸心空愛惜，惜此來天涯。", "忽承明主詔，來謁太一祠。", "再見劉先生，氣貌清且羸。", "持此以爲贈，所謂得其宜。", "少助橘童力，好引花鹿隨。", "步月莫離手，看山聊搘頤。", "微物懶致書，故作筇竹詩。"]'),
('f82e6c67-68cd-4022-aee0-d292e1526e9d','對雪','王禹偁','宋','宋诗','song-poetry','','[]','帝鄉歲云暮，衡門晝長閉。',288,'全唐诗/poet.song.3000.json','["帝鄉歲云暮，衡門晝長閉。", "五日免常參，三館無公事。", "讀書夜卧遲，多成日高睡。", "睡起毛骨寒，窗牖瓊花墜。", "披衣出戶看，飄飄滿天地。", "豈敢患貧居，聊將賀豐歲。", "月俸雖無餘，晨炊且相繼。", "薪芻未闕供，酒肴亦能備。", "數杯奉親老，一酌均兄弟。", "妻子不饑寒，相聚歌時瑞。", "因思河朔民，輸稅供邊鄙。", "車重數十斛，路遥幾百里。", "羸蹄凍不行，死轍冰難曳。", "夜來何處宿，闃寂荒陂裏。", "又思邊塞兵，荷戈禦胡騎。", "城上卓旌旗，樓中望烽燧。", "弓勁添氣力，甲寒侵骨髓。", "今日何處行，牢落窮沙際。", "自念亦何人，偷安得如是。", "深爲蒼生蠹，仍尸諫官位。", "謇諤無一言，豈得爲直士。", "褒貶無一詞，豈得爲良史。", "不耕一畝田，不持一隻矢。", "多慚富人術，且乏安邊議。"]'),
('27b07236-c77e-4032-9f14-fa98bc98d46a','金吾','王禹偁','宋','宋诗','song-poetry','','[]','金吾河朔人，事郡在賤列。',264,'全唐诗/poet.song.3000.json','["金吾河朔人，事郡在賤列。", "攀附周世宗，龍飛起魚鱉。", "委質向聖朝，積功取旄鉞。", "所在肆貪殘，乘時恃勳伐。", "皇家平金陵，九江聚遺孽。", "彌年城乃陷，不使鷄犬活。", "老小數千人，一怒盡流血。", "三惑無不具，五福何嘗缺。", "晚年得執金，富貴居朝闕。", "娛樂有清商，康强無白髮。", "享年六十九，固不爲夭折。", "考終北牖下，手足全啟發。", "子孫十數人，解珮就衰絰。", "贈典頗優崇，視朝爲之輟。", "哀榮既如是，報應何足說。", "責簿李廣死，賜劍武安滅。", "僥倖過古人，况無大功烈。", "福善與禍淫，斯言僅虛設。", "吁嗟爲儒者，寒餓守名節。", "五十朝大夫，龍鍾頭似雪。", "無故不殺羊，禮文安可越。", "何况賓祀間，貧苦無羊殺。"]'),
('9da0840c-7dde-4b33-a582-60a5c0112bce','送戚維戚綸之閬州亳州','王禹偁','宋','宋诗','song-poetry','','[]','古人貴道德，豈以祿位拘。',288,'全唐诗/poet.song.3000.json','["古人貴道德，豈以祿位拘。", "有道不在位，顔回舜之徒。", "無德殃且至，商受爲獨夫。", "以此固名節，富貴安足圖。", "睢陽戚先生，今世古之儒。", "終身不求仕，沒齒唯誦書。", "孝愛睦姻族，淳謹化里閭。", "文翁變蜀土，尚以德位俱。", "仲淹居汾水，專用素教敷。", "青青子衿輩，櫛比曳朝裾。", "盛德苟無報，吾道將焉如。", "鯉庭生二子，驪頷委雙珠。", "樸厚有父風，學業張皇謨。", "各登進士科，齊乘使者車。", "閬中佐郡政，亳社司搉酤。", "佐郡古半刺，可使惸嫠蘇。", "搉酤今權道，亦助軍國須。", "牽車驥雖屈，補履刃有餘。", "誰謂佐著作，在上積薪芻。", "誰謂光祿勳，其中混瓊琚。", "我亦何爲者，先上青雲衢。", "伐木空求友，拔茅未連茹。", "終待奮直筆，會當伏青蒲。", "請慎名與器，願分賢與愚。"]'),
('97e4ae89-2a87-4d05-b4c6-48d8e7e6dc40','送陳侯之任同州','王禹偁','宋','宋诗','song-poetry','','[]','丈夫貴自奮，何必恃貽謀。',156,'全唐诗/poet.song.3000.json','["丈夫貴自奮，何必恃貽謀。", "當年功不立，古人重爲憂。", "太師忠順公，沒世有餘休。", "令子一何賢，恥隨資蔭流。", "碌碌奉朝請，帝恩何以酬。", "鬰鬰不快意，上章聞冕旒。", "願爲循良吏，未甘恩澤侯。", "天子嘉乃誠，錫命蒞同州。", "同州古三輔，北望雄且優。", "詔條得以布，民瘼得以求。", "勿謂綺紈子，當有襦袴謳。", "詩云無忝爾，禮云必爲裘。", "去去繼旄節，免作將門羞。"]'),
('8a07a99b-7aea-4a09-808b-70716bf4a4a5','送朱九齡','王禹偁','宋','宋诗','song-poetry','','[]','吏隠不求貴，親老不擇祿。',292,'全唐诗/poet.song.3000.json','["吏隠不求貴，親老不擇祿。", "之子有俊才，弱冠中正鵠。", "弗墜先人業，何慚有道穀。", "一命佐碭山，枳棘聊容足。", "再命宰嘉興，絲桐幾易俗。", "率身甘菜茹，養母求粱肉。", "承顔苟不虧，折腰未爲辱。", "解印無餘貲，舟中只琴筑。", "十口寄淮泗，一身來輦轂。", "又說東南行，秋風江水淥。", "鄱陽古名郡，赤金流山谷。", "每歲鼓錢刀，從來設官局。", "還得便高堂，無辭縻逸躅。", "颺帆江湖思，木脫天地肅。", "楓葉紫斕斒，蓼花紅{罒/彔}𦌊。", "津吏曉來迎，溪僧夜留宿。", "至止事方簡，優游從所欲。", "江城豐稻粱，水市多魚蔌。", "三載奉甘飴，百錢飽家族。", "自有綵衣華，勿歎藍袍綠。", "行年未三十，氣壯顔如玉。", "行義日以聞，焉能長碌碌。", "終列侍臣班，耀我同年錄。", "且賦白華詩，唱作離筵曲。"]'),
('0dddabcc-a515-4690-9571-9fd0f20a4f03','暴富送孫何入史館','王禹偁','宋','宋诗','song-poetry','','[]','孟郊常貧苦，忽吟不貧句。',96,'全唐诗/poet.song.3000.json','["孟郊常貧苦，忽吟不貧句。", "爲喜玉川子，書船歸洛浦。", "迺知君子心，所樂在稽古。", "漢公得高科，不足唯墳素。", "二年佐棠陰，眼黑怕文簿。", "躍身入三館，爛目閱四庫。", "孟貧昔不貧，孫貧今暴富。", "暴富亦須防，文高被人妬。"]'),
('18e3b863-7e9a-4d74-a5b0-bd0d558e4e2c','贈劉仲堪','王禹偁','宋','宋诗','song-poetry','','[]','劉生頗少秀，爲學識根柢。',132,'全唐诗/poet.song.3000.json','["劉生頗少秀，爲學識根柢。", "丘軻有堂奧，試脚到階砌。", "楊墨恣荒榛，揮手欲芟薙。", "携文訪謫居，趣向非權勢。", "對挹雛鳳下，交言孤鶴唳。", "在璞認良玉，行當爲國器。", "彼茁見靈芽，佇可供王祭。", "豈止隨衆人，區區一枝桂。", "宜哉孫漢公，妻之以女弟。", "吾家兄之子，笄年未伉儷。", "恨不早相逢，取子爲佳壻。"]'),
('8940edca-493e-4f0c-9acd-fb8d08bec28f','送馮尊師','王禹偁','宋','宋诗','song-poetry','','[]','前日訪潘閬，下馬入窮巷。',192,'全唐诗/poet.song.3000.json','["前日訪潘閬，下馬入窮巷。", "忽見雙笋石，卧向青苔上。", "云是馮尊師，秋來留在茲。", "今說東南行，問我堅乞詩。", "又見宋閣老，亦言師甚好。", "欲去天台山，即別長安道。", "臺閣有羣英，贈別瑰與瓊。", "琤然滿懷袖，此事殊爲榮。", "安用徵吾句，吾道方齟齬。", "老爲八品官，有山未能去。", "束髮號男兒，出處貴得宜。", "出則學臯夔，獨立稱帝師。", "處則同喬松，决起如冥鴻。", "誰能似蚯蚓，蟠屈泥土中。", "師行甚可羨，雲鶴無覊絆。", "爲我持此詩，題于桐栢觀。"]'),
('5f260934-9243-47ba-ac49-6be68456945e','八絕詩 庶子泉','王禹偁','宋','宋诗','song-poetry','','[]','物形固天造，物景不自勝。',155,'全唐诗/poet.song.3000.json','["物形固天造，物景不自勝。", "泉乎未遇人，石罅徒流迸。", "宮相政多暇，行樂躡巖磴。", "發蒙漲爲溪，幽致茲焉盛。", "唐賢大曆後，峭壁刻名姓。", "我來一何暮，今秋始乘興。", "山勢環有缺，山門壺引柄。", "乍挹清泚姿，頗愜幽閑性。", "味將春茗宜，光與曉嵐暝。", "架竹落僧厨，遠聲入清磬。", "何當宿禪室，欹枕終夜聽。", "飲多病骨換，照久塵逈。", "銷盡謫居愁，無心治歸艇。"]'),
('004958b0-138a-4937-9582-3ecdb072f095','八絕詩 白龍泉','王禹偁','宋','宋诗','song-poetry','','[]','崖石何鑿鑿，渤潏湧山脚。',168,'全唐诗/poet.song.3000.json','["崖石何鑿鑿，渤潏湧山脚。", "含虛光可鑒，倒影壁如削。", "瀰漫到前溪，支脈通遠壑。", "白龍乃神物，胡此戀一勺。", "勢能爲霖雨，力可興雷雹。", "上天未有命，茲焉縮頭角。", "應防困螻蟻，泥蟠詎敢躍。", "葅醢曾是憂，豢養殊非樂。", "亦如君子道，出處貴先覺。", "吾生苦遷謫，未免郡政縛。", "偶來泉畔坐，感興題秋籜。", "斗藪纓上塵，試就清漣濯。", "聊將一掬水，洗我面慚怍。", "日暮不忍歸，風埃滿城郭。"]'),
('217d8fba-5b6a-44c0-b61e-9eea99225ebd','八絕詩 明月溪','王禹偁','宋','宋诗','song-poetry','','[]','漲溪者爲誰，人骨皆已朽。',48,'全唐诗/poet.song.3000.json','["漲溪者爲誰，人骨皆已朽。", "我來尋故跡，溪荒亂泉吼。", "惜哉幽勝事，盡落唐賢手。", "唯餘舊時月，團團照山口。"]'),
('eaa9a751-4e5b-4770-ae13-d4bdf95dbd43','八絕詩 清風亭','王禹偁','宋','宋诗','song-poetry','','[]','茲亭廢已久，厥趾猶在哉。',48,'全唐诗/poet.song.3000.json','["茲亭廢已久，厥趾猶在哉。", "清風爲我起，疑有精靈來。", "神交念宮相，臨砌傾一杯。", "迴頭問黄菊，寂寞與誰開。"]'),
('763be229-e8f1-45cb-ad4c-dd60068814bc','八絕詩 望日臺','王禹偁','宋','宋诗','song-poetry','','[]','荒臺隠層碧，雲磴踰百尺。',72,'全唐诗/poet.song.3000.json','["荒臺隠層碧，雲磴踰百尺。", "攀蘿試一上，依然有遺跡。", "掌舒舊砌平，屏卓諸峰直。", "憑高聊寫望，孤懷念鄉國。", "長安不可見，但對金烏赤。", "傾盡葵藿心，庶免浮雲隔。"]'),
('5bb87b29-36d1-4c38-80f7-9b20eb1aa0d6','八絕詩 歸雲洞','王禹偁','宋','宋诗','song-poetry','','[]','碧洞何眈眈，呀然倚山根。',84,'全唐诗/poet.song.3000.json','["碧洞何眈眈，呀然倚山根。", "朝雲出如嘔，暮雲歸如吞。", "大塊氣不死，茲爲玄牝門。", "怪石擁左右，勢若貙虎蹲。", "旁行數十步，漆黑不可捫。", "安得鞭燭龍，爲吾前馳奔。", "尋盡神仙窟，一一知其源。"]'),
('beb443d9-acb0-41c4-9dd4-b02768cba03f','八絕詩 陽冰篆','王禹偁','宋','宋诗','song-poetry','','[]','泠泠庶子泉，落落陽冰筆。',84,'全唐诗/poet.song.3000.json','["泠泠庶子泉，落落陽冰筆。", "雲氣勢崩垂，龍蛇互蟠屈。", "嶧山既劘滅，石鼓又缺失。", "唯茲數十字，遒勁倚雲窟。", "模印徧華夷，流傳耀緗帙。", "書誠一藝爾，小道詎可忽。", "乃知出人事，千古名不沒。"]'),
('6a60343f-e91f-4582-9731-a1a91689fa6e','八絕詩 垂藤蓋','王禹偁','宋','宋诗','song-poetry','','[]','古藤何樛蟠，低蔭庶子泉。',120,'全唐诗/poet.song.3000.json','["古藤何樛蟠，低蔭庶子泉。", "童童若青蓋，挂在絕壁前。", "月穿波影碎，露滴岸聲圓。", "曉籠使君醉，夜覆溪僧禪。", "昔之好事者，爲作出偶然。", "人亡藤已朽，猶得聲名傳。", "我欲移青松，植向泉眼邊。", "既圖歲月久，復取節操全。", "所爲亦一時，所期或千年。", "庶吾不朽名，長與偃蓋懸。"]'),
('4f2d5d34-9a8d-4fab-bb0b-d9fbb8f542f8','東門送郎吏行寄承旨宋侍郎','王禹偁','宋','宋诗','song-poetry','','[]','西門送僕射，鞍馬照路光。',276,'全唐诗/poet.song.3000.json','["西門送僕射，鞍馬照路光。", "南門送貳卿，冠蓋遥相望。", "東門送郎吏，艤舟隋堤傍。", "郎吏誠隔品，同直白玉堂。", "丈人况知己，振拔在舉場。", "憐才惜我去，深勸離別觴。", "醉中不記事，烟水空茫茫。", "醒來聞鳴櫓，嘔軋摇斜陽。", "猶疑在禁中，殘漏寒丁當。", "迴望銀臺門，五雲遮帝鄉。", "聚散本如此，升沉庸何傷。", "丈人名位峻，只欠登巖廊。", "平居倦朝請，高論思退藏。", "圃田有別業，古木羅修篁。", "艸亭寒蕭蕭，池波碧泱泱。", "嘗云拂袖去，可以傲羲皇。", "丈人果能爾，識度非尋常。", "安車比疏廣，辟穀如張良。", "再拜願丈人，壽考仍康强。", "自念山野士，不解隨圓方。", "宦途多齟齬，身計頗悲凉。", "行將解簪笏，歸去事農桑。", "幸容操杖履，洒掃近丘牆。"]'),
('042e368d-3ae6-4e04-b3e2-6aae2726e5a7','送林介','王禹偁','宋','宋诗','song-poetry','','[]','八年困名場，萬里有慈親。',84,'全唐诗/poet.song.3000.json','["八年困名場，萬里有慈親。", "吟變閩越聲，衣有京洛塵。", "况復久相依，知子文行淳。", "不能致一第，虛作金鑾臣。", "昔予貶商洛，相送遠涉溱。", "今予謫滁上，語別清淮濱。", "途窮與道喪，詎免同沾巾。"]'),
('2b1cb921-9797-4c99-a98c-1b2058111ce7','北樓感事','王禹偁','宋','宋诗','song-poetry','','[]','北樓出林杪，登覽開病姿。',288,'全唐诗/poet.song.3000.json','["北樓出林杪，登覽開病姿。", "旁带滁州城，雉堞何逶迤。", "下入刺史宅，却臨統軍池。", "伊予翰林客，失職方在茲。", "兩衙簿領外，盡日吟望時。", "晚窗度急雨，夏木交繁枝。", "淮南氣候殊，經秋囀黄鸝。", "簷前有山果，採掇亦甘滋。", "樽中有官醖，傾酌任醇醨。", "忘機得真趣，懷古生遠思。", "念昔李太尉，落落邦家基。", "下筆到西漢，料兵如六奇。", "謫官來此郡，鬰鬰持一麾。", "嘗作懷嵩樓，記文悲盛衰。", "甚得進退理，深明禍福機。", "未幾再入用，斯言忽如遺。", "君恩匪膠柱，天殃若影隨。", "六月萬里行，炎荒竟不歸。", "功成又名遂，不退將安之。", "姑以人事較，勿憑天命推。", "矧予草澤士，被褐復羹藜。", "謬因弄文翰，八載侍丹墀。", "三入承明盧，古人期並馳。", "玉堂百日罷，所累非文詞。"]'),
('4629c1cc-a7d7-4863-838d-456e5f296758','送劉職方','王禹偁','宋','宋诗','song-poetry','','[]','罷直出玉堂，詔授尚書郎。',252,'全唐诗/poet.song.3000.json','["罷直出玉堂，詔授尚書郎。", "朝僉假郡印，承乏來永陽。", "喜開黄紙書，云替劉職方。", "職方老狀頭，疇昔名擅場。", "宦游三十載，寸進鴛鷺行。", "未出六品班，鬚鬢已垂霜。", "顧予新進生，遭時恣翱翔。", "綸闈與內署，掌誥侍玉皇。", "夜召赴浴殿，春遊醉柏梁。", "晚出銀臺門，朝服含天香。", "爲儒能到此，自道摩穹蒼。", "今年四十二，典郡清淮旁。", "卧錦郎位正，腰金服色光。", "見君深自愧，撫己庸何傷。", "古人重交代，子孫不相忘。", "西掖替左司，劉白形詩章。", "况我忝翰林，而君列文昌。", "待將官與氏，山寺題修篁。", "共保不朽名，他年比甘棠。", "昇沉何足道，聚散安有常。", "且當唱此詩，爲君送離觴。"]'),
('a307b197-c8ba-4e53-96a5-bead6d04107e','感興','王禹偁','宋','宋诗','song-poetry','','[]','吾嘗入深山，谿谷寒且沍。',96,'全唐诗/poet.song.3000.json','["吾嘗入深山，谿谷寒且沍。", "杉檜頗凌雲，歲月自朽蠹。", "般輸目不見，何由用斤斧。", "東山大夫松，中岳金雞樹。", "秦政本獨夫，則天乃淫嫗。", "名號被常材，所幸因一顧。", "爲木豈有命，偶然生要路。", "誰取澗底松，立作明堂柱。"]'),
('a66e7582-6cff-4b40-9a70-80c9a4de5ab7','老態','王禹偁','宋','宋诗','song-poetry','','[]','白髮不相饒，秋來生鬢邊。',48,'全唐诗/poet.song.3000.json','["白髮不相饒，秋來生鬢邊。", "黑花最相親，終日在眼前。", "老態固具矣，宦情信悠然。", "唯當共心約，收拾早歸田。"]'),
('fdb36bbc-7e9d-4bc6-96cf-696b5a072b10','官醖','王禹偁','宋','宋诗','song-poetry','','[]','爲郡得官醖，月給盈三斛。',168,'全唐诗/poet.song.3000.json','["爲郡得官醖，月給盈三斛。", "地僻少使車，時清罕留獄。", "老大復遷謫，吾懷頗幽獨。", "嬋娟樓上月，爛漫池邊菊。", "東院與西亭，翛翛風弄竹。", "對此不開樽，騷人應慟哭。", "獨酌入醉鄉，陶然瞑雙目。", "醒來成浩歎，胡爲事口腹。", "彝酒書垂誡，羣飲聖所戮。", "漢文亦禁酒，患在糜人穀。", "自從孝武來，用度常不足。", "榷酤奪人利，取錢入官屋。", "古今事相倍，帝皇道難復。", "吾無奈爾何，更盡杯中淥。"]'),
('8a97678f-096b-4af9-ac3c-dbc4237d3db5','射弩','王禹偁','宋','宋诗','song-poetry','','[]','蹷張見舊史，强弩亦古官。',264,'全唐诗/poet.song.3000.json','["蹷張見舊史，强弩亦古官。", "如何壯夫事，今作儒者歡。", "罰郡在僻左，時清政多閑。", "戎裝命賓侶，作此開愁顔。", "吳弩號健捷，僕夫爲吾彎。", "正侯廢已久，畫紙爲雕盤。", "日暈生幾重，挂壁何團團。", "記籌鼓聲急，中的酒量寬。", "誠非軍旅事，亦有堵牆觀。", "安得十萬枝，長驅過桑乾。", "射彼老上庭，奪取燕脂山。", "不見一匈奴，直抵瀚海還。", "北方盡納款，獻壽天可汗。", "吾徒久不武，干祿爲饑寒。", "所得纔升斗，齷齪在朝班。", "不如執戈士，意氣登韓壇。", "笑擁白玉妓，醉馳黄金鞍。", "郎官一生俸，供爾數月間。", "儒將古所重，料兵如轉丸。", "誰知戴章甫，終老弄辛酸。", "偶因兒戲爲，痛念邊事艱。", "臨風自慷慨，素髮衝儒冠。"]'),
('d4b4baa6-54b3-4e2f-9a86-d22db0d48c52','黑裘','王禹偁','宋','宋诗','song-poetry','','[]','野蠶自成繭，繰絡爲山紬。',156,'全唐诗/poet.song.3000.json','["野蠶自成繭，繰絡爲山紬。", "此物産何許，萊夷負海州。", "一端重數斤，裁染爲吾裘。", "守黑异華楚，示儉非輕柔。", "燻香則無取，風雪曾何憂。", "朝可奉冠带，夜以爲衾裯。", "晏嬰三十年，庶幾跡相侔。", "季子苦貂弊，吾服仍爲優。", "不恥狐貉者，亦當師仲由。", "况我屢遷謫，行將耕故丘。", "映髮垂鷺頂，植杖昂鳩頭。", "袖寬可以舞，老農即爲儔。", "紫綬挂君門，任爾爭封侯。"]'),
('dfc80323-2b04-4188-9431-73089ac2a472','聞鴞','王禹偁','宋','宋诗','song-poetry','','[]','元精育萬彙，羽族何茫茫。',288,'全唐诗/poet.song.3000.json','["元精育萬彙，羽族何茫茫。", "爲怪有鴟鴞，爲瑞稱鳳皇。", "鳳皇不時出，未識五色章。", "吾生在鄒魯，風土殊遠方。", "鳴鳩隨乳燕，日夕巢我梁。", "翩翾雜鳥雀，穿屋率爲常。", "又從筮仕來，五年居帝鄉。", "更直入承明，侍宴趨未央。", "上林聞鶑囀，巧舌如笙簧。", "鴟鴞徒知名，聞見實未嘗。", "頃年謫商山，聽之已悲凉。", "今茲出內庭，罰郡來永陽。", "誰知爾鸋鴂，營巢在城牆。", "年加睡漸少，秋盡漏且長。", "鳴嘯殊不已，歷歷含微霜。", "孺人泣我右，稚子啼我傍。", "吾心非達士，詎免亦倀倀。", "人生縱百歲，忽若石火光。", "其間有窮通，幽昧難自量。", "我愛臯與夔，峨冠虞舜堂。", "簫韶聞九成，丹穴來鏘鏘。", "又愛閎與散，陳力遇文王。", "鸑鷟聽岐山，多士周道昌。", "嗟嗟漢賈誼，年少謫南荒。"]'),
('7ad81fbb-9371-48c3-854c-d22cbd0494f5','甘菊冷淘','王禹偁','宋','宋诗','song-poetry','','[]','經年厭粱肉，頗覺道氣渾。',216,'全唐诗/poet.song.3000.json','["經年厭粱肉，頗覺道氣渾。", "孟春奉齋戒，敕厨唯素飱。", "淮南地甚暖，甘菊生籬根。", "長芽觸土膏，小葉弄晴暾。", "采采忽盈把，洗去朝露痕。", "俸麵新且細，溲攝如玉墩。", "隨刀落銀鏤，煮投寒泉盆。", "雜此青青色，芳草敵蘭蓀。", "一舉無孑遺，空媿越盌存。", "解衣露其腹，稚子爲我捫。", "飽慚廣文鄭，饑謝魯山元。", "况吾草澤士，藜藿供朝昏。", "謬因事筆硯，名通金馬門。", "官供政事食，久直紫微垣。", "誰言謫滁上，吾族飽且溫。", "既無甘旨慶，焉用品味繁。", "子美重槐葉，直欲獻至尊。", "起予有遺韵，甫也可與言。"]'),
('1e84e4d0-49d4-4406-a117-8af7380fc234','霪雨中偶書所見','王禹偁','宋','宋诗','song-poetry','','[]','丙申二月七，是夕月離畢。',180,'全唐诗/poet.song.3000.json','["丙申二月七，是夕月離畢。", "春雲忽霮䨴，春雨復蒙密。", "綿綿殆三旬，不見天上日。", "謫官在淮甸，幽抱常鬰鬰。", "豈無瑯邪山，泥濘不可出。", "空庭唯蚯蚓，得勢互蟠屈。", "乘茲積陰氣，小穴恣出沒。", "山禽忽飛下，長嘴啄深窟。", "倒曳方力爭，强吞遽全失。", "食土與巢林，上下非儔匹。", "胡然羅此酷，不能保微質。", "嗟嗟彼羣小，傾奪事匪一。", "儀鳳去九夷，神龍入泉室。", "如何役吾眼，瞻視此小物。", "歸來因浩歎，自悔成詩筆。"]'),
('71c63058-5d2d-4d2d-9344-a25509bd45d9','唱山歌','王禹偁','宋','宋诗','song-poetry','','[]','滁民带楚俗，下俚同巴音。',96,'全唐诗/poet.song.3000.json','["滁民带楚俗，下俚同巴音。", "歲稔又時安，春來恣歌吟。", "接臂轉若環，聚首叢如林。", "男女互相調，其詞非奔淫。", "修教不易俗，吾亦弗之禁。", "夜闌尚未闋，其樂何愔愔。", "用此散楚兵，子房謀計深。", "乃知國家事，成敗因人心。"]'),
('06d335da-6f76-48aa-81ec-fae45bfa77c7','酬楊遂','王禹偁','宋','宋诗','song-poetry','','[]','楊君江左士，文律何飄飄。',204,'全唐诗/poet.song.3000.json','["楊君江左士，文律何飄飄。", "人言未冠時，作賦凌洞簫。", "甲科中南國，通籍趨東朝。", "轗軻位不進，陶潜還折腰。", "宰邑向蜀道，龿蒲忽興妖。", "官小力不支，奔竄避槍刀。", "朝廷責守土，黜入縣佐僚。", "昨朝寫孤憤，遺我有客謠。", "伊予亦左遷，諷之心無憀。", "人生一世間，否泰安可逃。", "姑問道何如，未必論卑高。", "自古富貴者，撩亂如藜蒿。", "德業苟無取，未死名已消。", "豈期顔子淵，不朽在一瓢。", "推此任窮達，其樂方陶陶。", "達則爲鵾鵬，窮則爲鷦鷯。", "垂天與巢林，識分皆逍遥。"]'),
('5e97a1df-8b02-4d48-97f5-3a1d74c307d6','和楊遂賀雨','王禹偁','宋','宋诗','song-poetry','','[]','我罷內庭職，出臨永陽民。',288,'全唐诗/poet.song.3000.json','["我罷內庭職，出臨永陽民。", "永陽民雖庶，未免多饑貧。", "富之既無術，齪齪爲謹身。", "可堪今夏旱，如燎復如焚。", "厥田本塗泥，坐見生埃氛。", "稚老無所訴，嗷嗷望穹旻。", "食祿憂人憂，蚤夜眉不伸。", "促决獄中囚，徧禱境內神。", "楚辭有山鬼，廟貌羅水濱。", "胡法有浮圖，寺宇連城闉。", "齋莊命寮寀，供給抽俸緡。", "鼓笛迎湫水，香花照金輪。", "誠知非典故，且慰旱熯人。", "偶與天雨會，霶霶四郊勻。", "插秧復修堰，野叟何欣欣。", "可辦官賦調，亦免農艱辛。", "燮調頼時相，感應由聖君。", "于吾復何有，敢望歌頌云。", "清流楊水部，德與我爲鄰。", "仇香官位屈，何遜詩格新。", "見投賀雨篇，言自人口聞。", "夫君蓋私我，過實豈相親。", "爲霖非我事，職業唯詞臣。", "若有民謠起，當歌帝澤春。"]'),
('77428d2c-8287-40c9-a82f-2e99a1f63017','揚州寒食贈屯田張員外成均吳博士同年殿省柳丞','王禹偁','宋','宋诗','song-poetry','','[]','前年寒食節，待詔直內庭。',288,'全唐诗/poet.song.3000.json','["前年寒食節，待詔直內庭。", "休假百官出，獨掩深嚴扃。", "近侍不敢醉，賜酒空滿瓶。", "閑就通中枕，時聞索上鈴。", "思入無何鄉，兀然欲忘形。", "去年寒食日，滁上忝專城。", "山歌喧里巷，春物媚池亭。", "永陽溪水淥，琅邪山色青。", "謫宦自消遣，不敢誇獨醒。", "往往取官醖，時時對花傾。", "醉來念身世，翻使淚縱橫。", "今年蒞淮海，時節又清明。", "堆案有留事，聽歌無歡聲。", "胥徒費簿領，使客煩送迎。", "狴牢未空歇，堰埭勞修營。", "衰病力不支，懶慢性已成。", "虛花滿雙目，素髮添幾莖。", "酒肴略無味，妓樂固難聽。", "誰言寒食下，終日取茶烹。", "屯田布素交，屈此關市征。", "昔年同應舉，典衣飛巨觥。", "博士東觀客，求官得步兵。", "况且丹陛前，同爲出谷鶑。", "殿丞尹我邑，桑梓復弟兄。"]'),
('23cc2985-dff1-4550-bdbf-cef15a09a4aa','揚州池亭即事','王禹偁','宋','宋诗','song-poetry','','[]','冥心閱羣動，亦各趨所安。',216,'全唐诗/poet.song.3000.json','["冥心閱羣動，亦各趨所安。", "胡爲名利人，戚戚常鮮歡。", "吾生四十四，結佩呼郎官。", "掌言入綸閣，待詔直金鑾。", "匪謂得祿少，所嗟行道難。", "前年謫滁上，憂畏雙鬢殘。", "頼有琅邪溪，時濯塵纓冠。", "朝僉徙淮海，任重力易殫。", "君恩詎可報，感激涕汍瀾。", "民瘼不能治，惻隠情悲酸。", "況復多病身，名宦心已闌。", "歸田未果决，懷祿尚盤桓。", "公退何所適，池亭一凭欄。", "旭日媚春卉，微風生鳴湍。", "呵僮勿挾彈，留客不持竿。", "用冀魚鳥馴，熙熙肆遊觀。", "神仙未可學，吏隠聊自寬。", "孤吟刻幽石，此義非考槃。"]'),
('a76ab562-3de8-485d-b279-070832476137','一品孫鄭昱','王禹偁','宋','宋诗','song-poetry','','[]','卜葬得假告，南出安上門。',288,'全唐诗/poet.song.3000.json','["卜葬得假告，南出安上門。", "鞭馬六十里，暮投中書村。", "村翁館我宿，茅屋欲黄昏。", "有客忽投刺，自稱一品孫。", "氣貌不凡俗，因爲開酒樽。", "坐久問家諜，其族大且繁。", "池州有清節，濫觴登洪源。", "太傅擅鴻筆，入相又出藩。", "其家本開封，改號一何尊。", "至昱始六代，布衣老丘樊。", "跨馿入府縣，驅犢耕郊原。", "家廟固已毀，國史空具存。", "盛德百世著，功必格乾坤。", "高太已不祀，羨絪何可論。", "况復起章句，乘時寵便蕃。", "子孫雖替陵，尚得守田園。", "我愛三代時，法度有深根。", "卿大夫稱家，世世奉蘋蘩。", "四民有定分，宦路無馳奔。", "自從雜伯道，傾奪日喧喧。", "脫耒秉金鉞，吮筆乘朱軒。", "朝榮又暮辱，容易如掌翻。", "古道不可復，頹波益以渾。", "何况度木者，倒置輪與轅。"]'),
('2adf06ee-c587-4679-8037-4a1dac4db52d','鳳皇陂','王禹偁','宋','宋诗','song-poetry','','[]','次公治潁川，仁政被一方。',96,'全唐诗/poet.song.3000.json','["次公治潁川，仁政被一方。", "神物不藏瑞，茲焉集鳳皇。", "在昔奏簫韶，舜庭來蹌蹌。", "西伯有至化，亦見鳴岐陽。", "仲尼豈無德，已矣空悲傷。", "夫何刀筆吏，而能致殊祥。", "我來過荒陂，烟草但蒼蒼。", "緬懷漢循吏，史筆恐未詳。"]'),
('d21a7c4f-9f46-4ba4-988d-26497ea39954','月波樓詠懷','王禹偁','宋','宋诗','song-poetry','','[]','郡城無大小，雉堞皆有樓。',288,'全唐诗/poet.song.3000.json','["郡城無大小，雉堞皆有樓。", "其間著名者，不過十數州。", "吹簫事遼夐，仙跡難尋求。", "庾公在九江，締構何風流。", "謝守鎮宣城，疊嶂名有由。", "東陽敞八詠，吾聞沈隠侯。", "白雪架郢中，調高難和酬。", "黄鶴倚鄂渚，仙去事悠悠。", "贊皇謫滁上，作賦懷嵩丘。", "樓居出俗態，澤國多勝遊。", "好景不遇人，安得名存留。", "齊安古郡廢，移此清江頭。", "築城隨山勢，屈曲復環周。", "茲樓最軒豁，曠望西北陬。", "武昌地如掌，天末入雙眸。", "平遠無林木，一望同離婁。", "山形如八字，會合勢相勾。", "三國事既遠，六朝名亦休。", "近從唐末來，爭奪互仇讎。", "斯樓備矢石，此地控咽喉。", "終朝望烽燧，連歲事戈矛。", "可憐好詩景，牢落無人收。", "皇家統萬國，遠邇盡懷柔。", "三聖四十年，蕩蕩文德修。"]'),
('cd4ccbaf-19b6-4778-a70c-0c3b9297cd34','十月二十日作','王禹偁','宋','宋诗','song-poetry','','[]','重衾又重茵，蓋覆衰孏身。',108,'全唐诗/poet.song.3000.json','["重衾又重茵，蓋覆衰孏身。", "中夜忽涕泗，無復及吾親。", "須臾殘漏歇，吏報國忌辰。", "凌旦騎馬出，溪冰薄潾潾。", "路傍饑凍者，顔色頗悲辛。", "飽暖我不覺，羞見黄州民。", "昔賢終祿養，往往歸隠淪。", "誰教爲妻子，頭白走風塵。", "修身與行道，多愧古時人。"]'),
('c1cefdcf-1e41-47ce-8414-b539e3c3775a','雷','王禹偁','宋','宋诗','song-poetry','','[]','商山春夏旱，旱雷不降雨。',72,'全唐诗/poet.song.3000.json','["商山春夏旱，旱雷不降雨。", "及秋又霖霪，雷聲時一舉。", "南山復北山，渹礚若贙虎。", "君子容必變，所以敬天怒。", "無乃豐隆鬼，恣意撾雷鼓。", "此怒既非天，敬之亦奚取。"]'),
('669d0199-f466-44d8-8013-260f8bee4322','秋霖二首  其一','王禹偁','宋','宋诗','song-poetry','','[]','秋霖過百日，歲望終何如。',72,'全唐诗/poet.song.3000.json','["秋霖過百日，歲望終何如。", "嘉穀就穗生，茁茁垂青鬚。", "宿麥未入土，大田多泥塗。", "河闊不辨馬，原高恐生魚。", "時政苟云失，生民亦何辜。", "雨若是天淚，天眼應已枯。"]'),
('9ce07f38-0c64-4389-9fc0-a97d3a81e9e6','秋霖二首  其二','王禹偁','宋','宋诗','song-poetry','','[]','山雲百日雨，山水十丈波。',96,'全唐诗/poet.song.3000.json','["山雲百日雨，山水十丈波。", "田疇與道路，一夕成江河。", "巨石大於甕，吹轉如蓬窠。", "夏旱既損麥，秋潦復無禾。", "津梁盡傾壞，商販絕經過。", "斗米二百金，吾生將奈何。", "安敢比夷齊，愚聖不同科。", "應如元魯山，餓死深山阿。"]'),
('3f87aa8d-547f-4a33-b9f7-7364a43b49f2','真娘墓','王禹偁','宋','宋诗','song-poetry','','[]','女命在于色，士命在于才。',120,'全唐诗/poet.song.3000.json','["女命在于色，士命在于才。", "無色無才者，未死如塵灰。", "虎丘真娘墓，止是空土堆。", "香魂與膩骨，銷散隨黄埃。", "何事千百年，一名長在哉。", "吳越多婦人，死即藏山隈。", "無色固無名，丘冢空崔嵬。", "唯此真娘墓，客到情徘徊。", "我是好名士，爲爾傾一杯。", "我非好色者，後人無相咍。"]'),
('c7972c84-c5f1-4413-a115-58794c548463','遊虎丘','王禹偁','宋','宋诗','song-poetry','','[]','樂天曾守郡，酷愛虎丘山。',72,'全唐诗/poet.song.3000.json','["樂天曾守郡，酷愛虎丘山。", "一年十二度，五馬來松關。", "我今方吏隠，心在雲水間。", "野性羣麋鹿，忘機狎鷗鷳。", "乘興即一到，興盡復自還。", "不知使君貴，何似長官閑。"]'),
('62f898fd-6fe7-4bd0-8ada-9a036f39f1ad','吳王墓','王禹偁','宋','宋诗','song-poetry','','[]','惜哉吳王墓，秦帝嘗開破。',48,'全唐诗/poet.song.3000.json','["惜哉吳王墓，秦帝嘗開破。", "應笑埋金玉，千年賈餘禍。", "不待虎迹銷，已聞鮑車過。", "又是驪山頭，炎炎三月火。"]'),
('98abd9e6-3928-45bb-9805-abe9d301ecd5','橄欖','王禹偁','宋','宋诗','song-poetry','','[]','江東多果實，橄欖稱珍奇。',96,'全唐诗/poet.song.3000.json','["江東多果實，橄欖稱珍奇。", "北人將就酒，食之先顰眉。", "皮核苦且澀，歷口復棄遺。", "良久有迴味，始覺甘如飴。", "我今何所喻，喻彼忠臣詞。", "直道逆君耳，斥逐投天涯。", "世亂思其言，噬臍焉能追。", "寄語採詩者，無輕橄欖詩。"]'),
('df6c058b-70c1-4808-8f99-0847e756e95c','爲惡','王禹偁','宋','宋诗','song-poetry','','[]','明時巧言士，亂世佞倖郎。',36,'全唐诗/poet.song.3000.json','["明時巧言士，亂世佞倖郎。", "佞倖惟苟且，巧言頗包藏。", "爲惡雖不同，同歸於覆亡。"]'),
('286276be-3d73-4e6c-b428-919fcb5648b2','成武縣作','王禹偁','宋','宋诗','song-poetry','','[]','釋褐來成武，初官且自强。',48,'全唐诗/poet.song.3000.json','["釋褐來成武，初官且自强。", "位卑松在澗，俸薄葉經霜。", "雨菌生書案，饑禽啄印床。", "猶驚寫秋卷，槐砌落花黄。"]'),
('061f87db-d450-4288-a3e8-7300a248bb70','寄碭山主簿朱九齡','王禹偁','宋','宋诗','song-poetry','','[]','閑思蓬島會羣仙，二百同年最少年。',64,'全唐诗/poet.song.3000.json','["閑思蓬島會羣仙，二百同年最少年。", "利市襴衫拋白紵，風流名紙寫紅牋。", "歌樓夜宴停銀燭，柳巷春泥污錦韉。", "今日折腰塵土裏，共君追想好淒然。"]'),
('05bec1dd-c141-40f7-82c4-227c49a66352','寄魚臺主簿傅翶','王禹偁','宋','宋诗','song-poetry','','[]','健羨魚臺景最奇，鮑參軍到語多時。',64,'全唐诗/poet.song.3000.json','["健羨魚臺景最奇，鮑參軍到語多時。", "波平綠野懸魚網，木脫空城露酒旗。", "錦擲鮮鱗紅撥剌，雪翹寒鷺白䙰褷。", "仍誇縣尹風騷客，應有秋來唱和詩。"]'),
('05ff9e22-e475-47e7-ae5e-ba0677362636','寄寧陵陳長官','王禹偁','宋','宋诗','song-poetry','','[]','吏隠寧陵縣，琴堂枕古河。',48,'全唐诗/poet.song.3000.json','["吏隠寧陵縣，琴堂枕古河。", "家山隔江遠，風雨過船多。", "假日親尋藥，公庭自種莎。", "相逢如舊識，執手動勞歌。"]'),
('71b32578-f82e-43ae-b520-658895958a6e','寄金鄉張贊善','王禹偁','宋','宋诗','song-poetry','','[]','年少辭榮自古稀，朝衣不著著斑衣。',64,'全唐诗/poet.song.3000.json','["年少辭榮自古稀，朝衣不著著斑衣。", "北堂侍膳侵星起，南畝催耕冒雨歸。", "種竹野塘春筍脆，採蘭幽澗露牙肥。", "伊予自是徒勞者，未得同尋舊釣磯。"]'),
('00dacf55-16a2-4ee1-9e92-16d971c14dec','赴長洲縣作  其一','王禹偁','宋','宋诗','song-poetry','','[]','移任長洲縣，扁舟興有餘。',48,'全唐诗/poet.song.3000.json','["移任長洲縣，扁舟興有餘。", "篷高時見月，棹穩不妨書。", "雨碧蘆枝亞，霜紅蓼穗疏。", "此行紆墨綬，不是爲鱸魚。"]'),
('cc560e33-b475-427a-a798-724ac811cccf','赴長洲縣作  其二','王禹偁','宋','宋诗','song-poetry','','[]','移任長洲縣，辭親淚滿衣。',48,'全唐诗/poet.song.3000.json','["移任長洲縣，辭親淚滿衣。", "折腰雖未免，搔首欲何歸。", "曉白霜華重，晴紅栗葉飛。", "江頭鷗鳥在，應怪不忘機。"]'),
('d9624f9f-802f-4e58-ac78-2684a0e41842','赴長洲縣作  其三','王禹偁','宋','宋诗','song-poetry','','[]','移任長洲縣，孤帆冒雨行。',48,'全唐诗/poet.song.3000.json','["移任長洲縣，孤帆冒雨行。", "全家隨逆旅，一夜泊江城。", "身世漂淪極，功名早晚成。", "惟當泥尊酒，得喪任浮生。"]'),
('fc83787a-b8f6-4e92-ae53-bc1cc1e13036','赴長洲縣作  其四','王禹偁','宋','宋诗','song-poetry','','[]','移任長洲縣，窮秋入水鄉。',48,'全唐诗/poet.song.3000.json','["移任長洲縣，窮秋入水鄉。", "江涵千頃月，船載一篷霜。", "竹密藏魚市，雲疏漏雁行。", "故園漸迢遞，烟浪白茫茫。"]'),
('ff219bbd-88cc-46c1-8bf9-cd9b19a79df0','赴長洲縣作  其五','王禹偁','宋','宋诗','song-poetry','','[]','移任長洲縣，沿流漸入吳。',48,'全唐诗/poet.song.3000.json','["移任長洲縣，沿流漸入吳。", "見碑時下岸，逢店自徵酤。", "野廟連荒冢，江禽似畫圖。", "高堂從別後，應夢宿菰蒲。"]'),
('d8fbbdad-be44-494f-8d6c-cfd415dde3de','惠山寺留題','王禹偁','宋','宋诗','song-poetry','','[]','吟入惠山山下寺，古泉閑挹味何嘉。',64,'全唐诗/poet.song.3000.json','["吟入惠山山下寺，古泉閑挹味何嘉。", "好拋此日陶潛米，學煮當年陸羽茶。", "猶負片心眠水石，略開塵眼識烟霞。", "勞生未了還東去，孤棹寒篷宿浪花。"]'),
('ac964ed8-4d1c-4853-8d44-c5708f49b7e3','遊虎丘寺','王禹偁','宋','宋诗','song-poetry','','[]','寺牆圍著碧孱顔，曾是當年海湧山。',64,'全唐诗/poet.song.3000.json','["寺牆圍著碧孱顔，曾是當年海湧山。", "盡抱好峰藏院裏，不教幽景落人間。", "劍池草色經冬在，石座苔花自古斑。", "珍重晉朝吾祖宅，一迴來此便忘還。"]'),
('1bee8d7c-686a-4724-80b1-cc8a12acc186','寄獻潤州趙舍人  其一','王禹偁','宋','宋诗','song-poetry','','[]','南徐城古樹蒼蒼，衙府樓臺盡枕江。',64,'全唐诗/poet.song.3000.json','["南徐城古樹蒼蒼，衙府樓臺盡枕江。", "甘露鐘聲清醉榻，海門山色滴吟窗。", "直廬久負題紅葉，出鎮何妨擁碧幢。", "聞說秋來自高尚，道裝筇竹鶴成雙。"]'),
('aba3b459-8267-45f6-b531-d14777ddc944','寄獻潤州趙舍人  其二','王禹偁','宋','宋诗','song-poetry','','[]','記言彩筆罷摛華，郡閣高閑似道家。',64,'全唐诗/poet.song.3000.json','["記言彩筆罷摛華，郡閣高閑似道家。", "琴院坐聽江寺磬，郡樓吟見海山霞。", "春園遺母親燒筍，夜榻留僧自煮茶。", "應笑陶潛未歸去，折腰奔走在泥沙。"]'),
('71692646-4f1f-43a1-9784-ce29715fd23a','寄毗陵劉博士','王禹偁','宋','宋诗','song-poetry','','[]','毗陵古郡接江堧，赴任琴書共一船。',64,'全唐诗/poet.song.3000.json','["毗陵古郡接江堧，赴任琴書共一船。", "下岸且尋甘露寺，到城先問惠山泉。", "秋蟾吐檻供吟興，野鶴偎床伴醉眠。", "官散道孤詩格老，算應雙鬢更皤然。"]'),
('267409a8-b112-46af-a102-82dfe6220dfb','謝柴侍御送鶴','王禹偁','宋','宋诗','song-poetry','','[]','兩朵春雲墮世間，霜臺乞與縣僚看。',64,'全唐诗/poet.song.3000.json','["兩朵春雲墮世間，霜臺乞與縣僚看。", "骨含仙氣生來瘦，羽插天風過處寒。", "唳別繡衣聲寂寞，舞隨藍綬意闌珊。", "今朝窗外頻相顧，應怪頭無獬豸冠。"]'),
('de4e4163-afb2-463a-9965-56451073e88b','官舍書懷呈羅思純','王禹偁','宋','宋诗','song-poetry','','[]','同年事分幾般同，墨綬逶迤一郡中。',64,'全唐诗/poet.song.3000.json','["同年事分幾般同，墨綬逶迤一郡中。", "仙桂並枝攀月魄，縣花交影笑春風。", "分莎種就尋僧逕，借竹編成養鶴籠。", "公暇不妨閑唱和，免教來往遞詩筒。"]'),
('067bd20a-0f3d-49a2-a986-13bd167563ea','除夜寄羅評事同年  其一','王禹偁','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','歲暮洞庭山，知君思浩然。',48,'全唐诗/poet.song.3000.json','["歲暮洞庭山，知君思浩然。", "年侵曉色盡，人枕夜濤眠。", "移棹燈摇浪，開窗雪滿天。", "無因一乘興，同醉太湖船。"]'),
('e39da049-6b89-4a71-9838-81d014bf6a4e','除夜寄羅評事同年  其二','王禹偁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','除夜在天涯，共君同憶歸。',48,'全唐诗/poet.song.3000.json','["除夜在天涯，共君同憶歸。", "夢中傾壽酒，堂下著斑衣。", "臘雪通宵舞，梅花到處飛。", "更堪洞庭宿，愁思倍依依。"]'),
('748a06eb-8bc7-4edb-bcbd-b88de3906160','除夜寄羅評事同年  其三','王禹偁','宋','宋诗','song-poetry','','["\u592a\u6e56"]','郡僚方賀正，獨宿太湖稜。',48,'全唐诗/poet.song.3000.json','["郡僚方賀正，獨宿太湖稜。", "階下羞爲吏，船中祗載僧。", "折梅和薄雪，煮茗對孤燈。", "應笑排衙早，寒靴踏曉冰。"]'),
('214b8059-db5a-4bf4-9c81-f19d9dbec4f9','陸羽泉茶','王禹偁','宋','宋诗','song-poetry','','[]','甃石封苔百尺深，試茶嘗味少知音。',32,'全唐诗/poet.song.3000.json','["甃石封苔百尺深，試茶嘗味少知音。", "唯餘半夜泉中月，留得先生一片心。"]'),
('90e41a39-b0fb-42a5-9134-824d9ca326f4','投柴殿院','王禹偁','宋','宋诗','song-poetry','','[]','南面修文德，東吳納土疆。',288,'全唐诗/poet.song.3000.json','["南面修文德，東吳納土疆。", "蒼生思撫育，丹詔擇循良。", "烏府官新轉，龍頭桂舊香。", "渡江驄馬瘦，垂地繡衣長。", "綸閣材知屈，蘇臺俗必康。", "恩流一車雨，威凜柏臺霜。", "休假尋山寺，行春泊野塘。", "白公是前政，魯望有維桑。", "求瘼心雖切，頤神道豈妨。", "煎茶虎丘井，搗藥木蘭堂。", "筍蕨供家饌，園林著道裝。", "擊筇教鶴舞，收橘待僧嘗。", "迎使朝衣穩，娛賓綺席張。", "犬聲銷巷陌，鶑舌動笙簧。", "冷句題秋葉，孤琴貯夜囊。", "歌樓寒月白，飲舫晚波凉。", "官業除苛法，家風襲雅章。", "豸冠危肅物，象簡醉橫床。", "熊軾淹寧久，鼇頭譽轉芳。", "南園休命侶，北闕即徵黄。", "清貴容誰見，遭逢合自强。", "字人叨屬邑，畏德每循牆。", "名品知懸隔，孤危俟薦揚。", "折腰休太息，青眼異尋常。"]'),
('c6f9c86b-0f0b-485b-b6a7-13bafa605f37','東鄰竹','王禹偁','宋','宋诗','song-poetry','','[]','東鄰誰種竹，偏稱長官心。',48,'全唐诗/poet.song.3000.json','["東鄰誰種竹，偏稱長官心。", "月上分清影，風來惠好音。", "低枝疑見接，迸筍似相尋。", "多謝此君意，牆頭誘我吟。"]'),
('663d8a92-9876-421a-bde2-dfc2df86a669','南園偶題','王禹偁','宋','宋诗','song-poetry','','[]','天子優賢是有唐，鑑湖恩賜賀知章。',32,'全唐诗/poet.song.3000.json','["天子優賢是有唐，鑑湖恩賜賀知章。", "他年我若功成去，乞取南園作醉鄉。"]'),
('6061807c-7fe6-42ef-804d-30865e471375','戲贈嘉興朱宰同年','王禹偁','宋','宋诗','song-poetry','','[]','縣前蘇小舊荒墳，應作行雲入夢頻。',32,'全唐诗/poet.song.3000.json','["縣前蘇小舊荒墳，應作行雲入夢頻。", "猶勝白公尉盩厔，庭花剛喚作夫人。"]'),
('fe050b1e-d6c8-412f-b881-3f74140142e7','春日官舍偶題','王禹偁','宋','宋诗','song-poetry','','[]','薄宦苦流離，壯年心已衰。',48,'全唐诗/poet.song.3000.json','["薄宦苦流離，壯年心已衰。", "鶑花愁不覺，風雨病先知。", "曉月晃竹屋，寒苔疊槿籬。", "無人慰幽寂，庭柳自低垂。"]'),
('92aa0dc0-6a66-42b1-bafa-92994955d3cc','寄獻翰林宋舍人','王禹偁','宋','宋诗','song-poetry','','[]','金鼎鹽梅偶未和，位高猶說野情多。',64,'全唐诗/poet.song.3000.json','["金鼎鹽梅偶未和，位高猶說野情多。", "宮牆月上開琴匣，道院風清響藥羅。", "留客旋燒含露筍，倩僧教種耐霜莎。", "孤寒知有爲霖望，未忍江頭釣淥波。"]'),
('4c355adc-d9ec-48ef-86dc-839cdac7cb8f','吳江縣寺留題','王禹偁','宋','宋诗','song-poetry','','[]','松江江寺對峰巒，檻外生池接野灘。',64,'全唐诗/poet.song.3000.json','["松江江寺對峰巒，檻外生池接野灘。", "幽鷺靜翹春草碧，病僧閑說夜濤寒。", "晨齋施筍唯溪叟，國忌行香祇縣官。", "盡日門前照流水，塵纓渾疑濯汍瀾。"]'),
('3d6f88a4-956a-4dc7-94cb-bc3e995bb1b2','獻轉運使雷諫議  其一','王禹偁','宋','宋诗','song-poetry','','[]','當年辭氣壓朱雲，老作皇家諫諍臣。',64,'全唐诗/poet.song.3000.json','["當年辭氣壓朱雲，老作皇家諫諍臣。", "章疏罷封無事日，朝廷猶惜直言人。", "題詩野館光泉石，講易秋堂動鬼神。", "棘寺下僚叨末路，齋心唯願秉陶鈞。"]'),
('5558646d-ee97-4d7a-9905-4b7cbd4c7137','獻轉運使雷諫議  其二','王禹偁','宋','宋诗','song-poetry','','[]','江南江北接王畿，漕運帆檣去似飛。',64,'全唐诗/poet.song.3000.json','["江南江北接王畿，漕運帆檣去似飛。", "父子有才同富國，君王無事免宵衣。", "屏除姦吏魂應喪，養活疲民肉漸肥。", "還有文場受恩客，望塵情抱倍依依。"]'),
('d2335b6e-f66f-49a5-b622-31f959142ce2','羅思純鶴斃爲四韵吊之','王禹偁','宋','宋诗','song-poetry','','[]','雪乾朱澹殞仙姿，千歲無徵事可悲。',64,'全唐诗/poet.song.3000.json','["雪乾朱澹殞仙姿，千歲無徵事可悲。", "埋瘞肯饒鸚鵡塚，飛鳴不到鳳凰池。", "遺翎尚在飄松逕，舊跡猶存傍槿籬。", "應得羽人尸解術，夜來何處啄靈芝。"]'),
('2c251c30-4502-4b6c-8c19-55ae452de628','即席送許製之曹南省兄','王禹偁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','梅爛荷圓六月天，歸帆高背虎丘烟。',64,'全唐诗/poet.song.3000.json','["梅爛荷圓六月天，歸帆高背虎丘烟。", "到時自是成行雁，別處休聽滿樹蟬。", "賣劍爲賒吳市酒，携家猶借洞庭船。", "待看春榜來江外，名占蓬萊第幾仙。"]'),
('82f6d14e-daed-496a-ba51-7b5dcb7693c4','中元夜宿餘杭仙泉寺留題','王禹偁','宋','宋诗','song-poetry','','[]','祭廟迴來略問禪，蘇牆莎逕碧山前。',64,'全唐诗/poet.song.3000.json','["祭廟迴來略問禪，蘇牆莎逕碧山前。", "風疏遠磬秋開講，水響寒車夜救田。", "藍綬有香花菡萏，竹窗無寐月嬋娟。", "自慚政術貽枯旱，忍卧松陰漱石泉。"]'),
('cd6d4fc5-5c36-4385-a6e6-33d3a5069aad','贈草庵禪師','王禹偁','宋','宋诗','song-poetry','','[]','陽山山下草庵深，寂寂香燈對遠岑。',32,'全唐诗/poet.song.3000.json','["陽山山下草庵深，寂寂香燈對遠岑。", "莫怪相看總無語，坐禪爲政一般心。"]'),
('66b5b086-1104-4560-838d-f1b9a198f90e','言懷','王禹偁','宋','宋诗','song-poetry','','[]','宦途日日與心違，人事紛紛任是非。',32,'全唐诗/poet.song.3000.json','["宦途日日與心違，人事紛紛任是非。", "却爲遊山置行李，漁家船舫道家衣。"]'),
('432077dd-6009-46d9-9154-387f7e2ce828','題響屧廊壁','王禹偁','宋','宋诗','song-poetry','','[]','廊壞空留響屧名，爲因西子遶廊行。',32,'全唐诗/poet.song.3000.json','["廊壞空留響屧名，爲因西子遶廊行。", "可憐伍相終朝諫，誰記當時曳履聲。"]'),
('6ba129c3-9b15-4195-ab74-4284f33747dc','中秋月','王禹偁','宋','宋诗','song-poetry','','[]','何處見清輝，登樓正午時。',48,'全唐诗/poet.song.3000.json','["何處見清輝，登樓正午時。", "莫辭終夕看，動是隔年期。", "冷濕流螢草，光凝宿鶴枝。", "不禁鷄唱曉，輕別下天涯。"]'),
('98ef1211-4417-42aa-ace6-0187f786635e','贈採訪使閤門穆舍人','王禹偁','宋','宋诗','song-poetry','','[]','經略十三州，東南帝不憂。',240,'全唐诗/poet.song.3000.json','["經略十三州，東南帝不憂。", "二年辭玉砌，幾夜夢珠旒。", "旌旆雖遐適，江山是勝遊。", "風謠隨處採，民瘼盡心求。", "報國機鈐密，供吟景象幽。", "煮茶溪畔寺，望月海邊樓。", "步武思龍尾，琴書在鷁舟。", "聽泉調玉軫，拂石試銀鈎。", "古畫多收買，新詩寡和詶。", "酒醒聞瀑響，睡起見潮頭。", "奉使時將久，歸朝禮必優。", "一麾先出守，萬戶待封侯。", "遇主當宜貴，遺材亦合收。", "此身居下位，無路畫良籌。", "已悔田園廢，堪驚鬢髮秋。", "憑誰念寒苦，祇自擬歸休。", "僻甚陶元亮，貧過魯仲由。", "品題殊不濫，清濁肯同流。", "復命期三接，陳詩說四愁。", "薦雄如有便，還解殺身酬。"]'),
('84595013-d3e8-4f74-9595-da10a24b7194','泛吳松江','王禹偁','宋','宋诗','song-poetry','','["\u538c\u6076", "\u6292\u60c5", "\u653f\u6cbb", "\u5199\u666f", "\u4ed5\u9014"]','葦篷疏薄漏斜陽，半日孤吟未過江。',32,'全唐诗/poet.song.3000.json','["葦篷疏薄漏斜陽，半日孤吟未過江。", "唯有鷺鷀和我意，時時翹足對船窗。"]'),
('16ab72a7-008e-421d-b278-4e8e07ef562f','獻轉運副使太常李博士','王禹偁','宋','宋诗','song-poetry','','[]','邦計動宸衷，時賢蒞浙東。',216,'全唐诗/poet.song.3000.json','["邦計動宸衷，時賢蒞浙東。", "量寬吞渤澥，氣直稟崆峒。", "捧詔瑶池下，辭班玉筍中。", "饋糧蕭相國，制禮叔孫通。", "舉措敦儒行，談諧有古風。", "冀方思舊政，江表佇成功。", "吏畏嚴霜白，民歌愛日紅。", "勤王雖運智，修道豈妨公。", "旋種烟莎逕，閑科雨竹叢。", "養成丹頂鶴，瘦盡雪花驄。", "移石情無倦，抄書俸不充。", "晨餐燒露筍，秋句寫霜楓。", "棋閣連花塢，書窗映燭籠。", "僧傳栽樹法，客獻遞詩筒。", "飲席螺爲盞，吟舟葦作篷。", "按琴苔院冷，搗藥月堂空。", "清白成家計，操修達聖聰。", "即徵歸象闕，清秩冠鴛鴻。"]'),
('f0a162e5-6519-4f6b-bbd4-74586a09184b','蘇州寒食日送人歸覲','王禹偁','宋','宋诗','song-poetry','','[]','江城寒食下，花木慘離魂。',48,'全唐诗/poet.song.3000.json','["江城寒食下，花木慘離魂。", "幾宿投山寺，孤帆過海門。", "篷聲潑火雨，柳色禁烟村。", "定省高堂後，斑衣減淚痕。"]'),
('f5589b63-f2dd-4601-beb4-c1f845e28a56','春晚遊太和宮','王禹偁','宋','宋诗','song-poetry','','[]','數里新萍夾岸莎，春來乘興宿烟蘿。',64,'全唐诗/poet.song.3000.json','["數里新萍夾岸莎，春來乘興宿烟蘿。", "隨風蝴蝶顛狂甚，當路花枝採折多。", "絳節參差抽苦筍，翠鈿狼籍撒圓荷。", "湖山滿眼不休去，空羨漁翁雨一蓑。"]'),
('8dbb4ed0-3690-4bf1-8bab-3b25d70f3afe','再泛吳江','王禹偁','宋','宋诗','song-poetry','','[]','二年爲吏住江濱，重到江頭照病身。',64,'全唐诗/poet.song.3000.json','["二年爲吏住江濱，重到江頭照病身。", "滿眼碧波輸野鳥，一蓑疏雨屬漁人。", "隨船曉月孤輪白，入座晴山數點春。", "張翰精靈還笑我，綠袍依舊惹埃塵。"]'),
('d16b9ae6-c51d-46dd-9780-5d31dd1a2f9f','筍  其一','王禹偁','宋','宋诗','song-poetry','','[]','數里春蹊獨自尋，迸犀抽錦亂森森。',32,'全唐诗/poet.song.3000.json','["數里春蹊獨自尋，迸犀抽錦亂森森。", "田文死去賓朋散，拋擲三千玳瑁簪。"]'),
('5f873c83-3bb4-4131-ba7e-538ee4951365','筍  其二','王禹偁','宋','宋诗','song-poetry','','[]','綠玉脩脩冷罩烟，一溪春雨洗嬋娟。',32,'全唐诗/poet.song.3000.json','["綠玉脩脩冷罩烟，一溪春雨洗嬋娟。", "不知徐福歸何處，丱女童男泣海田。"]'),
('37772d88-f99b-479f-bb63-80430860d1c6','筍  其三','王禹偁','宋','宋诗','song-poetry','','[]','一夜春雷起舊根，亂披烟籜出溪門。',32,'全唐诗/poet.song.3000.json','["一夜春雷起舊根，亂披烟籜出溪門。", "稚川龍過頻回首，認得青青數代孫。"]'),
('46bd6190-5135-4181-9818-dba66bae79c2','官舍書懷呈郡守','王禹偁','宋','宋诗','song-poetry','','[]','年來潘令鬢初凋，瘦馬青衫耻下僚。',64,'全唐诗/poet.song.3000.json','["年來潘令鬢初凋，瘦馬青衫耻下僚。", "藥債漸多醫宿疾，宦情猶切戀明朝。", "空江梅雨添幽鬰，古縣槐花鏁寂寥。", "頼有郡侯知己在，每憐憔悴貰金貂。"]'),
('49da8fd9-9eea-48ba-9744-2a668a4d2ee0','贈毋中舍','王禹偁','宋','宋诗','song-poetry','','[]','嶺表榆關路嶮巇，頒條持節兩無辭。',64,'全唐诗/poet.song.3000.json','["嶺表榆關路嶮巇，頒條持節兩無辭。", "四方自是男兒事，萬里歸來聖主知。", "磧雪舊行閑入夢，貪泉曾飲別留詩。", "如今已見功名立，休憶當年一桂枝。"]'),
('08b6efdb-94db-40ce-8c6f-da6f3c2eab05','贈贊寧大師','王禹偁','宋','宋诗','song-poetry','','[]','詔修僧史浙江濱，萬卷書中老一身。',64,'全唐诗/poet.song.3000.json','["詔修僧史浙江濱，萬卷書中老一身。", "赴闕尚留支遁馬，援毫應待仲尼麟。", "溟濛雪影松窗曉，狼籍苔花竹院春。", "還許幽齋暫相訪，却慚陶令滿衣塵。"]'),
('d46d5ea6-a0a9-4f56-be4c-414e81d0a1c1','題錢塘縣羅江東手植海棠','王禹偁','宋','宋诗','song-poetry','','[]','江東遺跡在錢塘，手植庭花滿縣香。',32,'全唐诗/poet.song.3000.json','["江東遺跡在錢塘，手植庭花滿縣香。", "若使當年居顯位，海棠今日是甘棠。"]'),
('f67d0bb8-abff-46ce-83b8-71f6b3e2d296','武平寺留題','王禹偁','宋','宋诗','song-poetry','','[]','縣齋東面是禪齋，公退何妨引鶴來。',64,'全唐诗/poet.song.3000.json','["縣齋東面是禪齋，公退何妨引鶴來。", "長愛座中如洞府，却慚衣上有塵埃。", "竹聲冷撼秋窗雨，山影青籠曉院苔。", "最憶去年飛雪裏，煮茶煨栗夜深迴。"]'),
('39ac97cf-d623-4db4-a208-28f5c5d12896','贈湖州張從事','王禹偁','宋','宋诗','song-poetry','','[]','前年春牓亞龍頭，詞賦曾推第一流。',64,'全唐诗/poet.song.3000.json','["前年春牓亞龍頭，詞賦曾推第一流。", "上直未歸紅藥院，供吟先得白蘋洲。", "酒醒野寺烹山蕨，公退溪亭狎海鷗。", "自是吳門折腰吏，滿衣塵土爲君羞。"]'),
('b2429d1a-f1c6-4756-a17c-aa95b3cc8d83','送李中舍罷蕭山赴闕','王禹偁','宋','宋诗','song-poetry','','[]','吏隠江東五六年，歸時猶戀好山川。',64,'全唐诗/poet.song.3000.json','["吏隠江東五六年，歸時猶戀好山川。", "野僧送別携詩句，瘦馬臨歧當酒錢。", "吳苑醉逢梅弄雪，隋堤吟見柳垂煙。", "自言更共秋濤約，未捨四興一釣船。"]'),
('7ee66b85-afb5-4f08-87d2-e85d6f70d56c','寄主客安員外十韵','王禹偁','宋','宋诗','song-poetry','','[]','罷郡歸蘭省，還愁到帝鄉。',120,'全唐诗/poet.song.3000.json','["罷郡歸蘭省，還愁到帝鄉。", "趨朝騎瘦馬，賃宅住閑坊。", "命服紆春草，吟髭鑷夜霜。", "有心憶雲水，無語狎班行。", "藥債經年欠，文編滿篋藏。", "教兒誦詩賦，倩客賣囊裝。", "尋寺誰同步，留僧自拂床。", "舉公投卷軸，時相覓文章。", "窮達君雖了，沉淪我亦傷。", "何當昇大用，吾道始輝光。"]'),
('7e7cdc8a-ea95-4da1-8ebf-9312c670af0d','和郡僚題李中舍公署','王禹偁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','樹影池光映曉霞，綠楊陰下吏排衙。',64,'全唐诗/poet.song.3000.json','["樹影池光映曉霞，綠楊陰下吏排衙。", "閑拖屐齒妨橫筍，靜拂琴床有落花。", "地脉暗分吳苑水，厨烟時煮洞庭茶。", "青宮詞客多閑暇，按曲飛觴待歲華。"]'),
('db13c817-d7eb-426e-89e6-bb96dda7672f','送奉常李丞赴闕','王禹偁','宋','宋诗','song-poetry','','[]','江城方話舊，捧詔去長安。',48,'全唐诗/poet.song.3000.json','["江城方話舊，捧詔去長安。", "宦路相逢少，鄉情敘別難。", "烟波迷曉渡，風雨動春寒。", "初夏應回首，重期看牡丹。"]'),
('02e9de48-8d29-4e85-ac79-310fa4224c1c','題張處士溪居','王禹偁','宋','宋诗','song-poetry','','[]','雲裏寒溪竹裏橋，野人居處絕塵囂。',64,'全唐诗/poet.song.3000.json','["雲裏寒溪竹裏橋，野人居處絕塵囂。", "病來芳草生漁艇，睡起殘花落酒瓢。", "閑把道書尋晚逕，靜携茶鼎洗春潮。", "長洲懶吏頻過此，爲愛盤飧有藥苗。"]'),
('09196d9b-e643-45b5-9920-b362df30a35b','初拜拾遺遊瓊林苑','王禹偁','宋','宋诗','song-poetry','','[]','開宴曾遊此綴行，五年爲吏別仙鄉。',32,'全唐诗/poet.song.3000.json','["開宴曾遊此綴行，五年爲吏別仙鄉。", "杏園鶑蝶如相識，應怪重來蒨綬香。"]'),
('a70900ec-f2d7-4237-8f1f-8cbd6253e6ed','館中春值偶題','王禹偁','宋','宋诗','song-poetry','','[]','御柳差差拂禁牆，菲才何事直仙鄉。',64,'全唐诗/poet.song.3000.json','["御柳差差拂禁牆，菲才何事直仙鄉。", "坐聞雞唱皇宮近，睡枕魚鬚白日長。", "簾挂蘚庭微雨霽，研添桐井落花香。", "春風老盡詩情淡，翻卷青編獨繞廊。"]'),
('3f2b8d3f-b069-47aa-a8e4-c9c61c5a6538','寄贊寧上人','王禹偁','宋','宋诗','song-poetry','','[]','支公兼有董狐才，史傳修成乙夜開。',64,'全唐诗/poet.song.3000.json','["支公兼有董狐才，史傳修成乙夜開。", "天子遠酬丹詔去，高僧不出白雲來。", "眉毫久別應垂雪，心印休傳本似灰。", "若念重瞳欲相見，未妨西上一浮杯。"]'),
('6f445762-fcd9-4c8e-911d-0d03c70b1a52','歲暮偶書寄蘇臺舊僚友','王禹偁','宋','宋诗','song-poetry','','[]','吳門吏隠過三年，何事陶潜捧詔還。',64,'全唐诗/poet.song.3000.json','["吳門吏隠過三年，何事陶潜捧詔還。", "步武已趨龍尾道，夢魂猶憶虎丘山。", "花開茂苑誰同醉，雪滿梁園獨掩關。", "會待他年求郡印，劍池重遶碧潺潺。"]'),
('3ccb956b-881f-494c-ad79-0562bedddec6','朝退偶題','王禹偁','宋','宋诗','song-poetry','','[]','吏隠金門祗似閑，退朝窮巷懶開關。',64,'全唐诗/poet.song.3000.json','["吏隠金門祗似閑，退朝窮巷懶開關。", "經年不到公卿宅，五日空隨侍從班。", "禁漏出花寒歷歷，御泉通市細潺潺。", "功名未立年猶少，爭忍携琴去舊山。"]'),
('bfdc9dc8-5d8d-4272-91ca-5cb53ea78970','送王司諫赴淮南轉運','王禹偁','宋','宋诗','song-poetry','','[]','白獸樽前侍玉除，暫分邦計別宸居。',64,'全唐诗/poet.song.3000.json','["白獸樽前侍玉除，暫分邦計別宸居。", "映淮風月供吟筆，拱極星辰伴使車。", "別岸酒濃桑葉落，野亭霜薄菊花疏。", "東南莫作三年調，紅藥香繁在直廬。"]'),
('da3915f1-c236-47de-a941-d97b610d602a','送郝校書從事相州','王禹偁','宋','宋诗','song-poetry','','[]','提筆從戎別帝鄉，官清兼領校書郎。',64,'全唐诗/poet.song.3000.json','["提筆從戎別帝鄉，官清兼領校書郎。", "將軍幕下紅蓮媚，詩客袖中丹桂香。", "吟倚旌旗春過雨，醉聽刁斗夜含霜。", "金臺莫作多時計，非久應歸振鷺行。"]'),
('70f44fc9-1d7a-4fd2-ad4a-838807f0e315','獻僕射相公  其一','王禹偁','宋','宋诗','song-poetry','','[]','罷調金鼎道光輝，聞說閑園自種薇。',64,'全唐诗/poet.song.3000.json','["罷調金鼎道光輝，聞說閑園自種薇。", "書院日斜春睡覺，沙堤人靜早朝歸。", "吟穿竹逕僧同步，醉遶花庭蝶上衣。", "却恐優游未終歲，台星依舊照黄扉。"]'),
('10bba0cf-1794-411c-ac3b-da5e5e6c111e','獻僕射相公  其二','王禹偁','宋','宋诗','song-poetry','','[]','五年黄閣掌陶甄，憂國翻成兩鬢斑。',64,'全唐诗/poet.song.3000.json','["五年黄閣掌陶甄，憂國翻成兩鬢斑。", "初到廟堂溫樹冷，暫收霖雨岳雲閑。", "春園領鶴尋芳草，小閣留僧畫遠山。", "惟有門生苦求見，竹齋花院一開關。"]'),
('97c6ad28-62b6-40d7-9070-52a9e88777f7','賀李宗諤先輩除校書郎','王禹偁','宋','宋诗','song-poetry','','[]','祕省官清住帝鄉，春來春榜探花郎。',64,'全唐诗/poet.song.3000.json','["祕省官清住帝鄉，春來春榜探花郎。", "未吟紅藥歸西掖，且著青衫侍北堂。", "射策更期揮健筆，騎馿猶得醉閑坊。", "同年佐邑應相羨，衣上芸香雜桂香。"]'),
('4c51dccb-0de4-43c4-973e-f2c2e2d6628f','送夏侯正言襄陽迎親','王禹偁','宋','宋诗','song-poetry','','[]','蘭省方讎乙夜書，襄陽迎侍暫脂車。',64,'全唐诗/poet.song.3000.json','["蘭省方讎乙夜書，襄陽迎侍暫脂車。", "揮毫偶未歸綸閣，衣錦何妨奉板輿。", "峴首碑前留馬足，鹿門山下宿僧居。", "漢臯遊女曾相識，應解鳴璫換佩魚。"]'),
('04fb6c4e-4b80-44f4-a7e1-07e6befb9445','送鞠評事宰蘭溪','王禹偁','宋','宋诗','song-poetry','','[]','東下蘭溪數十程，幾多山水入圖經。',64,'全唐诗/poet.song.3000.json','["東下蘭溪數十程，幾多山水入圖經。", "科名舊捷仙人桂，縣界遥看婺女星。", "琴院靜籠江樹綠，敕樓高對海峰青。", "三年吏隠無嗟嘆，百里封疆似畫屏。"]'),
('a58348c9-4429-44f2-9c0b-df4e45ff3b18','送查校書從事彭門','王禹偁','宋','宋诗','song-poetry','','[]','佐幕徐方鬢未秋，官升芸閣更風流。',64,'全唐诗/poet.song.3000.json','["佐幕徐方鬢未秋，官升芸閣更風流。", "姓名舊在鶑遷榜，詩什重題燕子樓。", "漸有俸錢供藥債，應無歸夢到漁舟。", "公餘時上臺頭寺，珠履金貂共勝遊。"]'),
('fb7fb614-b64f-4767-8fc3-f9f55bd4b983','送史館趙寺丞出宰咸陽','王禹偁','宋','宋诗','song-poetry','','[]','縣連秦漢舊離宮，分付詩人勝武功。',64,'全唐诗/poet.song.3000.json','["縣連秦漢舊離宮，分付詩人勝武功。", "带職遠辭書殿去，携家深入畫圖中。", "庭莎曉潤終南雨，檻竹寒摇渭水風。", "百里封疆三館客，折腰休歎似陶公。"]'),
('d85d41e9-1485-4bc2-9464-091020c285b6','送田舍人出牧淮陽','王禹偁','宋','宋诗','song-poetry','','[]','藥樹吟多且握蘭，藹然公議滿朝端。',64,'全唐诗/poet.song.3000.json','["藥樹吟多且握蘭，藹然公議滿朝端。", "西垣罷直蒼苔冷，南郡行春綠野寬。", "蒨旆出過應曜墓，棠陰潜上伏犧壇。", "鄉心休夢峨眉雪，會顧青蒲憶史丹。"]'),
('dcfff443-de6f-464f-9e4b-7dc24e8d556b','送羅著作奉使湖湘','王禹偁','宋','宋诗','song-poetry','','[]','使星躔次入長沙，曉別延英去路賒。',64,'全唐诗/poet.song.3000.json','["使星躔次入長沙，曉別延英去路賒。", "數刻漏中承密旨，幾重湖外奉皇華。", "山行馬拂湘川石，寺宿僧供岳麓茶。", "迴日期君直西掖，當階紅藥正開花。"]'),
('445554b8-059a-42bf-81d1-6f9fc135f729','送夏侯正言奉使江南','王禹偁','宋','宋诗','song-poetry','','[]','百舌關關麥壠青，遠山迎馬翠如屏。',64,'全唐诗/poet.song.3000.json','["百舌關關麥壠青，遠山迎馬翠如屏。", "禁中已誦相如賦，江外猶看使者星。", "衣拂茶烟尋水寺，枕欹梅雨泊沙汀。", "歸期莫過中秋節，侍宴甘泉月滿庭。"]'),
('cded3732-0007-4f64-9c72-dff7d5570216','送館中王正言使交趾','王禹偁','宋','宋诗','song-poetry','','[]','乘軺南下興何長，大半江山是故鄉。',64,'全唐诗/poet.song.3000.json','["乘軺南下興何長，大半江山是故鄉。", "蠻府好迎天上使，朝賢不爲橐中裝。", "犀牛出水挨銅柱，颶母扶空卸海檣。", "復命丹墀莫經歲，北門西掖待翶翔。"]'),
('d7f61204-489b-4f38-aa6f-1f9e5375009d','七夕應製','王禹偁','宋','宋诗','song-poetry','','[]','斜漢橫空瑞氣浮，橋邊烏鵲待牽牛。',64,'全唐诗/poet.song.3000.json','["斜漢橫空瑞氣浮，橋邊烏鵲待牽牛。", "長生殿冷時無事，乞巧樓多歲有秋。", "菡萏晚花清露濕，嬋娟新月暮烟收。", "華封禱祝華胥夢，誰道神仙不可求。"]'),
('8ffcb9d3-403d-4990-b61e-f0ee86c4c609','送柴郎中使高麗','王禹偁','宋','宋诗','song-poetry','','[]','初過清明野色繁，柳花榆莢撲軺軒。',64,'全唐诗/poet.song.3000.json','["初過清明野色繁，柳花榆莢撲軺軒。", "中臺應宿郎官貴，外國占星使者尊。", "海水無波分島嶼，扶桑見日認藩垣。", "東夷休請蕭夫子，好把詩書問狀元。"]'),
('db61eca7-1997-40f5-b604-9f4fcd10f1d1','送羅著作兩浙按獄','王禹偁','宋','宋诗','song-poetry','','[]','使印星車適舊遊，陶潜今日在瀛洲。',64,'全唐诗/poet.song.3000.json','["使印星車適舊遊，陶潜今日在瀛洲。", "科條盡曉三千罪，囹圄應空十二州。", "蒨綬有香籠驛馬，皇華無暇狎沙鷗。", "歸來重過姑蘇郡，莫忘題名向虎丘。"]'),
('78cfb1e9-bd0c-4e48-90ca-25d5dc5659f3','賀溫正言賜紫','王禹偁','宋','宋诗','song-poetry','','[]','密疏封來乙夜看，延英召對議安邊。',64,'全唐诗/poet.song.3000.json','["密疏封來乙夜看，延英召對議安邊。", "榮頒紫綬同三品，舊賜朱衣未一年。", "白獸捧樽斟御酒，金魚垂鬣惹爐烟。", "從今便有公卿望，休夢天臺瀑布泉。"]'),
('08ef988b-2cee-4713-bc2a-26d73be7d247','送光祿王寺丞通判徐方','王禹偁','宋','宋诗','song-poetry','','[]','通悴徐方蒨綬新，老萊衣服暫離身。',64,'全唐诗/poet.song.3000.json','["通悴徐方蒨綬新，老萊衣服暫離身。", "家君蓮幕開廳事，府帥金貂耀縉紳。", "戲馬臺荒春寂寞，斬蛇鄉古樹輪囷。", "公餘應長吟滋味，好寄西垣寓直人。"]'),
('2d2bbc55-1e5f-4187-8783-69d820fd4aa6','謝同年黄法曹送道服','王禹偁','宋','宋诗','song-poetry','','[]','鮑照貽我羽人衣，下直何妨盡日披。',64,'全唐诗/poet.song.3000.json','["鮑照貽我羽人衣，下直何妨盡日披。", "老去自堪將野鶴，客來休更佩金龜。", "官供謾說青綾被，私便全勝白接䍦。", "未脫朝簪戀明主，耿懷空作謝君詩。"]'),
('0ba49731-436b-483f-975f-2ee62e055b06','送馮學士入蜀','王禹偁','宋','宋诗','song-poetry','','[]','錦川宜共少年期，四十風情去未遲。',64,'全唐诗/poet.song.3000.json','["錦川宜共少年期，四十風情去未遲。", "蠶市夜歌欹枕處，峨嵋春雪倚樓時。", "休誇上直吟紅藥，多羨乘軺聽子規。", "莫學當初杜工部，因循不賦海棠詩。"]'),
('37d3f1bd-b425-4493-8695-23260f34f23c','和陳州田舍人留別  其一','王禹偁','宋','宋诗','song-poetry','','[]','宛丘分理藉賢明，暫輟詞臣撫百城。',64,'全唐诗/poet.song.3000.json','["宛丘分理藉賢明，暫輟詞臣撫百城。", "職罷掖垣人共惜，郡連京輔自爲榮。", "休吟紅藥堦前色，且聽長淮枕上聲。", "駐馬都門相別處，柳黄莎碧上林鶑。"]'),
('4f856bf3-4774-40cb-9c09-f767c0452b26','和陳州田舍人留別  其二','王禹偁','宋','宋诗','song-poetry','','[]','東風初暖酒難銷，五馬行春罷趁朝。',64,'全唐诗/poet.song.3000.json','["東風初暖酒難銷，五馬行春罷趁朝。", "道畔棠陰同召伯，堦前蓂莢別唐堯。", "下車正是嘗新筍，得句何妨寄舊僚。", "預想郡齋公宴處，桃花凝露柳垂條。"]'),
('f3e9af2d-7a2a-47b3-ad72-1a28a553b3e2','和陳州田舍人留別  其三','王禹偁','宋','宋诗','song-poetry','','[]','演綸多暇每封章，暫去頒條道更光。',64,'全唐诗/poet.song.3000.json','["演綸多暇每封章，暫去頒條道更光。", "郡吏好排紅粉妓，史君曾是紫微郎。", "樓臺有月新詩出，囹圄無人綠草長。", "地接清淮足佳致，水村烟塢似魚鄉。"]'),
('c40eabc6-412f-4cf8-ba2a-9f3d182ac32e','和陳州田舍人留別  其四','王禹偁','宋','宋诗','song-poetry','','[]','淮陽冰綻柳條新，風物暄妍土俗淳。',64,'全唐诗/poet.song.3000.json','["淮陽冰綻柳條新，風物暄妍土俗淳。", "捧詔暫辭雙闕路，勸農深入四郊春。", "茶烟靜拂聽琴鶴，穀雨輕籠鋤麥人。", "贏得褰帷恣吟興，落花飛絮滿車茵。"]'),
('acb6e939-0e22-4b6f-b1b4-623947232fb6','和陳州田舍人留別  其五','王禹偁','宋','宋诗','song-poetry','','[]','頒條京輔近吾君，政術高于召信臣。',64,'全唐诗/poet.song.3000.json','["頒條京輔近吾君，政術高于召信臣。", "道服日斜披鶴氅，藥畦春暖步龍鱗。", "歸朝莫指三年調，化俗應蘇一郡人。", "願作淮陽去思頌，與君刊石慰陳民。"]'),
('9def2ca4-4bc0-4c35-9ee5-f72762055a7e','賀將作孔監致仕','王禹偁','宋','宋诗','song-poetry','','[]','泣辭明主挂冠簪，便約幽雲老舊林。',64,'全唐诗/poet.song.3000.json','["泣辭明主挂冠簪，便約幽雲老舊林。", "朝請罷來頻典笏，田園歸去只携琴。", "焚香靜院當山色，曬藥空庭避竹陰。", "一子得官三品祿，未饒疏傅有黄金。"]'),
('bdd0789c-bac6-4f58-8d32-b670c0d11277','送密直溫學士西京遷葬','王禹偁','宋','宋诗','song-poetry','','[]','錦衣西去道何光，卜葬伊川舊釣鄉。',64,'全唐诗/poet.song.3000.json','["錦衣西去道何光，卜葬伊川舊釣鄉。", "留守開筵親舉白，故人垂淚看焚黄。", "重尋泉石應多感，旋插松楸未著行。", "一月歸程如有暇，雲間時到讀書房。"]'),
('e0f81206-ac8c-4476-ad20-057f949e6364','寄田舍人','王禹偁','宋','宋诗','song-poetry','','[]','出處昇沉不足悲，羨君操履是男兒。',64,'全唐诗/poet.song.3000.json','["出處昇沉不足悲，羨君操履是男兒。", "左遷郡印辭綸閣，直諫書囊在殿帷。", "未有僉諧徵賈誼，可無章疏雪微之。", "朝行孤立知音少，閑步蒼苔一淚垂。"]'),
('9659d382-22d5-4e9b-b628-4fbafc1aeede','送趙令公西京留守','王禹偁','宋','宋诗','song-poetry','','[]','勳業與誰同，蕭何第一功。',240,'全唐诗/poet.song.3000.json','["勳業與誰同，蕭何第一功。", "兩朝行直道，萬國變淳風。", "微恙妨三接，辭榮動四聰。", "白麻宣上閣，清洛守離宮。", "讓表迴宸翰，朝辭泣舜瞳。", "對深移五刻，官重带三公。", "鳳浴荀池暖，龍蟠洛邑雄。", "位尊非借寇，神爽近維嵩。", "導騎香塵細，肩輿曉霧籠。", "下車鶗鴂語，開宴牡丹紅。", "溫樹深嚴夢，甘棠蔽芾叢。", "趨庭採蘭子，投刺茹芝翁。", "廣化如靈鷲，天津似綵虹。", "先皇陵樹老，白傅影堂空。", "春饌思山蕨，秋屏畫水葓。", "御泉通廨宇，禁柳映簾櫳。", "元老優游盛，明君眷注隆。", "更須歸相府，特地代天工。", "永佐千年運，重頒九錫弓。", "不同崔四入，正在亂離中。"]'),
('d65d77f7-157a-4f7a-a86e-0a067bce86c2','送同年劉司諫通判西都','王禹偁','宋','宋诗','song-poetry','','[]','元老留司卧雒陽，諫官通理輟鴛行。',64,'全唐诗/poet.song.3000.json','["元老留司卧雒陽，諫官通理輟鴛行。", "仲宣舊佐紅蓮幕，裴度新開綠野堂。", "幾處古碑停馬讀，到時春筍約僧嘗。", "香山居士真容在，爲我公餘奠一觴。"]'),
('1b33e054-013a-4e3f-8f74-72acfc7d7ae1','賀范舍人再入西掖','王禹偁','宋','宋诗','song-poetry','','[]','再入承明舊直廬，腰間仍得佩金魚。',64,'全唐诗/poet.song.3000.json','["再入承明舊直廬，腰間仍得佩金魚。", "重批漢武求賢詔，曾上東方自薦書。", "紅藥篇章應感動，紫泥封檢未生疏。", "樊川杜曲休勞夢，日日延英侍玉除。"]'),
('7964ec51-0d2c-44b8-af5b-3c40fe1aaef5','閣下詠懷','王禹偁','宋','宋诗','song-poetry','','[]','正向承明戀直廬，年來華髮已侵梳。',64,'全唐诗/poet.song.3000.json','["正向承明戀直廬，年來華髮已侵梳。", "官清自比乘軒鶴，心小還同畏網魚。", "西掖永懷王閣老，北門堪歎扈尚書。", "會當辭祿東陵去，數畝瓜田一柄鋤。"]'),
('ada45faf-fb48-4493-abf3-ef5dcb4673cd','閣下暮春','王禹偁','宋','宋诗','song-poetry','','[]','詔書稀少日何長，閑枕通中睡一場。',32,'全唐诗/poet.song.3000.json','["詔書稀少日何長，閑枕通中睡一場。", "院吏報來丞相出，紫微花影上東廊。"]'),
('547d9b8b-c7f2-44b9-aa17-7a2a7880ad66','舍人院竹','王禹偁','宋','宋诗','song-poetry','','[]','封了詞頭遶砌行，此君相伴最多情。',32,'全唐诗/poet.song.3000.json','["封了詞頭遶砌行，此君相伴最多情。", "西垣不宿還堪恨，辜負夜窗風雨聲。"]'),
('30726961-ab96-4dfd-af5a-28892279512a','省中苦雨  其一','王禹偁','宋','宋诗','song-poetry','','[]','霏霏連晝復連宵，紅藥蒼苔也寂寥。',32,'全唐诗/poet.song.3000.json','["霏霏連晝復連宵，紅藥蒼苔也寂寥。", "唯有御溝堤畔柳，拂簷遮檻不勝嬌。"]'),
('2123ad1d-720d-48ff-976e-0f2b1d78ddd8','省中苦雨  其二','王禹偁','宋','宋诗','song-poetry','','[]','醉魂吟魄共悽悽，簷溜窗風冷切肌。',32,'全唐诗/poet.song.3000.json','["醉魂吟魄共悽悽，簷溜窗風冷切肌。", "階下怒蛙休跳躍，浮雲遮日不多時。"]'),
('8bf77eba-c170-490c-8a48-196a2b6ed16c','初出京過瓊林苑','王禹偁','宋','宋诗','song-poetry','','[]','忽憶今春暮，宮花照苑牆。',120,'全唐诗/poet.song.3000.json','["忽憶今春暮，宮花照苑牆。", "瓊林侍游宴，金口獨褒揚。", "立向勾陳內，宣來帝座傍。", "丁寧問年紀，委曲敘行藏。", "屏息聞天語，酡顔醉御觴。", "近臣多健羨，睿眷豈尋常。", "盛事誰能及，非才自不遑。", "厚恩難負荷，薄命果譸張。", "得罪縻山郡，携家出帝鄉。", "何時重到此，駐馬淚浪浪。"]'),
('cf8b580e-5f88-44c5-bd32-fa11871c4504','中牟縣旅舍喜同年高紳著作見訪','王禹偁','宋','宋诗','song-poetry','','[]','古縣日初沉，軺車忽見尋。',48,'全唐诗/poet.song.3000.json','["古縣日初沉，軺車忽見尋。", "不將遷客累，方認故人心。", "無酒銷寒漏，挑燈聽遠砧。", "郟郊千里路，並轡未妨吟。"]'),
('97d88f9d-1108-45a6-8c6e-c6e215bff7e8','鄭州與張秉監察聯句','王禹偁','宋','宋诗','song-poetry','','[]','函關秋霽雁初迴，六里商於曉色開。',32,'全唐诗/poet.song.3000.json','["函關秋霽雁初迴，六里商於曉色開。", "四皓有靈應笑我，謫官方始入山來。"]'),
('b27ef137-2733-4ed1-a794-dd11e8ce7382','滎陽懷古','王禹偁','宋','宋诗','song-poetry','','[]','紀信生降爲沛公，草荒孤壘想英風。',32,'全唐诗/poet.song.3000.json','["紀信生降爲沛公，草荒孤壘想英風。", "漢家青史緣何事，却道蕭何第一功。"]'),
('67996e63-2a0e-422b-b496-eeee8c39308e','過鴻溝','王禹偁','宋','宋诗','song-poetry','','[]','侯公緩頰太公歸，項籍何曾會戰機。',64,'全唐诗/poet.song.3000.json','["侯公緩頰太公歸，項籍何曾會戰機。", "只見鴻溝分兩處，不知垓下有重圍。", "危橋带雨無人過，敗葉隨風傍馬飛。", "半日垂鞭念前事，露莎霜樹映斜暉。"]'),
('359d9175-44fc-4bc4-8f02-3302561a09e6','旅次新安','王禹偁','宋','宋诗','song-poetry','','[]','遷客乍離羣，秋砧不忍聞。',48,'全唐诗/poet.song.3000.json','["遷客乍離羣，秋砧不忍聞。", "迴頭戀紅藥，失脚下青雲。", "尚假金貂冕，猶殘柱國勳。", "此身未敢死，會擬報明君。"]'),
('9dbfc131-7109-42a9-9766-c80b50683b3d','硤石縣旅舍','王禹偁','宋','宋诗','song-poetry','','[]','霜乾紅葉飛，遷客思凄凄。',48,'全唐诗/poet.song.3000.json','["霜乾紅葉飛，遷客思凄凄。", "處險人垂癭，登山馬跙蹄。", "籬荒蛬韻苦，雲凍雁行低。", "此夕應無寐，何煩報曉雞。"]'),
('fa042c32-752e-4ce8-8cf3-2d70eabe0e05','稠桑坡車覆','王禹偁','宋','宋诗','song-poetry','','[]','稠桑坡險忽摧車，悔戴儒冠出敝廬。',32,'全唐诗/poet.song.3000.json','["稠桑坡險忽摧車，悔戴儒冠出敝廬。", "已被文章相錯誤，謫官猶載一車書。"]'),
('243284f2-54b3-4dc7-bd95-6eda5a5a0f9d','閿鄉旅夜','王禹偁','宋','宋诗','song-poetry','','[]','行盡兩京路，將登六里山。',24,'全唐诗/poet.song.3000.json','["行盡兩京路，將登六里山。", "全家空洒淚，知是幾時還。"]'),
('4063a5de-8718-4979-b69b-2a3e8a753c40','初入山聞提壺鳥','王禹偁','宋','宋诗','song-poetry','','[]','遷客由來長合醉，不煩幽鳥道提壺。',32,'全唐诗/poet.song.3000.json','["遷客由來長合醉，不煩幽鳥道提壺。", "商州未是無人境，一路山村有酒沽。"]'),
('c9d2320d-5b06-492c-ae85-c978b8469665','聽泉','王禹偁','宋','宋诗','song-poetry','','[]','平生詩句多山水，謫宦誰知是勝遊。',32,'全唐诗/poet.song.3000.json','["平生詩句多山水，謫宦誰知是勝遊。", "南下閿鄉三百里，泉聲相送到商州。"]'),
('aaf6c1b0-54e0-4090-b892-ebfb22f2cce2','初到商州館于妙高禪院佛屋壁上見草聖數行讀之乃數年前應制所作皇帝試貢士歌追思前事感而成章','王禹偁','宋','宋诗','song-poetry','','[]','應制詩篇對玉除，是誰傳寫到商於。',64,'全唐诗/poet.song.3000.json','["應制詩篇對玉除，是誰傳寫到商於。", "昔從蓂莢階前作，今向蓮花座畔書。", "商嶺未甘隨綺季，漢庭曾忝用相如。", "山僧莫怪頻垂淚，乍別承明舊直廬。"]'),
('e21bfada-f9ca-46a2-9d83-48453a5dbf98','謫居感事','王禹偁','宋','宋诗','song-poetry','','[]','遷謫獨熙熙，襟懷自坦夷。',288,'全唐诗/poet.song.3000.json','["遷謫獨熙熙，襟懷自坦夷。", "孤寒明主信，清直上天知。", "消息還依道，生涯只在詩。", "惟當諭山水，詎敢詠江蘺。", "偶歎勞生事，因思志學時。", "讀書方睹奧，下筆便搜奇。", "賦格欺鸚鵡，儒冠薄鵔鸃。", "耕桑都不事，園井未曾窺。", "必欲縑緗富，寧教杼軸紕。", "光陰常矻矻，交友盡偲偲。", "步驟依班馬，根源法孔姬。", "收螢秋不倦，刻鵠夜忘疲。", "流輩多相許，時賢亦見推。", "叨榮偕計吏，濫吹謁春司。", "僕瘦途中病，馿寒雪裏騎。", "空拳入場屋，拭目看京師。", "技癢初調箭，鋒銛欲試錐。", "甲科登漢制，內殿識堯眉。", "數刻愁晡矣，三題亦勉之。", "先鳴輸俊彥，上第遂參差。", "罷舉身何託，還家命自奇。", "唯慙親倚戶，敢望嫂停炊。", "竭力求甘旨，終朝走路歧。", "貪希仲由來，多廢董生帷。"]'),
('baee40a5-679e-4c7f-ac88-f4f6e5eeb6b8','弊帷詩','王禹偁','宋','宋诗','song-poetry','','[]','謫宦那堪歎弊帷，承明寓直數年騎。',64,'全唐诗/poet.song.3000.json','["謫宦那堪歎弊帷，承明寓直數年騎。", "滿階紅藥曾嘶處，六里青山忽斃時。", "駿骨欲埋金價直，的顱猶愛雪離披。", "貳車謾道貂冠貴，從此徒行奉一麾。"]'),
('bc02320d-10a1-492c-9a46-0726b311f002','和馮中允仙娥峰','王禹偁','宋','宋诗','song-poetry','','[]','熊耳如當出檻熊，仙姿孤秀壓諸峰。',64,'全唐诗/poet.song.3000.json','["熊耳如當出檻熊，仙姿孤秀壓諸峰。", "採芝逋客憐貞質，化石佳人妬麗容。", "身上霓衣慵整頓，天邊華蓋會裁縫。", "嫦娥月裏休相笑，萬古應無竊藥蹤。"]'),
('1e7f2b36-a170-46de-9fc8-913bcbfa463e','龍鳳茶','王禹偁','宋','宋诗','song-poetry','','[]','樣標龍鳳號題新，賜得還因作近臣。',64,'全唐诗/poet.song.3000.json','["樣標龍鳳號題新，賜得還因作近臣。", "烹處豈期商嶺外，碾時空想建溪春。", "香於九畹芳蘭氣，圓似三秋皓月輪。", "愛惜不嘗惟恐盡，除將供養白頭親。"]'),
('5e331333-593c-404f-a430-913069a70d07','元日作','王禹偁','宋','宋诗','song-poetry','','[]','獻歲在商州，依然想舊遊。',48,'全唐诗/poet.song.3000.json','["獻歲在商州，依然想舊遊。", "前年捧玉冊，此日對珠旒。", "御酒堯樽畔，仙韶舜殿頭。", "自慚非賈傅，宣室詎重求。"]'),
('deb3c0de-dde3-46aa-a332-e8dc8597ddb4','急就章','王禹偁','宋','宋诗','song-poetry','','[]','賜來三載錦囊盛，今日重看倍覺榮。',32,'全唐诗/poet.song.3000.json','["賜來三載錦囊盛，今日重看倍覺榮。", "元白當時皆謫宦，不聞將得御書行。"]'),
('0de85c04-e695-4a5d-96db-be24181f1815','御書錢','王禹偁','宋','宋诗','song-poetry','','[]','謫官無俸突無烟，惟擁琴書盡日眠。',32,'全唐诗/poet.song.3000.json','["謫官無俸突無烟，惟擁琴書盡日眠。", "還有一般勝趙壹，囊中猶貯御書錢。"]'),
('98cd9eb6-61aa-4cae-b3b3-12d3ff72bcf7','上元夜作','王禹偁','宋','宋诗','song-poetry','','[]','去年正月十五夜，乾元門上奉乘輿。',64,'全唐诗/poet.song.3000.json','["去年正月十五夜，乾元門上奉乘輿。", "今年正月十五夜，商洛郡中爲貳車。", "謫宦門欄偏冷落，山城燈火苦蕭疏。", "爐灰畫盡不成寐，頼有逍遥一帙書。"]'),
('5f595b84-abcd-426e-bad9-99db9a51111a','仙娥峰','王禹偁','宋','宋诗','song-poetry','','[]','窈窕奇峰疊古苔，望秦嶺外勢徘徊。',64,'全唐诗/poet.song.3000.json','["窈窕奇峰疊古苔，望秦嶺外勢徘徊。", "巨靈非疋休期刻，毛女爲鄰合往來。", "傅粉微茫春雪在，墮鬟浮動曉雲開。", "好邀上雒王常侍，時就巖前飲一盃。"]'),
('5c4826c5-3318-44cb-9dc2-24e50182f62b','遊仙娥峰後戲題','王禹偁','宋','宋诗','song-poetry','','[]','爲愛一峰形窈窕，豈辭十里路崎嶇。',32,'全唐诗/poet.song.3000.json','["爲愛一峰形窈窕，豈辭十里路崎嶇。", "誰知不似陽臺女，別後經宵夢也無。"]'),
('42852766-ec7d-4bff-992b-07220a389297','上寺留題','王禹偁','宋','宋诗','song-poetry','','[]','松杉疏瘦簇山根，樓殿參差對郭門。',64,'全唐诗/poet.song.3000.json','["松杉疏瘦簇山根，樓殿參差對郭門。", "不惜馬蹄來北寺，爲憐熊耳在西軒。", "雲生石砌摇寒影，泉汲銅瓶露凍痕。", "遷客頻來何所得，一叢修竹拂吟魂。"]'),
('d01083d9-f6e6-4d97-804b-f2fa0f577a04','對雪感懷呈翟使君馮中允同年','王禹偁','宋','宋诗','song-poetry','','[]','歲暮山城雪，民和歲有秋。',288,'全唐诗/poet.song.3000.json','["歲暮山城雪，民和歲有秋。", "深聞五袴詠，聊減貳車愁。", "凌亂藏溪寺，霏微洒郡樓。", "凍宜粘酒旆，香好試茶甌。", "逐吹殊無定，連宵勢未休。", "仙娥低粉面，熊耳壓峰頭。", "樹老花重發，川長縞不收。", "平沉採芝洞，深鎖避賢郵。", "麋鹿全迷逕，鷹鸇不下鞲。", "夜村埋古屋，丹水咽寒流。", "上洛城中客，梁園日下州。", "前年直綸閣，臘月奉宸遊。", "六出寒光亂，重瞳喜氣浮。", "催班臨秘殿，稱賀拱凝旒。", "漠漠籠天仗，輕輕落御溝。", "瑶池同皎潔，珠箔助颼飀。", "民有豐年望，君無旰食憂。", "佩垂延喜玉，服曜吉光裘。", "雞樹令開宴，鴛行許命儔。", "千鍾方灧灧，三爵未油油。", "舉白朱顔凝，飛文彩筆抽。", "傳宣須盡醉，御札遣冥搜。", "晚出蒼龍闕，驕馳紫燕騮。", "自慚生草澤，人指在蓬丘。"]'),
('7d4f92f8-418d-48b0-990f-93d90e5fd5fc','遊四皓廟','王禹偁','宋','宋诗','song-poetry','','[]','修篁瑟瑟石磷磷，去謁荒祠不厭頻。',64,'全唐诗/poet.song.3000.json','["修篁瑟瑟石磷磷，去謁荒祠不厭頻。", "四皓古來無事客，貳車今世最閑人。", "紫芝欲採非仙骨，紅藥曾題是近臣。", "一奠村醪還獨酌，滿軒松雪照吟身。"]'),
('aecf8fde-ece0-4817-a6c5-4cf606cf5214','商山','王禹偁','宋','宋诗','song-poetry','','[]','六百里巉巖，嵐光霽後添。',144,'全唐诗/poet.song.3000.json','["六百里巉巖，嵐光霽後添。", "經年吟未得，盡日看無厭。", "僧舍青當檻，人家翠滿簷。", "氣蒸丹水碧，脉潤紫芝甜。", "嶺礙翻雲鶻，峰遮落海蟾。", "澗深春有凍，影闊夏無炎。", "勢鬭嵩并華，名欺霍與灊。", "石危蹲虎脚，松老咤龍髯。", "曉榻便欹枕，晴樓懶下簾。", "未能棲岫幌，猶道佐彤襜。", "望久衣襟濕，登多屐齒粘。", "何當隨四皓，深隠避猜嫌。"]'),
('ef9943dd-c6d1-4f27-8ffc-65293558b288','丹水','王禹偁','宋','宋诗','song-poetry','','[]','瑟瑟復潺潺，朝宗去不還。',144,'全唐诗/poet.song.3000.json','["瑟瑟復潺潺，朝宗去不還。", "和雲歸漢浦，噴雪下商山。", "影浸仙娥面，波涵織女鬟。", "飲猿清滿掬，渡鹿冷侵斑。", "北潤深通洛，東犇嶮叩關。", "灌園縈似带，漕磑曲如環。", "夜枕驚幽夢，秋汀照病顔。", "玉膏分地脉，銀漢落人寰。", "漱石藏青鯉，崩沙聚白鷳。", "村橋微雨後，岸樹夕陽間。", "翠漲新萍綠，紅浮敗葉殷。", "貳車時濯足，來伴釣翁閑。"]'),
('4af96bfd-d386-4978-9c9d-7fdb30204b82','歲暮感懷貽馮同年中允  其一','王禹偁','宋','宋诗','song-poetry','','[]','謫宦商於郡，閑門車馬稀。',48,'全唐诗/poet.song.3000.json','["謫宦商於郡，閑門車馬稀。", "塵侵書命筆，香散入朝衣。", "燒盡峰巒出，霜晴木葉飛。", "夜來天欲雪，寒夢不成歸。"]'),
('1b701107-0fa1-4d8c-9aa3-a10b35498f04','歲暮感懷貽馮同年中允  其二','王禹偁','宋','宋诗','song-poetry','','[]','歲暮客商山，謫居多晝眠。',48,'全唐诗/poet.song.3000.json','["歲暮客商山，謫居多晝眠。", "夢迴紅藥樹，身落紫微天。", "不得親公事，如何望俸錢。", "荒城共誰語，除却訪同年。"]'),
('94c75036-affa-448b-b6e9-b054fc6c6e2c','歲暮感懷貽馮同年中允  其三','王禹偁','宋','宋诗','song-poetry','','[]','謫居京信斷，歲暮更凄凉。',48,'全唐诗/poet.song.3000.json','["謫居京信斷，歲暮更凄凉。", "郡僻青山合，官閑白日長。", "燒烟侵寺舍，林雪照街坊。", "爲有遷鶑侶，詩情不敢忘。"]'),
('d11aaa84-94a7-4350-b49e-b78cc39c5544','畬田詞  其一','王禹偁','宋','宋诗','song-poetry','','[]','大家齊力劚孱顔，耳聽田歌手莫閑。',32,'全唐诗/poet.song.3000.json','["大家齊力劚孱顔，耳聽田歌手莫閑。", "各願種成千百索，豆萁禾穗滿青山。"]'),
('d89d4461-8dcf-4e1a-98b1-b167b28133e0','畬田詞  其二','王禹偁','宋','宋诗','song-poetry','','[]','殺盡雞豚喚劚畲，由來遞互作生涯。',32,'全唐诗/poet.song.3000.json','["殺盡雞豚喚劚畲，由來遞互作生涯。", "莫言火種無多利，禾樹明年似亂麻。"]'),
('1b74e215-877f-400e-bd8a-dcdba3366966','畬田詞  其三','王禹偁','宋','宋诗','song-poetry','','[]','鼓聲獵獵酒醺醺，斫上高山入亂雲。',32,'全唐诗/poet.song.3000.json','["鼓聲獵獵酒醺醺，斫上高山入亂雲。", "自種自收還自足，不知堯舜是吾君。"]'),
('e1dd0435-1013-49e8-98e1-62af7db41184','畬田詞  其四','王禹偁','宋','宋诗','song-poetry','','[]','北山種了種南山，相助刀耕豈有偏。',32,'全唐诗/poet.song.3000.json','["北山種了種南山，相助刀耕豈有偏。", "願得人間皆似我，也應四海少荒田。"]'),
('572fd6fb-06e7-4523-9571-90039fff5c5c','畬田詞  其五','王禹偁','宋','宋诗','song-poetry','','[]','畬田鼓笛樂熙熙，空有歌聲未有詞。',32,'全唐诗/poet.song.3000.json','["畬田鼓笛樂熙熙，空有歌聲未有詞。", "從此商於爲故事，滿山皆唱舍人詩。"]'),
('eafd1e4c-debe-430b-86d7-f5fe8a6d6375','雪後登靈果寺閣','王禹偁','宋','宋诗','song-poetry','','[]','雪引詩情不敢慵，來登高閣犯晨鐘。',32,'全唐诗/poet.song.3000.json','["雪引詩情不敢慵，來登高閣犯晨鐘。", "山僧莫怪多時望，玉立南山萬萬峰。"]'),
('74c497c5-c32f-46fd-8cb4-9fe381a622db','獨遊南靜川','王禹偁','宋','宋诗','song-poetry','','[]','高車嶺上無人見，南靜川中信馬行。',32,'全唐诗/poet.song.3000.json','["高車嶺上無人見，南靜川中信馬行。", "多謝仙娥相管顧，遠擎松雪助詩情。"]'),
('394c0b5a-e97c-44af-8dcd-95a5236a6a37','賀畢翰林','王禹偁','宋','宋诗','song-poetry','','[]','聞步花磚喜復悲，所悲君較十年遲。',64,'全唐诗/poet.song.3000.json','["聞步花磚喜復悲，所悲君較十年遲。", "銀臺曉入批丹詔，銅鏡秋開鑷白髭。", "宮錦細袍宣與著，內閑驕馬賜來騎。", "家門記得咸通事，莫忘論兵夜召時。"]'),
('a80be516-1d67-44e1-9c5a-ad78c3299b55','賀三舍人新入西掖','王禹偁','宋','宋诗','song-poetry','','[]','紫微新命舊交遊，報到商於寂寞州。',64,'全唐诗/poet.song.3000.json','["紫微新命舊交遊，報到商於寂寞州。", "天上共分三字貴，山中全減貳車愁。", "拋離紅藥心無恨，彈拂金貂舞不休。", "最喜吾家有餘慶，鳳毛還直鳳池頭。"]'),
('aa4c78fe-29f6-48fc-ad2e-a13036b8fb88','送舍弟赴舉因寄兩制諸大僚','王禹偁','宋','宋诗','song-poetry','','[]','堂上尊親鶴髮垂，十年祿仕不相離。',64,'全唐诗/poet.song.3000.json','["堂上尊親鶴髮垂，十年祿仕不相離。", "何期膝下承顔日，却是山中謫宦時。", "未有重茵如子路，空披綵服學嬰兒。", "全家送爾隨鄉薦，試向朝端獻此詩。"]'),
('dc24c512-ee31-440b-9a24-239570031335','商山海棠','王禹偁','宋','宋诗','song-poetry','','[]','錦里名雖盛，商山艷更繁。',240,'全唐诗/poet.song.3000.json','["錦里名雖盛，商山艷更繁。", "別疑天與態，不稱土生根。", "淺著紅蘭染，深于絳雪噴。", "待開先釀酒，怕落預呼魂。", "春裏無勍敵，花中是至尊。", "桂須辭月窟，桃合避仙源。", "浮動冠頻側，霓裳袖忽翻。", "望夫臨水石，窺客出牆垣。", "贈別難饒柳，忘憂肯讓萱。", "輕輕飛燕舞，脈脈息媯言。", "蕙陋虛侵徑，梨凡浪占園。", "論心留蝶宿，低面厭鶑喧。", "不忝神仙品，何辜造化恩。", "自期栽御苑，誰使擲山村。", "綺里荒祠畔，仙娥古洞門。", "烟愁思舊夢，雨泣怨新婚。", "畫恐明妃恨，移同卓氏奔。", "祇教三月見，不得四時存。", "繡被堆籠勢，臙脂浥淚痕。", "貳車春未去，應得伴芳罇。"]'),
('e8a5cabd-2df6-49fd-b29a-452802e5e329','翰林畢學士寄示醫癭藥方因題四韻兼簡兩制諸知','王禹偁','宋','宋诗','song-poetry','','[]','預憂囊癭病龍鍾，乞得仙方便有功。',64,'全唐诗/poet.song.3000.json','["預憂囊癭病龍鍾，乞得仙方便有功。", "縱免項如樗里子，也應頭似夏黄公。", "西暉亭下峰巒碧，南靜川中木葉紅。", "盡是貳車堪醉處，春來唯恐酒罇空。"]'),
('78371130-0666-4d52-be88-795478ecd497','內翰畢學士外制柴舍人故兵部閣老王公之門生又與第五廳舍人同在兩制追思餘慶因賦短章寄于三君子','王禹偁','宋','宋诗','song-poetry','','[]','掌貢司言耀聖朝，宦途屯否數難逃。',64,'全唐诗/poet.song.3000.json','["掌貢司言耀聖朝，宦途屯否數難逃。", "雄文自貯胸中甲，直氣誰防笑裏刀。", "黄閣不登名甚屈，紫垣終老道彌高。", "君看身後榮多少，兩制門生伴鳳毛。"]'),
('e96908ab-f0ea-4599-bd11-ef5f721e8af5','賀柴舍人新入西掖','王禹偁','宋','宋诗','song-poetry','','[]','早折蟾宮第一枝，綸闈恩命苦何遲。',64,'全唐诗/poet.song.3000.json','["早折蟾宮第一枝，綸闈恩命苦何遲。", "久爲俗吏殊無味，合掌王言亦有時。", "好繼忠州文最盛，應嫌長慶格猶卑。", "他年莫忘中吳宰，六里山前歌紫芝。"]'),
('36937792-102e-4d09-ae93-11cc7207d576','歲除日同年馮中允携觴見訪因而沉醉病酒三日醒而偶題','王禹偁','宋','宋诗','song-poetry','','[]','除夜渾疑便白頭，携壺相勸醉方休。',64,'全唐诗/poet.song.3000.json','["除夜渾疑便白頭，携壺相勸醉方休。", "敢辭枕上三朝卧，且免燈前一夕愁。", "薄命我甘離鳳閣，多才君亦滯龍樓。", "相逢不盡杯中物，何以支當寂寞州。"]'),
('c1d528a9-2cdb-44bc-88ab-baa60c21adca','得昭文李學士書報以二絕  其一','王禹偁','宋','宋诗','song-poetry','','[]','謫居不敢詠江蘺，日永門閑何所爲。',32,'全唐诗/poet.song.3000.json','["謫居不敢詠江蘺，日永門閑何所爲。", "爲謝昭文李學士，勸教枕藉樂天詩。"]'),
('8d68a18d-287a-447f-abd0-96f7b75d6e65','得昭文李學士書報以二絕  其二','王禹偁','宋','宋诗','song-poetry','','[]','左宦寂寥惟上洛，窮愁依約似長沙。',32,'全唐诗/poet.song.3000.json','["左宦寂寥惟上洛，窮愁依約似長沙。", "樂天詩什雖堪讀，奈有春深遷客家。"]'),
('0e5e87fc-8784-425e-ba9a-8a5a9f9ef3d9','南靜川野桃花下獨酌因簡同年馮中允','王禹偁','宋','宋诗','song-poetry','','[]','野桃無主滿山隈，遷客携觴獨自來。',64,'全唐诗/poet.song.3000.json','["野桃無主滿山隈，遷客携觴獨自來。", "盡日馨香留我醉，每春顔色爲誰開。", "枝穿綠竹渾疑畫，片落丹河去不迴。", "待約同年一攀折，便如劉阮到天台。"]'),
('7e24935c-9225-4a1b-9e59-aa8c64168619','放言  其一','王禹偁','宋','宋诗','song-poetry','','[]','誰信人間是與非，進須行道退忘機。',64,'全唐诗/poet.song.3000.json','["誰信人間是與非，進須行道退忘機。", "卦逢大壯羝羊困，鄉入無何蛺蝶飛。", "澤畔衣裳蘭作佩，山中生計竹爲扉。", "饑腸已共夷齊約，一曲高歌去採薇。"]'),
('31ad5180-000f-46ed-b565-a448fb0a2268','放言  其二','王禹偁','宋','宋诗','song-poetry','','[]','榮枯禍福轉如輪，幽暗難欺有鬼神。',64,'全唐诗/poet.song.3000.json','["榮枯禍福轉如輪，幽暗難欺有鬼神。", "天上若無司報者，世間爭向不平人。", "夏蟲莫怪冰壺色，秋隼休猜月窟身。", "吾道斯文如未喪，且憑方寸託穹旻。"]'),
('7fba85ff-4ef3-486b-9483-ea6e8fa651f5','放言  其三','王禹偁','宋','宋诗','song-poetry','','[]','賢人雖學心無悶，君子須知道自消。',64,'全唐诗/poet.song.3000.json','["賢人雖學心無悶，君子須知道自消。", "德似仲尼悲鳳鳥，聖如姬旦賦鴟鴞。", "看松好待嚴霜降，試玉宜將烈火燒。", "青女祝融如不黨，願分頑石與山苗。"]'),
('77f08fad-46dd-445f-ad48-c3889bce186d','放言  其四','王禹偁','宋','宋诗','song-poetry','','[]','人生唯問道如何，得喪升沉總是虛。',64,'全唐诗/poet.song.3000.json','["人生唯問道如何，得喪升沉總是虛。", "寧可飛鴻隨四皓，未能魚腹葬三閭。", "傅巖偶夢誰調鼎，彭澤高歌自荷鋤。", "不向世間爭窟穴，蝸牛到處是吾廬。"]'),
('142f08b3-174e-4b95-9461-8e4a143f91e6','放言  其五','王禹偁','宋','宋诗','song-poetry','','[]','靜算人間事偶然，窮通未必在穹玄。',64,'全唐诗/poet.song.3000.json','["靜算人間事偶然，窮通未必在穹玄。", "關從白馬欺來度，赦被青蠅暗裏傳。", "禁樹罷吟紅爛漫，江蘺且詠綠芊綿。", "放言詩什誰堪贈，焚贈微之與樂天。"]'),
('f12db36b-d4bb-45e9-8025-c72e2e963d96','寄獻僕射相公  其一','王禹偁','宋','宋诗','song-poetry','','[]','三朝文匠百僚師，再秉洪鈞七政齊。',64,'全唐诗/poet.song.3000.json','["三朝文匠百僚師，再秉洪鈞七政齊。", "一道白麻來玉署，兩條紅燭上沙堤。", "池波尚浴當時鳳，省樹猶存舊日雞。", "鑪冶正開無棄物，應憐折劍在塵泥。"]'),
('157d7392-276b-4736-94e9-38ac76bdb0ec','寄獻僕射相公  其二','王禹偁','宋','宋诗','song-poetry','','[]','聖君宵旰念生民，重命甘盤秉國鈞。',64,'全唐诗/poet.song.3000.json','["聖君宵旰念生民，重命甘盤秉國鈞。", "引馬但傳三刻漏，喘牛休問四時春。", "羹和舊鼎黄金鉉，雪壓新堤白玉塵。", "應念前年獻詩客，謫官無俸不勝貧。"]'),
('c0d22508-3ace-42f6-b10e-e97efccd3bbb','寄馮舍人','王禹偁','宋','宋诗','song-poetry','','[]','轉輪爭合滯才華，急詔重乘上漢查。',64,'全唐诗/poet.song.3000.json','["轉輪爭合滯才華，急詔重乘上漢查。", "繼我已吟紅藥樹，勸君曾賦海棠花。", "詞隨健筆光綸誥，詩落成都燦綺霞。", "應笑同時東觀客，商於憔悴似長沙。"]'),
('d27fa220-d0ac-4038-9a05-1d976b24a829','迴襄陽周奉禮同年因題紙尾','王禹偁','宋','宋诗','song-poetry','','[]','武關西畔路巉巖，兩月勞君寄兩緘。',64,'全唐诗/poet.song.3000.json','["武關西畔路巉巖，兩月勞君寄兩緘。", "鏡裏想添新白髮，篋中猶貯舊青衫。", "扶頭酒好無辭醉，縮項魚多且放饞。", "譬似元和張太祝，十年不改舊官銜。"]'),
('28aa259d-9462-4ce2-8686-11ac81993694','清明日獨酌','王禹偁','宋','宋诗','song-poetry','','["\u8c2a\u5c45", "\u6e05\u660e\u8282", "\u65e0\u5948"]','一郡官閑唯副使，一年冷節是清明。',64,'全唐诗/poet.song.3000.json','["一郡官閑唯副使，一年冷節是清明。", "春來春去何時盡，閑恨閑愁觸處生。", "漆燕黄鸝誇舌健，柳花榆莢鬭身輕。", "脫衣換得商山酒，笑把離騷獨自傾。"]'),
('faad82ff-7ea3-4ca8-ae30-80405eb18f29','寒食','王禹偁','宋','宋诗','song-poetry','','[]','今年寒食在商山，山裏風光亦可憐。',64,'全唐诗/poet.song.3000.json','["今年寒食在商山，山裏風光亦可憐。", "稚子就花拈蛺蝶，人家依樹繫鞦韆。", "郊原曉綠初經雨，巷陌春陰乍禁烟。", "副使官閑莫惆悵，酒錢猶有撰碑錢。"]'),
('724b66a5-338e-442b-96e9-0685a7198f3c','春日登樓','王禹偁','宋','宋诗','song-poetry','','[]','紅桃飛盡綠楊深，獨倚危樓半日吟。',64,'全唐诗/poet.song.3000.json','["紅桃飛盡綠楊深，獨倚危樓半日吟。", "六里山川多逐客，貳車官職是籠禽。", "蓬霑殘雪經秋鬢，葵隔浮雲向日心。", "身世榮衰不能算，且傾村酒沃愁襟。"]'),
('33878507-6ad0-4c70-8283-a6fa86b97f73','山僧雨中送牡丹','王禹偁','宋','宋诗','song-poetry','','[]','數枝香带雨霏霏，雨裏携來叩竹扉。',32,'全唐诗/poet.song.3000.json','["數枝香带雨霏霏，雨裏携來叩竹扉。", "擬戴却休成悵望，御園曾插滿頭歸。"]'),
('ef945fbc-2f2b-43a3-8896-d413e2d4c993','春居雜興  其一','王禹偁','宋','宋诗','song-poetry','','[]','兩株桃杏映籬斜，粧點商山副使家。',32,'全唐诗/poet.song.3000.json','["兩株桃杏映籬斜，粧點商山副使家。", "何事春風容不得，和鶑吹折數枝花。"]'),
('f1c631c8-f8ef-413a-80a5-ecdbe4ad95d9','春居雜興  其二','王禹偁','宋','宋诗','song-poetry','','[]','春雲如獸復如禽，日照風吹淺又深。',32,'全唐诗/poet.song.3000.json','["春雲如獸復如禽，日照風吹淺又深。", "誰道無心便容與，亦同翻覆小人心。"]'),
('76b19ebf-11a8-4451-9e57-b301f3ecb579','春居雜興  其三','王禹偁','宋','宋诗','song-poetry','','[]','閑寫新詩十數篇，曉來鋪向竹窗前。',32,'全唐诗/poet.song.3000.json','["閑寫新詩十數篇，曉來鋪向竹窗前。", "無端燕子欺人睡，故落春泥污綵箋。"]'),
('0122467a-8439-4002-a4b7-88a2536e6d5e','春居雜興  其四','王禹偁','宋','宋诗','song-poetry','','[]','一夜春雷百蟄空，山家籬落起蛇蟲。',32,'全唐诗/poet.song.3000.json','["一夜春雷百蟄空，山家籬落起蛇蟲。", "無端蚯蚓爭頭角，觸破莓苔氣似虹。"]'),
('7993a7a4-8255-4025-822f-8216484ad3a9','登郡南樓望山感而有作','王禹偁','宋','宋诗','song-poetry','','[]','西接藍田東武關，有唐名郡數商顔。',64,'全唐诗/poet.song.3000.json','["西接藍田東武關，有唐名郡數商顔。", "二千石盡非吾道，一百年來負此山。", "重疊曉嵐新雨後，參差春雪夕陽間。", "唯供遷客風騷興，醉望吟看不暫閑。"]'),
('aa23d631-e908-498e-b1ff-7c77ed6826dc','讀史記列傳','王禹偁','宋','宋诗','song-poetry','','[]','西山薇蕨蜀山銅，可見夷齊與鄧通。',32,'全唐诗/poet.song.3000.json','["西山薇蕨蜀山銅，可見夷齊與鄧通。", "佞倖聖賢俱餓死，若無史筆等頭空。"]'),
('fd3b34f9-e5d4-4400-be6c-95d24c71f3c9','睡','王禹偁','宋','宋诗','song-poetry','','[]','此境一何醇，熙熙別得春。',144,'全唐诗/poet.song.3000.json','["此境一何醇，熙熙別得春。", "有聲皆俗格，無夢是天真。", "壁上登山屐，床頭漉酒巾。", "輕輕龜喘息，苒苒蝶精神。", "滯寂通禪理，無何等道人。", "曲肱高勝枕，藉草軟于茵。", "吟苦魂初瞑，盃酣味更珍。", "覺知身是幻，靜與死爲鄰。", "酷恨巢簷燕，生憎欵戶賓。", "功成歸展轉，先兆自嚬呻。", "不入榮名客，還宜放逐臣。", "東窗一丈日，且作自由身。"]'),
('06c39f8d-8bff-44a9-80a2-99a3ddf91605','送秦供奉自商州使鄂渚','王禹偁','宋','宋诗','song-poetry','','[]','携家晝錦行，山驛接江城。',48,'全唐诗/poet.song.3000.json','["携家晝錦行，山驛接江城。", "使是皇華貴，人還故國榮。", "離筵青杏小，別夜子規鳴。", "鸚鵡洲邊宿，無忘吊禰衡。"]'),
('d42fd266-b634-4919-b62a-61b36424ef88','聞進士孫何及第因寄','王禹偁','宋','宋诗','song-poetry','','[]','昨朝邸吏報商山，聞道孫生得狀元。',32,'全唐诗/poet.song.3000.json','["昨朝邸吏報商山，聞道孫生得狀元。", "爲賀聖朝文物盛，喜於初入紫微垣。"]'),
('63979f11-0bf6-41b4-8011-4c8d829e9b73','哭同年羅著作五首  其一','王禹偁','宋','宋诗','song-poetry','','[]','宿草離披淚滿衫，孤墳遥想帝城南。',32,'全唐诗/poet.song.3000.json','["宿草離披淚滿衫，孤墳遥想帝城南。", "天生賈誼成何事，祇得人間三十三。"]'),
('5a1065a2-2e62-427b-8c66-9a1d1191682f','哭同年羅著作五首  其二','王禹偁','宋','宋诗','song-poetry','','[]','一枝丹桂謾成名，一片緋衫未是榮。',32,'全唐诗/poet.song.3000.json','["一枝丹桂謾成名，一片緋衫未是榮。", "頼有遺文在東觀，直應千載氣如生。"]'),
('a608ea9c-9d9a-40e3-8803-9a31e35fcfde','哭同年羅著作五首  其三','王禹偁','宋','宋诗','song-poetry','','[]','荒凉故宅何人住，寂寞孀妻即日還。',32,'全唐诗/poet.song.3000.json','["荒凉故宅何人住，寂寞孀妻即日還。", "一歲嬰兒安健否，巨源雖在謫深山。"]'),
('db41f0e9-59bb-4c9d-a364-1823a44fdf4f','哭同年羅著作五首  其四','王禹偁','宋','宋诗','song-poetry','','[]','生死雖殊道義存，曉來襟袖有啼痕。',32,'全唐诗/poet.song.3000.json','["生死雖殊道義存，曉來襟袖有啼痕。", "只應知我方憔悴，時向商山入夢魂。"]'),
('47bf83bc-289f-443c-971e-a925e394066f','哭同年羅著作五首  其五','王禹偁','宋','宋诗','song-poetry','','[]','同試五題爲縣吏，共求三字作詞臣。',32,'全唐诗/poet.song.3000.json','["同試五題爲縣吏，共求三字作詞臣。", "西垣謫宦何須恨，若比羅三是幸人。"]'),
('46fefb22-8ba9-42ba-bd22-86bb4ca7b5c6','西暉亭','王禹偁','宋','宋诗','song-poetry','','[]','孤亭疊嶂東，宛是古屏風。',144,'全唐诗/poet.song.3000.json','["孤亭疊嶂東，宛是古屏風。", "每到天將暮，渾疑日再中。", "餘霞猶散綺，新月已張弓。", "一水漪漣媚，千巖木葉紅。", "玳筵何烜赫，火宅忽牢籠。", "隙晃歸巢燕，簷拖截澗虹。", "果迷丹橘熟，洞訝赤城通。", "似燒連松塢，如斑染竹叢。", "近邀青瑣客，來伴紫芝翁。", "望久情無倦，吟多興未窮。", "陽烏看黯黯，歸馬恨怱怱。", "會待長棲隠，青冥逐去鴻。"]'),
('0f1f3ae1-beae-4901-970c-8a732d26754e','謫居','王禹偁','宋','宋诗','song-poetry','','[]','親老復嬰孩，吾生自可哀。',48,'全唐诗/poet.song.3000.json','["親老復嬰孩，吾生自可哀。", "無田得歸去，有俸是嗟來。", "直道雖已矣，壯心猶在哉。", "端居寡儔侶，懷抱向誰開。"]'),
('accf7dc4-55fb-45ef-8473-a7823825a145','道服','王禹偁','宋','宋诗','song-poetry','','[]','楮冠布褐皂紗巾，曾忝西垣寓直人。',64,'全唐诗/poet.song.3000.json','["楮冠布褐皂紗巾，曾忝西垣寓直人。", "此際暫披因假日，如今長著見閑身。", "濯纓未識三湘水，漉酒空經六里春。", "不爲行香著朝服，貳車誰信舊詞臣。"]'),
('81b3ab1b-438c-4550-bbca-4e47d61d3e3d','寄題洛南秦供奉新樓','王禹偁','宋','宋诗','song-poetry','','[]','多羨新樓上，公餘寫望閑。',120,'全唐诗/poet.song.3000.json','["多羨新樓上，公餘寫望閑。", "數峰迷華岳，一面是商山。", "棋暗幽雲過，簷喧宿鳥還。", "萬重蒼翠裏，百尺泬寥間。", "嵐破分樵逕，沙明認釣灣。", "望秦晴矗矗，清洛夜潺潺。", "平遠長安道，微茫函谷關。", "吟哦生古意，圖畫寄朝班。", "何日隨高步，乘秋豁病顔。", "銷憂吾祖事，會待共躋攀。"]'),
('4f4fe282-e9f5-4a02-b926-461d9d47869f','獨酌自吟拙詩次吏報轉運使到郡戲而有作','王禹偁','宋','宋诗','song-poetry','','[]','日高睡足更何爲，數首新篇酒一巵。',32,'全唐诗/poet.song.3000.json','["日高睡足更何爲，數首新篇酒一巵。", "郡吏謾勞相告報，轉輸應不管吟詩。"]'),
('212ea944-c4ef-47a9-a1fe-263909ef370c','春遊南靜川','王禹偁','宋','宋诗','song-poetry','','[]','南過高車嶺，川原似掌平。',120,'全唐诗/poet.song.3000.json','["南過高車嶺，川原似掌平。", "峰巒開畫障，畎畝列棋枰。", "帝女柔桑綠，王孫野草生。", "提壺催我醉，戴勝勸人耕。", "商嶺堪携妓，丹河好濯纓。", "蓋圓松影密，鞭亂竹根獰。", "勃勃畬田氣，磷磷水磑聲。", "野桃誰是主，山鳥不知名。", "欲舞寧無蝶，思歌亦有鶑。", "官閑春日永，擔酒此中行。"]'),
('54459dab-d555-4af7-bdbe-6afb4306cfb3','南郊大禮詩  其一','王禹偁','宋','宋诗','song-poetry','','[]','聖君重卜祀南郊，仗用黄麾間白旄。',64,'全唐诗/poet.song.3000.json','["聖君重卜祀南郊，仗用黄麾間白旄。", "仙吹冷翻蒼玉佩，曉霞晴透絳紗袍。", "天開兜率齋宮靜，海湧蓬萊帳殿高。", "遷客生還知有望，商山不敢讀離騷。"]'),
('51132e51-8efe-475c-bfa3-77d4d5e295e5','南郊大禮詩  其二','王禹偁','宋','宋诗','song-poetry','','[]','百僚冠劍互珊珊，文物威蕤屬禮官。',64,'全唐诗/poet.song.3000.json','["百僚冠劍互珊珊，文物威蕤屬禮官。", "清漏宿齋宣祖廟，質明行事昊天壇。", "旌旗漠漠帷宮曉，星斗依依綵仗寒。", "腸斷商於左遷客，圓丘無分得榮觀。"]'),
('04ddf12c-aed2-45f1-b256-2d32488e30b8','南郊大禮詩  其三','王禹偁','宋','宋诗','song-poetry','','[]','嚴配郊丘展孝思，質文參酌禮無違。',64,'全唐诗/poet.song.3000.json','["嚴配郊丘展孝思，質文參酌禮無違。", "大羹味薄牲牷潔，至樂聲和鳳鳥飛。", "黄道月斜風細細，紫壇天曉露霏霏。", "可憐此夜商山客，畫盡爐灰淚滿衣。"]'),
('3c2357a9-555f-4618-9fd2-fbce50a1cd1d','南郊大禮詩  其四','王禹偁','宋','宋诗','song-poetry','','[]','綵城殘月带微霜，版奏中嚴夜未央。',64,'全唐诗/poet.song.3000.json','["綵城殘月带微霜，版奏中嚴夜未央。", "三獻欲終侵曙色，百神齊下散天香。", "珠旒微亂塤篪韻，柴燎輕籠劍佩光。", "此夕商山對何物，猿啼鳥哭樹蒼蒼。"]'),
('2dc4679a-914b-4286-bb49-e5ecc67ab4bb','南郊大禮詩  其五','王禹偁','宋','宋诗','song-poetry','','[]','嚴禋禮退一陽生，抃賀歡呼動四溟。',64,'全唐诗/poet.song.3000.json','["嚴禋禮退一陽生，抃賀歡呼動四溟。", "聖壽久長南至日，寶圖高大北辰星。", "九重城闕天將曙，百萬人家戶不扃。", "知有化工無棄物，海波分納一浮萍。"]'),
('5c42d13f-dfef-47bd-a25c-5884445f465b','南郊大禮詩  其六','王禹偁','宋','宋诗','song-poetry','','[]','乾元門上赭袍光，雉扇初開散御香。',64,'全唐诗/poet.song.3000.json','["乾元門上赭袍光，雉扇初開散御香。", "郊祀一千年運祚，赦書三萬里封疆。", "人間草木霑皇澤，天上咸韶送壽觴。", "惆悵昔年曾侍從，而今翻似鼠拖腸。"]'),
('08bfac58-6d4b-4651-8490-b0c7d35bcb2b','南郊大禮詩  其七','王禹偁','宋','宋诗','song-poetry','','[]','六街旌旆嚲虹蜺，仙仗參差羽衛齊。',64,'全唐诗/poet.song.3000.json','["六街旌旆嚲虹蜺，仙仗參差羽衛齊。", "千步廊前班振鷺，百尋竿上揭金雞。", "狴牢冷落停丹筆，郡國歡呼拆紫泥。", "鳳閣舊臣期赦宥，免教長似觸藩羝。"]'),
('3cb95dff-2bc7-4557-ba27-362c646c1a9c','南郊大禮詩  其八','王禹偁','宋','宋诗','song-poetry','','[]','千官雲擁御樓時，朝服紛紛換禮衣。',64,'全唐诗/poet.song.3000.json','["千官雲擁御樓時，朝服紛紛換禮衣。", "萬里梯航歸大國，一聲雷雨破圜扉。", "青蠅傳去人人喜，丹鳳銜來處處飛。", "收盡洛南遷客淚，全家潜望日邊歸。"]'),
('92f0c571-fbc3-46e7-b5c5-1402dde04871','南郊大禮詩  其九','王禹偁','宋','宋诗','song-poetry','','[]','綵雲隨步下乾元，雨露新恩洽普天。',64,'全唐诗/poet.song.3000.json','["綵雲隨步下乾元，雨露新恩洽普天。", "四輔首迎丹鳳詔，六師齊散廩犧錢。", "熙熙品物瞻堯日，習習薰風動舜絃。", "商洛貳車當此際，舊朝衣上淚潺湲。"]'),
('70806cac-f49f-4d5d-a39f-b063a263e189','南郊大禮詩  其一○','王禹偁','宋','宋诗','song-poetry','','[]','年來不見祀圜丘，謫宦携親歎白頭。',64,'全唐诗/poet.song.3000.json','["年來不見祀圜丘，謫宦携親歎白頭。", "作賦有時悲鵩鳥，殺身無路學犧牛。", "非才豈合居臺閣，歸夢徒勞近冕旒。", "千載遭逢如未替，此身重見帝王州。"]'),
('0d19d955-54cb-4f80-9469-d9c8196acd60','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其一','王禹偁','宋','宋诗','song-poetry','','[]','玄象中台坼，皇家上相薨。',48,'全唐诗/poet.song.3000.json','["玄象中台坼，皇家上相薨。", "大功銘玉鉉，密事在金縢。", "無復同魚水，空嗟失股肱。", "若言豐沛舊，陪葬近長陵。"]'),
('d6d3ea33-9fdb-47e1-a5cb-fb25b4422860','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其二','王禹偁','宋','宋诗','song-poetry','','[]','經緯千年業，陶鎔萬物功。',48,'全唐诗/poet.song.3000.json','["經緯千年業，陶鎔萬物功。", "藩垣龍節在，禁掖鳳池空。", "鹵簿蒙寒雨，銘旌颺曉風。", "太常草儀注，全似葬周公。"]'),
('a8e60d1b-141b-4a99-841c-1eb2e37a2701','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其三','王禹偁','宋','宋诗','song-poetry','','[]','重位經三入，高年過七旬。',48,'全唐诗/poet.song.3000.json','["重位經三入，高年過七旬。", "有言皆爲國，無日不憂民。", "溫樹蕭蕭影，甘棠漠漠春。", "遥知神德廟，配饗更何人。"]'),
('5ba653e8-0d6c-4e56-891a-8d936711b906','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其四','王禹偁','宋','宋诗','song-poetry','','[]','國喪三台首，家藏五廟尊。',48,'全唐诗/poet.song.3000.json','["國喪三台首，家藏五廟尊。", "紀功誰秉筆，冊贈帝臨軒。", "盛德留千古，貞魂閉九原。", "皇情彌軫悼，天柱折崑崙。"]'),
('e169c8ba-2ccd-428b-a860-b18c719fcd38','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其五','王禹偁','宋','宋诗','song-poetry','','[]','麟喪虛靈囿，鳳衰空帝梧。',48,'全唐诗/poet.song.3000.json','["麟喪虛靈囿，鳳衰空帝梧。", "陶鎔存庶彙，霖雨潤寰區。", "舊疏同伊訓，遺章入禹謨。", "九原何所恨，猶未滅匈奴。"]'),
('b50eb40d-0676-481c-80b8-01d0e53cfd24','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其六','王禹偁','宋','宋诗','song-poetry','','[]','空留遺像在凌烟，誰繼堂堂命世賢。',64,'全唐诗/poet.song.3000.json','["空留遺像在凌烟，誰繼堂堂命世賢。", "將相位高三十載，風雲道合一千年。", "霖收傅說巖前雨，石隕媧皇補後天。", "見說吾君舉哀處，重瞳揮洒淚潺湲。"]'),
('dd2b6672-32db-4cbc-8cdd-eefc44139e2e','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其七','王禹偁','宋','宋诗','song-poetry','','[]','君恩雖聽罷居留，官拜維師命更優。',64,'全唐诗/poet.song.3000.json','["君恩雖聽罷居留，官拜維師命更優。", "異物忽隨黄石葬，晚年終負赤松遊。", "憑誰借筯論歸馬，無復停車問喘牛。", "唯有功名書信史，肯同塵土一時休。"]'),
('bc4adf65-5149-4514-854c-9bda2f2e4249','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其八','王禹偁','宋','宋诗','song-poetry','','[]','曾拜四章辭相府，又陳三表罷留司。',64,'全唐诗/poet.song.3000.json','["曾拜四章辭相府，又陳三表罷留司。", "朝廷年德劉仁軌，終始功名郭子儀。", "印鎖黄金塵暗澹，堂閑綠野草離披。", "吾君若念先朝舊，應似文貞御製碑。"]'),
('0e534420-40c0-4e85-b04d-cf5031cd4e03','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其九','王禹偁','宋','宋诗','song-poetry','','[]','忍聽咚咚窆鼓聲，笳簫嗚咽暮雲凝。',64,'全唐诗/poet.song.3000.json','["忍聽咚咚窆鼓聲，笳簫嗚咽暮雲凝。", "勳勞自合同蕭相，謚法還須比魏徵。", "曉月暗垂丹旐露，夜風輕觸繐帷燈。", "三川父老知何限，盡逐靈輀淚滿膺。"]'),
('c84f2238-2f4d-4cd0-b3d9-1b294617f34c','太師中書令魏國公冊贈尚書令追封真定王趙挽歌  其一○','王禹偁','宋','宋诗','song-poetry','','[]','元老令終歸葬日，有司重奏輟朝時。',64,'全唐诗/poet.song.3000.json','["元老令終歸葬日，有司重奏輟朝時。", "駢羅鹵簿三公禮，告赴同盟五月期。", "何處更求廊廟器，是誰重作帝王師。", "商山副使偏垂淚，未報當年國士知。"]'),
('b6459ab0-5351-4e3c-a63a-9b1cc55aa222','和仲咸詩六首 和與喻豐陽夜話','王禹偁','宋','宋诗','song-poetry','','[]','澤國來朝積歲年，商山相遇話鄉原。',64,'全唐诗/poet.song.3000.json','["澤國來朝積歲年，商山相遇話鄉原。", "郄詵重折月中桂，陶令未歸江上村。", "嵐氣滴空無限翠，泉聲通夕有何冤。", "寒燈挑盡芳樽竭，所得新奇盡雅言。"]'),
('0f2c5793-0529-4e0b-b8fc-f2f89d53e254','和仲咸詩六首 和迴喻令詩集','王禹偁','宋','宋诗','song-poetry','','[]','風雅荒凉信可悲，家聲留得盡玄微。',64,'全唐诗/poet.song.3000.json','["風雅荒凉信可悲，家聲留得盡玄微。", "且欣丹穴一毛在，莫道沅江九肋稀。", "思苦也知關國政，官卑應爲洩天機。", "他時遷客歸朝去，擬覓瓊瑶滿袖歸。"]'),
('9ac83559-47fe-494c-94c5-cb3997aa3ec8','和仲咸詩六首 和自詠','王禹偁','宋','宋诗','song-poetry','','[]','玉經炎火竹經霜，却把剛腸變酒腸。',64,'全唐诗/poet.song.3000.json','["玉經炎火竹經霜，却把剛腸變酒腸。", "庾信悲哀休作賦，接輿歌曲且佯狂。", "更諳喪亂災爲福，藴蓄才華有若亡。", "孤宦由來宜晚達，祝君霄漢路歧長。"]'),
('9903700c-ca12-47c5-8cc8-85c45af2f9fd','和仲咸詩六首 和與盧氏宋少府話舊遊','王禹偁','宋','宋诗','song-poetry','','[]','舊遊前政一追尋，宦路遷移敵古今。',64,'全唐诗/poet.song.3000.json','["舊遊前政一追尋，宦路遷移敵古今。", "黄綬位卑曾歎命，青宮官冷不妨吟。", "烟嵐不改當窗色，桃李應垂滿砌陰。", "好寄新詩題舊壁，爲言梅福珥朝簪。"]'),
('50858453-5717-4048-ba38-4c74b81bb20e','和仲咸詩六首 和題鳴馬廟','王禹偁','宋','宋诗','song-poetry','','[]','何人祠廟立空山，四皓精靈合往還。',64,'全唐诗/poet.song.3000.json','["何人祠廟立空山，四皓精靈合往還。", "疋馬不辭峰更險，冥鴻應爲世多艱。", "雲生碧殿縈鴟尾，風觸金鋪動獸環。", "欲識姓名無問處，空聞靈異庇商顔。"]'),
('4bc71eb9-98eb-4542-9165-b1ae75baa9a9','和仲咸詩六首 和送道服與喻宰','王禹偁','宋','宋诗','song-poetry','','[]','朝客吟詩送羽衣，應知彭澤久思歸。',32,'全唐诗/poet.song.3000.json','["朝客吟詩送羽衣，應知彭澤久思歸。", "三年官滿誰留得，領鶴携琴賦式微。"]'),
('7c267037-5bac-4b59-984b-e71f21a2f1f4','寄海州副使田舍人','王禹偁','宋','宋诗','song-poetry','','[]','繫即匏瓜轉即蓬，可憐蹤跡與君同。',64,'全唐诗/poet.song.3000.json','["繫即匏瓜轉即蓬，可憐蹤跡與君同。", "眼前有酒長須醉，身外除詩盡是空。", "閑採紫芝饑可療，欲浮滄海道應窮。", "聲名官職相磨折，休憶西垣藥樹紅。"]'),
('f29530f2-91e1-480f-b5e6-88b402733a2b','恭聞种山人表謝急徵不赴榮侍因成拙句仰紀高風','王禹偁','宋','宋诗','song-poetry','','[]','未赴吾君鳳詔徵，蒲輪何似板輿榮。',64,'全唐诗/poet.song.3000.json','["未赴吾君鳳詔徵，蒲輪何似板輿榮。", "自期物外長無事，誰覺人間已有名。", "餌朮肯嘗鍾鼎味，紉蘭應笑珮環聲。", "洛南遷客堪羞死，猶望量移近帝城。"]'),
('eba94c97-997a-402b-a892-3c205c3134df','再賦二章一以頌高人之風一以伸俗吏之意  其一','王禹偁','宋','宋诗','song-poetry','','[]','表讓皇家買酒錢，醉鄉歸去便陶然。',32,'全唐诗/poet.song.3000.json','["表讓皇家買酒錢，醉鄉歸去便陶然。", "吾君若問徵君意，自有東臯種黍田。"]'),
('582bc28f-8837-436f-b7ad-fedd5027c3f6','再賦二章一以頌高人之風一以伸俗吏之意  其二','王禹偁','宋','宋诗','song-poetry','','[]','不應明時鵠板書，可能終老傲唐虞。',32,'全唐诗/poet.song.3000.json','["不應明時鵠板書，可能終老傲唐虞。", "神仙見說須陰德，肯爲蒼生一出無。"]'),
('b7b36312-d79b-4b32-b1e0-55d1c8ceae7d','五更睡','王禹偁','宋','宋诗','song-poetry','','[]','數載直承明，寵深還若驚。',48,'全唐诗/poet.song.3000.json','["數載直承明，寵深還若驚。", "趁朝雞喚起，殘夢馬馱行。", "左宦離雙闕，高眠盡五更。", "如將閑比貴，此味敵公卿。"]'),
('0b514ee3-154b-4fa7-bdc0-42fbf4af7faa','自詠','王禹偁','宋','宋诗','song-poetry','','[]','華髮不稱老，高堂爲有親。',48,'全唐诗/poet.song.3000.json','["華髮不稱老，高堂爲有親。", "寧同賈生恨，自比老萊身。", "官散且無過，俸微猶助貧。", "誰能學屈蠖，拳跼苦求神。"]'),
('07d92eeb-0acc-43f9-8631-57be0842e89d','遣興','王禹偁','宋','宋诗','song-poetry','','[]','百年身世片時間，況是多愁鬢早斑。',64,'全唐诗/poet.song.3000.json','["百年身世片時間，況是多愁鬢早斑。", "貧有琴書聊自藥，貴無功業未如閑。", "波平南浦堪垂釣，日滿東窗尚掩關。", "祇爲慈親憶歸去，商山不隠隠何山。"]'),
('0454daf0-35a6-486f-b0a1-73ddfc076a3c','夏雲','王禹偁','宋','宋诗','song-poetry','','[]','嵯峨高鎖夕陽紅，斜入吟窗秀色濃。',32,'全唐诗/poet.song.3000.json','["嵯峨高鎖夕陽紅，斜入吟窗秀色濃。", "六里青山長滿眼，不勞雲片學奇峰。"]'),
('b223dc11-1914-46d1-9ff8-4263562ae87b','丹河閑步','王禹偁','宋','宋诗','song-poetry','','[]','誰愛潺湲到水濱，春來唯有我來頻。',64,'全唐诗/poet.song.3000.json','["誰愛潺湲到水濱，春來唯有我來頻。", "沙邊坐慣漁翁識，岸上行多白鳥馴。", "髭髮照看添霰雪，冠纓濯後少埃塵。", "今秋更擬營蓑笠，冒雨衝風把釣綸。"]'),
('28ae8cbc-cedc-430a-967a-5d34b784028b','新秋即事  其一','王禹偁','宋','宋诗','song-poetry','','[]','露莎烟竹冷凄凄，秋吹無端入客衣。',64,'全唐诗/poet.song.3000.json','["露莎烟竹冷凄凄，秋吹無端入客衣。", "鑑裏鬢毛衰颯盡，日邊京國信音稀。", "風蟬歷歷和枝響，雨燕差差掠地飛。", "繫滯不如商嶺葉，解隨流水向東歸。"]'),
('ccea5de8-476d-44f2-a771-4597e27da211','新秋即事  其二','王禹偁','宋','宋诗','song-poetry','','[]','宦途流落似長沙，頼有詩情遣歲華。',64,'全唐诗/poet.song.3000.json','["宦途流落似長沙，頼有詩情遣歲華。", "吟弄淺波臨釣渚，醉披殘照入僧家。", "石挨苦竹旁抽筍，雨打戎葵卧放花。", "安得君恩許歸去，東陵閑種一園瓜。"]'),
('87be3bb1-02c8-4d1b-b811-5501e4e51803','新秋即事  其三','王禹偁','宋','宋诗','song-poetry','','[]','百歲浮生一夢中，夢中何事有窮通。',64,'全唐诗/poet.song.3000.json','["百歲浮生一夢中，夢中何事有窮通。", "姓名舊署黄麻紙，顔狀今成白髮翁。", "烟暝小窗螢火碧，雨昏幽逕蓼花紅。", "謫居始信爲儒苦，生計兼無一畝宮。"]'),
('6e281ed1-1b3f-4513-a9e4-77f0f0b8aadf','秋居幽興  其一','王禹偁','宋','宋诗','song-poetry','','[]','秋光雖寂澹，幽興入詩家。',48,'全唐诗/poet.song.3000.json','["秋光雖寂澹，幽興入詩家。", "籬暗螿啼菊，園荒蟻上茄。", "圍棋知日影，理髮見霜華。", "向曉兒童喜，溪僧遺晚瓜。"]'),
('58b75c20-6e9b-4a80-9e05-a8799c56d796','秋居幽興  其二','王禹偁','宋','宋诗','song-poetry','','[]','園林經積雨，晚步思悠哉。',48,'全唐诗/poet.song.3000.json','["園林經積雨，晚步思悠哉。", "宿鳥頭相並，秋瓜頂自開。", "藥田荒野蔓，屐齒沒蒼苔。", "幽興將何遣，燋琴貰酒杯。"]'),
('247b9b8e-6221-4c47-8b60-83169c6f4f51','秋居幽興  其三','王禹偁','宋','宋诗','song-poetry','','[]','謫居人事慵，幽興與誰同。',48,'全唐诗/poet.song.3000.json','["謫居人事慵，幽興與誰同。", "僧到烹秋菌，兒啼索草蟲。", "掃苔留嫩綠，寫葉惜殘紅。", "歲晏琴罇好，籬邊有菊叢。"]'),
('f687140d-c844-418c-ad58-bcc76977d7de','前賦春居雜興詩二首間半歲不復省視因長男嘉祐讀杜工部集見語意頗有相類者咨于予且意予竊之也予喜而作詩聊以自賀','王禹偁','宋','宋诗','song-poetry','','[]','命屈由來道日新，詩家權柄敵陶鈞。',64,'全唐诗/poet.song.3000.json','["命屈由來道日新，詩家權柄敵陶鈞。", "任無功業調金鼎，且有篇章到古人。", "本與樂天爲後進，敢期子美是前身。", "從今莫厭閑官職，主管風騷勝要津。"]'),
('e74e0dcb-5a4f-4d8a-bb75-ffd81a91f322','翟使君挽歌  其一','王禹偁','宋','宋诗','song-poetry','','[]','丹旐換紅旌，蕭蕭五馬鳴。',48,'全唐诗/poet.song.3000.json','["丹旐換紅旌，蕭蕭五馬鳴。", "今朝爲旅櫬，昨日是專城。", "愛子方之蜀，遺書未到京。", "貳車郊外送，揮淚滿塵纓。"]'),
('727ccb6d-a768-4730-a0b4-6c69d9c7a9f8','翟使君挽歌  其二','王禹偁','宋','宋诗','song-poetry','','[]','國史書勳伐，州民頌樂康。',48,'全唐诗/poet.song.3000.json','["國史書勳伐，州民頌樂康。", "豈唯存柏槨，亦合葬桐鄉。", "黄壤千年恨，青山六里長。", "空餘鈴閣畔，寂寞菊花香。"]'),
('be9cab8c-030b-4bdb-b687-cdd3f4af0ce2','翟使君挽歌  其三','王禹偁','宋','宋诗','song-poetry','','[]','未滿三年政，何妨五月期。',48,'全唐诗/poet.song.3000.json','["未滿三年政，何妨五月期。", "理言歸葬速，遺愛出山遲。", "檣翣穿雲過，銘旌著雨垂。", "洛陽多故吏，號泣住靈輀。"]'),
('6b67333f-57fb-4296-922e-3025ac549e74','村行','王禹偁','宋','宋诗','song-poetry','','["\u5199\u666f", "\u79cb\u5929", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u601d\u4e61", "\u5b8b\u8bd7"]','馬穿山逕菊初黄，信馬悠悠野興長。',64,'全唐诗/poet.song.3000.json','["馬穿山逕菊初黄，信馬悠悠野興長。", "萬壑有聲含晚籟，數峰無語立斜陽。", "棠梨葉落胭脂色，蕎麥花開白雪香。", "何事吟餘忽惆悵，村橋原樹似吾鄉。"]'),
('ee4da1f4-1837-49b1-9c3e-ef37aa82f490','淳化二年八月晦日夜夢于上前賦詩既寤唯省一句云九日山州見菊花間一日有商於貳車之命實以十月三日到郡重陽已過殘菊尚多意夢已徵矣今忽然一歲又逼登高追續前詩句因成四韵','王禹偁','宋','宋诗','song-poetry','','[]','節近登高忽歎嗟，經年憔悴別京華。',64,'全唐诗/poet.song.3000.json','["節近登高忽歎嗟，經年憔悴別京華。", "貳車何處搔蓬鬢，九日山州見菊花。", "夢裏榮衰安足道，眼前盃酒且須賒。", "商於鄒魯雖迢遞，大底携家即是家。"]'),
('d6b80baa-5ffc-4431-b42d-20333a429a87','仲咸就加郡印因以四韵賀而勉之','王禹偁','宋','宋诗','song-poetry','','[]','如何小郡滯清賢，未得徵歸振鷺班。',64,'全唐诗/poet.song.3000.json','["如何小郡滯清賢，未得徵歸振鷺班。", "莫怕三年持漢詔，猶勝遷客卧商山。", "俱諳宦路須推命，同有詩情合好閑。", "唯是謫官無考限，比君知向幾時還。"]'),
('8e1bb3a3-33f5-4421-9ea0-f4d9d4c30a32','自嘲','王禹偁','宋','宋诗','song-poetry','','[]','三月降霜花木死，九秋飛雪麥禾災。',32,'全唐诗/poet.song.3000.json','["三月降霜花木死，九秋飛雪麥禾災。", "蟲蝗水旱霖淫雨，盡逐商山副使來。"]'),
('506afe5a-2b24-4d20-a0f9-dccac826b03d','雪霽霜晴獨尋山逕菊花猶盛感而賦詩','王禹偁','宋','宋诗','song-poetry','','[]','狼藉金錢撒野塘，幾叢無力卧斜陽。',64,'全唐诗/poet.song.3000.json','["狼藉金錢撒野塘，幾叢無力卧斜陽。", "爭偷暖律輸桃李，獨亞寒枝負雪霜。", "誰惜晚芳同我折，自憐孤艷襲人香。", "幽懷遠慕陶彭澤，且擷殘英泛一觴。"]'),
('62041b97-559b-4edc-aac7-503eb3d7ba46','寄豐陽喻長官','王禹偁','宋','宋诗','song-poetry','','[]','七十年華鬢未霜，道情偏稱宰豐陽。',64,'全唐诗/poet.song.3000.json','["七十年華鬢未霜，道情偏稱宰豐陽。", "早衙請印無仇覽，夜榻圍棋祇孟光。", "庭戶萬重嵐氣潤，盤餐數飣藥苗香。", "猶言彭澤終歸去，門柳青青檻菊黄。"]'),
('4eb7c470-1a6c-49ae-85f6-09b3fcc5b76b','官舍竹','王禹偁','宋','宋诗','song-poetry','','[]','誰種蕭蕭數百竿，伴吟偏稱作閑官。',64,'全唐诗/poet.song.3000.json','["誰種蕭蕭數百竿，伴吟偏稱作閑官。", "不隨夭艷爭春色，獨守孤貞待歲寒。", "聲拂琴牀生雅趣，影侵棋局助清歡。", "明年縱便量移去，猶得今冬雪裏看。"]'),
('b1c9467b-abc1-4273-8130-923367528388','雪夜看竹','王禹偁','宋','宋诗','song-poetry','','[]','夢斷閑窗酒半醺，月華薄薄雪紛紛。',32,'全唐诗/poet.song.3000.json','["夢斷閑窗酒半醺，月華薄薄雪紛紛。", "莫言官散無拘束，一夜披衣見此君。"]'),
('26b5b009-7650-40ee-857b-f5f1675196c2','喜雪貽仲咸','王禹偁','宋','宋诗','song-poetry','','[]','半冬無雪懶吟詩，薄暮紛紛喜可知。',64,'全唐诗/poet.song.3000.json','["半冬無雪懶吟詩，薄暮紛紛喜可知。", "衣上惹來看不足，竹邊聽處立多時。", "光迷曙色侵窗早，片舞寒空到地遲。", "今日使君吟望好，一車飛絮醉褰帷。"]'),
('452e8784-8120-4cd6-8ec1-592ae1ef8b6a','賦得臘雪連春雪','王禹偁','宋','宋诗','song-poetry','','[]','臘雪連春雪，商民舞且歌。',48,'全唐诗/poet.song.3000.json','["臘雪連春雪，商民舞且歌。", "數年求不得，一尺未爲多。", "試法烹茶鼎，資吟落釣蓑。", "登樓應更好，丹水是銀河。"]'),
('2627fa80-40b2-4a82-82ba-23e7eee2d73f','立春日細雨','王禹偁','宋','宋诗','song-poetry','','[]','澹于寒霧亂于絲，無點無聲落不知。',64,'全唐诗/poet.song.3000.json','["澹于寒霧亂于絲，無點無聲落不知。", "輕助雪痕歸麥壠，暗隨春氣入梅枝。", "踏苔立久微霑屐，遶竹吟餘漸著髭。", "翻憶滿身珠䍡𦌊，江頭閑把釣蓑披。"]'),
('8523076d-46fe-403c-8611-3c768120faf1','霽後望山中春雪','王禹偁','宋','宋诗','song-poetry','','[]','誰種離離碎玉苗，曉樓吟望興偏饒。',64,'全唐诗/poet.song.3000.json','["誰種離離碎玉苗，曉樓吟望興偏饒。", "白雲作伴宜長在，紅日無情已半銷。", "聚映早霞明野寺，散隨春水過溪橋。", "世間安得王摩詰，醉展霜縑把筆描。"]'),
('e7db4f21-40d4-4562-9bc5-73eab835bed9','閑居','王禹偁','宋','宋诗','song-poetry','','[]','何必問生涯，幽閑度歲華。',48,'全唐诗/poet.song.3000.json','["何必問生涯，幽閑度歲華。", "有琴方是樂，無竹不成家。", "吟裏銷春色，眠中見曙霞。", "今年如未去，更擬種胡麻。"]'),
('449bd361-f2fd-4c17-96e3-95599fd65fda','有懷戚二仲言同年','王禹偁','宋','宋诗','song-poetry','','[]','聞說去官常，悽悽返故鄉。',48,'全唐诗/poet.song.3000.json','["聞說去官常，悽悽返故鄉。", "與君同甲子，似我有文章。", "憔悴衣衫綠，蹉跎鬢髮蒼。", "此身知幸處，曾得紫微郎。"]'),
('6b934eaa-4f0f-4b61-8934-dd654b9aaba1','春郊寓目','王禹偁','宋','宋诗','song-poetry','','[]','百舌嬌慵未苦啼，雪隨春水下松溪。',64,'全唐诗/poet.song.3000.json','["百舌嬌慵未苦啼，雪隨春水下松溪。", "何人樵樹和雲斫，幾處山田带雨犁。", "蜀柳半開鸜鵒眼，海棠深結麝香臍。", "東風似待閑人出，一路青莎櫬馬蹄。"]'),
('b88e2d03-c366-46f8-856a-4e1eb066f0d8','杏花  其一','王禹偁','宋','宋诗','song-poetry','','[]','紅芳紫萼怯春寒，蓓蕾粘枝密作團。',32,'全唐诗/poet.song.3000.json','["紅芳紫萼怯春寒，蓓蕾粘枝密作團。", "記得觀燈鳳樓上，百條銀燭淚闌干。"]'),
('49d2384d-4699-4f6e-a0d3-87e636d0578a','杏花  其二','王禹偁','宋','宋诗','song-poetry','','[]','暖映垂楊曲檻邊，一堆紅雪罩輕烟。',32,'全唐诗/poet.song.3000.json','["暖映垂楊曲檻邊，一堆紅雪罩輕烟。", "春來自得風流伴，榆莢休拋買笑錢。"]'),
('39994c37-e380-4bff-8307-3dc1eeef9c14','杏花  其三','王禹偁','宋','宋诗','song-poetry','','[]','桃紅李白莫爭春，素態妖姿兩未勻。',32,'全唐诗/poet.song.3000.json','["桃紅李白莫爭春，素態妖姿兩未勻。", "日暮牆頭試迴首，不施朱粉是東鄰。"]'),
('6efaca96-55ef-49eb-a8c3-2ff094cdef83','杏花  其四','王禹偁','宋','宋诗','song-poetry','','[]','長愁風雨暗離披，醉遶吟看得幾時。',32,'全唐诗/poet.song.3000.json','["長愁風雨暗離披，醉遶吟看得幾時。", "唯有流鶑偏稱意，夜來偷宿最繁枝。"]'),
('e59b455b-3880-4d08-ae97-90d747c6ee06','杏花  其五','王禹偁','宋','宋诗','song-poetry','','[]','登龍曾入少年場，錫宴瓊林醉御觴。',32,'全唐诗/poet.song.3000.json','["登龍曾入少年場，錫宴瓊林醉御觴。", "爭戴滿頭紅爛熳，至今猶雜桂枝香。"]'),
('29ce2123-cfdd-4d61-aa8a-1223d26f26d2','杏花  其六','王禹偁','宋','宋诗','song-poetry','','[]','長安廢棄遷都後，曲沼荒凉一夢中。',32,'全唐诗/poet.song.3000.json','["長安廢棄遷都後，曲沼荒凉一夢中。", "見說舊園爲茂草，寂寥無復萬枝紅。"]'),
('45bb992c-c37b-4070-8301-2c1fb59c026e','杏花  其七','王禹偁','宋','宋诗','song-poetry','','[]','陌上繽紛枝上稀，多情猶解撲人衣。',32,'全唐诗/poet.song.3000.json','["陌上繽紛枝上稀，多情猶解撲人衣。", "雙成洒道迎王母，十里濛濛絳雪飛。"]'),
('2eeac968-5fbc-4499-b17a-e0f2d6535bb7','寄陝府通判孫狀元兼簡令弟秀才','王禹偁','宋','宋诗','song-poetry','','[]','商山留滯再經年，咫尺無由見狀元。',64,'全唐诗/poet.song.3000.json','["商山留滯再經年，咫尺無由見狀元。", "會赦未教歸北闕，高歌應合遇東園。", "寸心謾道如弦直，兩鬢難禁似雪繁。", "兄弟相知情未改，著書呼取屈原魂。"]'),
('9ffd6562-6ac3-4fd8-b4ce-137da90580d6','日長簡仲咸','王禹偁','宋','宋诗','song-poetry','','[]','日長何計到黄昏，郡僻官閑晝掩門。',64,'全唐诗/poet.song.3000.json','["日長何計到黄昏，郡僻官閑晝掩門。", "子美集開詩世界，伯陽書見道根源。", "風飄北院花千片，月上東樓酒一罇。", "不是同年來主郡，此心牢落共誰論。"]'),
('ce4910a3-85a5-4d79-8fd5-27c1edcecf48','春郊獨步','王禹偁','宋','宋诗','song-poetry','','[]','襟袖飄飄晚吹輕，孤吟何必共人行。',64,'全唐诗/poet.song.3000.json','["襟袖飄飄晚吹輕，孤吟何必共人行。", "綠楊繫馬尋芳逕，春草隨人上古城。", "不憤黄鸝誇巧舌，多慚戴勝勸歸耕。", "憑高朗詠沉湘賦，自許吾生似賈生。"]'),
('e0be0417-4362-4992-9fdb-9b5ec92e769c','種菜了雨下','王禹偁','宋','宋诗','song-poetry','','[]','菜助三餐急，園愁五月枯。',48,'全唐诗/poet.song.3000.json','["菜助三餐急，園愁五月枯。", "廢畦添糞壤，胼手捽荒蕪。", "前日種子下，今朝雨點粗。", "吟詩深自慰，天似憫窮途。"]'),
('3c348336-5086-491d-8689-7777463fd63b','偶置小園因題  其一','王禹偁','宋','宋诗','song-poetry','','[]','十畝春畦兩眼泉，置來應得弄潺湲。',64,'全唐诗/poet.song.3000.json','["十畝春畦兩眼泉，置來應得弄潺湲。", "三年謫宦供厨菜，數月朝行賃宅錢。", "空媿先師輕學圃，未如平子便歸田。", "此身久畜耕山計，不敢拋官爲左遷。"]'),
('29d4604b-9b2b-4065-bc85-4c5148f60601','偶置小園因題  其二','王禹偁','宋','宋诗','song-poetry','','[]','偶營菜圃爲盤飱，淮瀆祠前水北村。',64,'全唐诗/poet.song.3000.json','["偶營菜圃爲盤飱，淮瀆祠前水北村。", "泉響靜連衙鼓響，柴門深近子城門。", "濛濛細雨春蔬甲，亹亹寒流老樹根。", "從此商於地圖上，畫工添箇舍人園。"]'),
('54796f39-e915-4684-b8dd-de0d187b5966','戲從豐陽喻長官覓筍','王禹偁','宋','宋诗','song-poetry','','[]','春來春筍滿豐陽，祇把盤餐勸孟光。',32,'全唐诗/poet.song.3000.json','["春來春筍滿豐陽，祇把盤餐勸孟光。", "犀角錦文雖可惜，也須分惠紫微郎。"]'),
('7402a9b5-5bf6-4d37-a8f0-2425796a7221','三月廿七日偶作簡仲咸','王禹偁','宋','宋诗','song-poetry','','[]','一未量移一轉勳，貂冠羊胃總非真。',64,'全唐诗/poet.song.3000.json','["一未量移一轉勳，貂冠羊胃總非真。", "韶光祇有兩三日，浮世稀逢七十人。", "青杏勸君重酌酒，牡丹邀我且尋春。", "請看富貴趙中令，已作北邙山下塵。"]'),
('b71b6e48-8459-47a6-bb43-effee3f8d038','送巡撫侍讀呂司諫','王禹偁','宋','宋诗','song-poetry','','[]','三十軍城百萬家，侍臣分命走軺車。',64,'全唐诗/poet.song.3000.json','["三十軍城百萬家，侍臣分命走軺車。", "長春殿裏承丹詔，乙夜書邊別翠華。", "駐馬祇教看壠麥，憂民無暇醉溪花。", "歸朝舊友如相問，爲道山中學種畬。"]'),
('fba6309b-7455-4241-bf3b-33fb6dba199e','別商山量移解州作','王禹偁','宋','宋诗','song-poetry','','[]','欲辭蒼翠入塵囂，把酒看山思寂寥。',32,'全唐诗/poet.song.3000.json','["欲辭蒼翠入塵囂，把酒看山思寂寥。", "莫動移文苦相責，解梁聞說近中條。"]'),
('99c84e4d-89f7-4807-afb1-4f222728b97a','別丹水','王禹偁','宋','宋诗','song-poetry','','[]','曾經爛漫濯吾纓，忍別潺湲月下聲。',32,'全唐诗/poet.song.3000.json','["曾經爛漫濯吾纓，忍別潺湲月下聲。", "便入紅塵染詩思，吟魂猶合數年清。"]'),
('4b9fc9bb-d138-4f56-b8f5-ba79b8054356','別四皓廟','王禹偁','宋','宋诗','song-poetry','','[]','明朝欲別採芝翁，吟遶階前苦竹叢。',32,'全唐诗/poet.song.3000.json','["明朝欲別採芝翁，吟遶階前苦竹叢。", "貶謫入山非美退，此中爭敢逐冥鴻。"]'),
('bfec364b-6477-4c76-ae18-d53e390f7d0f','別仙娥峰','王禹偁','宋','宋诗','song-poetry','','[]','商山留滯再經春，吟愛仙娥最出羣。',32,'全唐诗/poet.song.3000.json','["商山留滯再經春，吟愛仙娥最出羣。", "若有精靈念遷客，暫來河北作行雲。"]'),
('d73e1820-e58f-4b5c-9d15-93f7dbabe369','別北窗竹','王禹偁','宋','宋诗','song-poetry','','[]','滿窗疏韵伴吟聲，別夜猶憐枕簟清。',32,'全唐诗/poet.song.3000.json','["滿窗疏韵伴吟聲，別夜猶憐枕簟清。", "見說解梁難種植，此君相別若爲情。"]'),
('95925155-b855-4ff6-8fd7-673049cf950e','別堂後海棠','王禹偁','宋','宋诗','song-poetry','','[]','一堆紅雪媚青春，惜別須教淚滿巾。',32,'全唐诗/poet.song.3000.json','["一堆紅雪媚青春，惜別須教淚滿巾。", "好在明年莫憔悴，校書兼是愛花人。"]'),
('d0ed1220-4666-442d-9d57-7e2d4aa85ae1','量移後自嘲','王禹偁','宋','宋诗','song-poetry','','[]','可憐蹤跡轉如蓬，隨例量移近陝東。',32,'全唐诗/poet.song.3000.json','["可憐蹤跡轉如蓬，隨例量移近陝東。", "便似人家養鸚鵡，舊籠騰倒入新籠。"]'),
('eb4ea59c-70f1-4a44-8cd1-5bfc88812b6e','量移自解','王禹偁','宋','宋诗','song-poetry','','[]','商山五百五十日，若比昔賢非滯留。',32,'全唐诗/poet.song.3000.json','["商山五百五十日，若比昔賢非滯留。", "試看江陵元相國，四年移得向通州。"]'),
('8ae4e296-9c8a-4dde-9512-f53c96e5a7d7','留別仲咸  其一','王禹偁','宋','宋诗','song-poetry','','[]','二年商嶺頼知音，惜別難藏淚滿襟。',64,'全唐诗/poet.song.3000.json','["二年商嶺頼知音，惜別難藏淚滿襟。", "頭白忽拋攀桂伴，道消休話拔茅心。", "科名偶得同年分，交契都因謫宦深。", "唱和詩章收拾取，兩家留與子孫吟。"]'),
('def6d089-5171-4be4-994e-eeb286fc89a4','留別仲咸  其二','王禹偁','宋','宋诗','song-poetry','','[]','世網嬰纏不自由，可憐匏繫又萍流。',64,'全唐诗/poet.song.3000.json','["世網嬰纏不自由，可憐匏繫又萍流。", "忽從清洛南邊郡，移向黄河北岸州。", "命薄我甘閑副使，道孤君是假諸侯。", "解梁去此無多地，時寄新詩慰客愁。"]'),
('780f122e-ed5e-4845-b47e-3e4ec554ff92','出商州有感','王禹偁','宋','宋诗','song-poetry','','[]','圜丘恩例得量移，笑領全家出翠微。',32,'全唐诗/poet.song.3000.json','["圜丘恩例得量移，笑領全家出翠微。", "惟有來時的顱馬，商山埋骨不同歸。"]'),
('508a7d49-3954-4035-aa3e-381e1194af02','閿鄉縣留題陶氏林亭','王禹偁','宋','宋诗','song-poetry','','[]','年來恩例得量移，祇合高歌不合悲。',64,'全唐诗/poet.song.3000.json','["年來恩例得量移，祇合高歌不合悲。", "消長盈虛存大易，東南西北有先師。", "未拋軒冕終妨道，偶見林泉且賦詩。", "何事閿鄉住三日，吟情難捨竹邊池。"]'),
('37b17042-9599-49ed-906d-c2b46656d6d7','寄潘處士','王禹偁','宋','宋诗','song-poetry','','[]','賣藥先生白布衣，書來方信在京師。',64,'全唐诗/poet.song.3000.json','["賣藥先生白布衣，書來方信在京師。", "減君爐裏燒丹術，助我山中買酒資。", "閑似野雲終不仕，閉如籠鶴已多時。", "飄飄又去黄河北，更負中條幾首詩。"]'),
('81969964-0b8a-4f9f-8089-2288ad7d508b','將及陝郊先寄孫狀元','王禹偁','宋','宋诗','song-poetry','','[]','宦途漂蕩似浮萍，又到棠陰邵伯城。',64,'全唐诗/poet.song.3000.json','["宦途漂蕩似浮萍，又到棠陰邵伯城。", "親老轉添衰鬢白，妻兒猶免智囊生。", "狀元館穀如無倦，副使量移豈繫程。", "吾道不拘官冷暖，唯君應合出郊迎。"]'),
('565e4f70-e129-4313-a695-3d11cdd8efb0','甘棠即事簡孫何','王禹偁','宋','宋诗','song-poetry','','[]','甘棠風雅美賢臣，伐樹悽悽亦聖人。',64,'全唐诗/poet.song.3000.json','["甘棠風雅美賢臣，伐樹悽悽亦聖人。", "因感得時留蔽芾，更嗟無位泣麒麟。", "誰知素教長多難，我向清朝自不辰。", "聽訟何如使無訟，與君憂道合霑巾。"]'),
('6326125c-a359-4153-9e1b-112f51a09511','解梁官舍','王禹偁','宋','宋诗','song-poetry','','[]','郡在中條山脚下，盬南風起晝昏昏。',64,'全唐诗/poet.song.3000.json','["郡在中條山脚下，盬南風起晝昏昏。", "舍人謫宦誰言命，副使量移豈是恩。", "月有俸錢堆長物，日無公事掩閑門。", "上天于我心還厚，祇遣文章道更尊。"]'),
('6d541f41-021a-41ec-a1f9-88da07d65e49','中條山','王禹偁','宋','宋诗','song-poetry','','[]','崛起巨河邊，奔騰欲上天。',240,'全唐诗/poet.song.3000.json','["崛起巨河邊，奔騰欲上天。", "遠臨滄海盡，高與太行連。", "大塊橫爲脊，它山立似拳。", "土膏經舜耒，石險任秦鞭。", "洞黑狂吹雨，峰青冷罩烟。", "店荒壇道絕，寺古柏梯懸。", "崦漏微茫雪，巖垂淅瀝泉。", "迸根通砥柱，斜徑入閑田。", "北笑恒藏寶，西輕華聳蓮。", "三門遥託跡，五老迥差肩。", "落實樵夫拾，靈苗本草傳。", "柱空擎雁塔，倒影蓋漁船。", "繪畫終無手，封崇必有年。", "鹽池浮翠靄，董澤媚漪漣。", "陰壑乖龍蟄，枯杉凍虺穿。", "圖經標數郡，神異産羣賢。", "呼壽嵩何諂，升中泰豈專。", "斯文如已矣，此地可終焉。", "暫看猶銷病，頻登合得仙。", "許昌休自負，吾什亦銘鎸。"]'),
('23708d17-11da-4d6c-baa3-3b77a9f27617','五老峰','王禹偁','宋','宋诗','song-poetry','','[]','矗矗拂星榆，崢嶸與衆殊。',192,'全唐诗/poet.song.3000.json','["矗矗拂星榆，崢嶸與衆殊。", "精靈奔昴宿，神異載河圖。", "捧日光先及，參天禮不趣。", "綠蘿供組綬，清籟獻笙竽。", "洩雨遥霑華，堆嵐下照蒲。", "僧窗分未足，郡閣占應俱。", "漠漠雲交袂，霏霏雪映鬚。", "巨靈羞用壯，玉女願爲奴。", "磊落工難畫，參差德不孤。", "兒孫溪石小，几杖澗松枯。", "洞鄙三茅隠，山嫌四皓逋。", "分形皆自立，倒影要誰扶。", "將數慚同漢，臣名合贊虞。", "嵩峰真樹黨，天柱太無徒。", "安得隨人意，移將近帝都。", "吾君南面處，萬歲一齊呼。"]'),
('0dc4e4bd-c3ef-47f8-a8ab-06224004bcb7','書孫僅甘棠集後','王禹偁','宋','宋诗','song-poetry','','[]','新集甘棠盡雅言，獨疑陳杜指根源。',64,'全唐诗/poet.song.3000.json','["新集甘棠盡雅言，獨疑陳杜指根源。", "一飛事往名雖屈，六義功成道更尊。", "骨氣向人蹲獬豸，波濤無敵瀉崑崙。", "明年再就堯階試，應被人呼小狀元。"]'),
('dfd8b32d-f28e-4ff6-af34-26c69a42364c','櫻桃','王禹偁','宋','宋诗','song-poetry','','[]','鳳實落嶙峋，蟠根出俗塵。',192,'全唐诗/poet.song.3000.json','["鳳實落嶙峋，蟠根出俗塵。", "子多將盡夏，花晚不爭春。", "上苑空枝後，荒巖滿樹新。", "鳥含紅映嘴，猿飽漬流唇。", "溪寺初供佛，山齋已待賓。", "升筵參李柰，入市附樵薪。", "葉襯青舒槲，龍擎綠透筠。", "瀉盤能宛轉，就酒益甘辛。", "致養侔懷橘，投誠等獻芹。", "齒酸雖欲動，喉渴尚宜頻。", "溉水應無主，驅禽免廢人。", "栽培傷物性，髠接失天真。", "自笑羹梅忝，誰知社栗神。", "用堪登俎豆，生合委荆榛。", "差小同謙退，饒先似屈伸。", "叔孫如薦廟，朴野味彌純。"]'),
('5e73e198-1362-457d-ad42-5367e6c9ee7d','贈朗上人','王禹偁','宋','宋诗','song-poetry','','[]','凈剃霜髭展舊真，自疑容貌是前身。',64,'全唐诗/poet.song.3000.json','["凈剃霜髭展舊真，自疑容貌是前身。", "僧中獨守三千戒，詩裏閑銷七十春。", "僻寺蘚深人少到，故山雲好夢歸頻。", "禪齋近日誰還往，祇有西垣放逐臣。"]'),
('b232a005-702f-443f-aea6-d7c0bbb9b1f9','再授小諫偶書所懷','王禹偁','宋','宋诗','song-poetry','','[]','宦途滋味飽更諳，命薄于人分亦甘。',64,'全唐诗/poet.song.3000.json','["宦途滋味飽更諳，命薄于人分亦甘。", "兩鬢雪霜爲小諫，六街泥雨趁常參。", "便休祿仕饑寒累，强逐班行面目慚。", "安得去如种處士，板輿榮侍卧終南。"]'),
('351d75d4-0229-4393-9c1a-084417920484','贈禮部宋員外閣老','王禹偁','宋','宋诗','song-poetry','','[]','未還西掖舊詞臣，且向南宮作舍人。',64,'全唐诗/poet.song.3000.json','["未還西掖舊詞臣，且向南宮作舍人。", "休歎貳車如竹葦，須知百日掌絲綸。", "錦窠官重真殊拜，玉筍班清祇一身。", "堪笑白頭王小諫，握蘭猶未得相親。"]'),
('885b23f8-62c4-47c6-806f-089d24631182','自寬','王禹偁','宋','宋诗','song-poetry','','[]','身世龍鍾且自寬，追量才分合饑寒。',64,'全唐诗/poet.song.3000.json','["身世龍鍾且自寬，追量才分合饑寒。", "朝中舊友休誇貴，篋裏新詩不博官。", "曉髮靜梳微霰落，夜琴閑拂古風殘。", "會須歸去滄江上，累石移莎擁釣灘。"]'),
('48175aca-d79d-4ec9-af80-e69ac76bbb4d','贈衛尉宋卿二十二丈送前翰長侍郎  其一','王禹偁','宋','宋诗','song-poetry','','[]','性情和雅得天真，卿寺鼇頭任屈伸。',64,'全唐诗/poet.song.3000.json','["性情和雅得天真，卿寺鼇頭任屈伸。", "三品且隨前宰相，重瞳偏認舊詞臣。", "宿齋院冷琴橫膝，朝退門閑鶴伴身。", "多少摳衣門弟子，側聆還望秉陶鈞。"]'),
('00850c29-8bcc-4737-88a4-6d9ba22ae465','贈衛尉宋卿二十二丈送前翰長侍郎  其二','王禹偁','宋','宋诗','song-poetry','','[]','謫宦歸來髮更斑，徊翔猶在寺卿間。',64,'全唐诗/poet.song.3000.json','["謫宦歸來髮更斑，徊翔猶在寺卿間。", "幾多僚吏三台上，太半生徒兩制間。", "舊賜錦袍多貰酒，新裁紗帽欲歸山。", "東垣小諫龍鍾甚，空愧洪鑪早鑄顔。"]'),
('81b299ac-13f3-4297-844b-a0ebfbafe4ca','送融州任巽戶曹','王禹偁','宋','宋诗','song-poetry','','[]','御前曾取好科名，一掾如何萬里行。',64,'全唐诗/poet.song.3000.json','["御前曾取好科名，一掾如何萬里行。", "身落蠻夷人共惜，罪因文學自爲榮。", "吏供版籍多魚稅，民種山田見象耕。", "君看咸通十司戶，投荒終久是公卿。"]'),
('6e1d5d6a-29e9-4dbb-acb0-a6353da8733f','寄商州馮十八仲咸同年','王禹偁','宋','宋诗','song-poetry','','[]','遷客秋來捧詔還，故人多怪鬢毛斑。',64,'全唐诗/poet.song.3000.json','["遷客秋來捧詔還，故人多怪鬢毛斑。", "重爲東掖垣中士，猶夢西暉亭下山。", "靜算宦途皆是命，老思身計不如閑。", "何時相約同歸隠，水竹蕭蕭並掩關。"]'),
('e815d166-68fe-42b3-8b09-6a19969be2e5','送史館學士楊億閩中迎侍','王禹偁','宋','宋诗','song-poetry','','[]','迎侍閩川去路長，才名官職過歐陽。',64,'全唐诗/poet.song.3000.json','["迎侍閩川去路長，才名官職過歐陽。", "翰林貴族誇東榻，史館清銜慶北堂。", "別酒正逢寒菊綻，歸舟應見早梅香。", "拾遺健羨吟詩送，莫笑蹉跎兩鬢霜。"]'),
('972fc7fd-74bf-454e-969b-4b8c39fb0dd7','覽照','王禹偁','宋','宋诗','song-poetry','','[]','覽照笑浮生，秋霜髮數莖。',48,'全唐诗/poet.song.3000.json','["覽照笑浮生，秋霜髮數莖。", "才高空有氣，官散即無榮。", "貧久心還樂，吟多骨亦清。", "他年文苑傳，應不漏吾名。"]'),
('e86b2b06-e38d-497d-bd7d-6700d0aeeab0','送寇諫議赴青州','王禹偁','宋','宋诗','song-poetry','','[]','表海鎮崢嶸，樞臣輟禁庭。',120,'全唐诗/poet.song.3000.json','["表海鎮崢嶸，樞臣輟禁庭。", "兩蕃申族帳，七縣造圖經。", "密勿君恩異，循良祖德馨。", "旌旗驅驛路，鼓角出郊坰。", "歸夢尋溫樹，行塵動福星。", "上儀三道判，排設十間廳。", "風靜衙門戟，霜寒郡閣鈴。", "看山樓號白，封社土分青。", "花好詩難惜，梨甘酒易醒。", "徵還都幾日，莫愛妓娉婷。"]'),
('c425754d-2eb0-4476-8b8e-99bfbb284d0c','寧公新拜首座因贈','王禹偁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','著書新奏御，優詔及禪扉。',48,'全唐诗/poet.song.3000.json','["著書新奏御，優詔及禪扉。", "首座名雖貴，家山老未歸。", "磬聲寒繞枕，塔影靜侵衣。", "終憶西湖上，秋風白鳥飛。"]'),
('f3892a20-4e31-4de5-862c-0b205fabf614','壽寧節祝聖壽  其一','王禹偁','宋','宋诗','song-poetry','','[]','待漏齊趨聖節筵，雲開金闕上青天。',32,'全唐诗/poet.song.3000.json','["待漏齊趨聖節筵，雲開金闕上青天。", "平明引入長生殿，共祝堯雲百萬年。"]'),
('d0a6b2de-bddd-4693-a889-7e3ab9b764c2','壽寧節祝聖壽  其二','王禹偁','宋','宋诗','song-poetry','','[]','數聲飛電響鳴鞘，香裊金爐映赭袍。',32,'全唐诗/poet.song.3000.json','["數聲飛電響鳴鞘，香裊金爐映赭袍。", "王母親承玉皇詔，年年今日進蟠桃。"]'),
('b416196e-3692-494f-be37-75e9103dd7fa','壽寧節祝聖壽  其三','王禹偁','宋','宋诗','song-poetry','','[]','華胥國土何時見，兜率天宮底處開。',32,'全唐诗/poet.song.3000.json','["華胥國土何時見，兜率天宮底處開。", "盡說今年壽寧節，一齊移入帝城來。"]'),
('9b6f7c89-e6c1-4c9f-827e-9db969dc6f13','壽寧節祝聖壽  其四','王禹偁','宋','宋诗','song-poetry','','[]','簾前可愛三冬日，階下新抽七葉蓂。',32,'全唐诗/poet.song.3000.json','["簾前可愛三冬日，階下新抽七葉蓂。", "昨夜靈臺因預奏，綵雲高捧老人星。"]'),
('5710bae5-258f-4981-a872-eaee6c642ff3','壽寧節祝聖壽  其五','王禹偁','宋','宋诗','song-poetry','','[]','益算真君南斗高，還因聖節奏天曹。',32,'全唐诗/poet.song.3000.json','["益算真君南斗高，還因聖節奏天曹。", "扶桑枯盡靈椿老，始放堯眉出壽毫。"]'),
('f0be1db7-1481-4c6c-b247-d1b7321c6ffa','壽寧節祝聖壽  其六','王禹偁','宋','宋诗','song-poetry','','[]','莊周浪說華封祝，漢帝虛傳嵩岳聲。',32,'全唐诗/poet.song.3000.json','["莊周浪說華封祝，漢帝虛傳嵩岳聲。", "爭似壽寧嘉節日，千門萬戶願長生。"]'),
('2c5d7740-be8d-4c05-8e8d-c96a32dd2b75','壽寧節祝聖壽  其七','王禹偁','宋','宋诗','song-poetry','','[]','帝德由來動百神，年年聖節絕纖塵。',32,'全唐诗/poet.song.3000.json','["帝德由來動百神，年年聖節絕纖塵。", "萬家喜氣生和氣，冬日翻疑一日春。"]'),
('733cb9e2-ba7c-479e-ad94-a35d36e5b6b9','壽寧節祝聖壽  其八','王禹偁','宋','宋诗','song-poetry','','[]','祇爲憂民感上玄，玉京今日集羣仙。',32,'全唐诗/poet.song.3000.json','["祇爲憂民感上玄，玉京今日集羣仙。", "更教添注吾君壽，直過人皇萬八千。"]'),
('de919edb-1802-4c54-8574-a35465f16419','壽寧節祝聖壽  其九','王禹偁','宋','宋诗','song-poetry','','[]','漢主壽山稱萬歲，玄宗佳節號千秋。',32,'全唐诗/poet.song.3000.json','["漢主壽山稱萬歲，玄宗佳節號千秋。", "吾皇別享無疆福，百姓歡呼動九州。"]'),
('6fb86d7f-8cfd-4038-873a-943e0c61ed01','壽寧節祝聖壽  其一○','王禹偁','宋','宋诗','song-poetry','','[]','謫宦商於又解梁，二年不見赭袍光。',32,'全唐诗/poet.song.3000.json','["謫宦商於又解梁，二年不見赭袍光。", "重來班列雖疏遠，祝壽情深淚數行。"]'),
('c2a4f755-1777-49b0-b40e-d012996f5f8b','幕次閑吟  其一','王禹偁','宋','宋诗','song-poetry','','[]','二年憔悴詠江蘺，恩詔重教侍玉墀。',64,'全唐诗/poet.song.3000.json','["二年憔悴詠江蘺，恩詔重教侍玉墀。", "寓直掖垣休入夢，常參幕次且吟詩。", "新文自負山中集，舊吏多驚鬢畔絲。", "莫道諫官無一事，猶勝閑卧解州時。"]'),
('58ccc705-cc03-4138-afbe-0e3f9f0ee67c','幕次閑吟  其二','王禹偁','宋','宋诗','song-poetry','','[]','禁漏遲遲待玉班，坐愁身計忽長歎。',64,'全唐诗/poet.song.3000.json','["禁漏遲遲待玉班，坐愁身計忽長歎。", "時清偶直千載運，頭白重爲八品官。", "烏帽半欹殘月冷，馬鞭慵執曉霜寒。", "君恩未報心猶壯，不敢思歸七里灘。"]'),
('05641875-f7a4-4c23-8542-e6e02460365f','幕次閑吟  其三','王禹偁','宋','宋诗','song-poetry','','[]','文章曾受帝褒稱，幕次孤吟冷似冰。',64,'全唐诗/poet.song.3000.json','["文章曾受帝褒稱，幕次孤吟冷似冰。", "借馬趁朝長後到，問人求米盡難憑。", "僮教罷藥朝無酒，兒廢看書夜絕燈。", "除却金章在腰下，其餘滋味一如僧。"]'),
('6bef35f3-7631-4ade-ab4b-f723a7bdd0fa','幕次閑吟  其四','王禹偁','宋','宋诗','song-poetry','','[]','六里山中謫宦身，歸來無路掌絲綸。',64,'全唐诗/poet.song.3000.json','["六里山中謫宦身，歸來無路掌絲綸。", "階前不見朱衣吏，堂上空辭白髮親。", "月入可堪茶作俸，雨多還怯桂爲薪。", "懶求郡印緣何事，曾忝西垣侍從臣。"]'),
('8e125f4b-9d6f-4205-aa41-6825a1714a68','幕次閑吟  其五','王禹偁','宋','宋诗','song-poetry','','[]','江蘺吟盡鬢成霜，謫宦歸來夢一場。',64,'全唐诗/poet.song.3000.json','["江蘺吟盡鬢成霜，謫宦歸來夢一場。", "每日祇窺丹鳳案，被人猶喚紫微郎。", "齋宮獨坐風翻幕，客舍閑吟葉滿床。", "若是承明容再入，未曾荒廢舊文章。"]'),
('cf5bb81f-f9d9-4e93-9600-35ab0b16e67a','還韋度支韶程集','王禹偁','宋','宋诗','song-poetry','','[]','嶺南爲郡带名曹，萬里江山興詠饒。',96,'全唐诗/poet.song.3000.json','["嶺南爲郡带名曹，萬里江山興詠饒。", "皇宋聲詩歸雅正，有唐門地本逍遥。", "雪霜思苦雖侵鬢，金紫恩深已佩腰。", "舊草滿囊勝薏苡，幾聯乘醉寫芭蕉。", "進來聖主迴天眷，抄逐蠻僧過海潮。", "何事曹南得披覽，韶程風什似聞韶。"]'),
('853e44e0-fd67-45cd-ba0c-b54bb2729990','將赴單州和韋度支相送之什次韵','王禹偁','宋','宋诗','song-poetry','','[]','就養求官動聖知，專城猶得近王畿。',64,'全唐诗/poet.song.3000.json','["就養求官動聖知，專城猶得近王畿。", "鄉人竟指曾題柱，丘嫂應慚不下機。", "西掖罷批天子詔，北堂榮著老萊衣。", "鄰封唱和如多暇，三載須成一集歸。"]'),
('7698769c-314c-41cf-9ab3-9b6f9202a22e','初上單州有作','王禹偁','宋','宋诗','song-poetry','','[]','舊官休念直承明，就養雖能繫宦情。',64,'全唐诗/poet.song.3000.json','["舊官休念直承明，就養雖能繫宦情。", "藍綬昔年爲短簿，綵衣今日是專城。", "妓人半在登樓看，親老初來滿郡迎。", "慢逐板輿張皂蓋，平生唯有此時榮。"]'),
('d50ef37c-ee58-44be-a5e4-b92b52cd6691','送秘閣裴都監奉使兩浙','王禹偁','宋','宋诗','song-poetry','','[]','霏霏梅雨灑船窗，綠荇參差早稻黄。',64,'全唐诗/poet.song.3000.json','["霏霏梅雨灑船窗，綠荇參差早稻黄。", "捧詔暫辭圖籍府，揚帆深入水雲鄉。", "皇華靜讌江樓月，御札閑開野寺香。", "若到蘇臺人問我，長官重拜紫微郎。"]'),
('ecb48f7d-2662-45dc-b6aa-2d11446e1531','送戚殿丞之任括蒼','王禹偁','宋','宋诗','song-poetry','','[]','佐郡海西邊，掛帆離兔園。',48,'全唐诗/poet.song.3000.json','["佐郡海西邊，掛帆離兔園。", "遠經羅剎石，去近鶺鴒原。", "菊暖秋飛蝶，霜晴夜叫猿。", "老郎方吏隠，應笑市朝喧。"]'),
('b437c78f-e131-431b-8670-850fe67ba194','送馮中允之任婺州','王禹偁','宋','宋诗','song-poetry','','[]','東南宦迹多勝遊，婺女星下溪山幽。',64,'全唐诗/poet.song.3000.json','["東南宦迹多勝遊，婺女星下溪山幽。", "嚴陵隠德七里瀨，沈約詩名八詠樓。", "岸上黍離經故國，湖邊木脫正高秋。", "承明三入妨賢久，擬覓江鄉小郡侯。"]'),
('927ef71a-d165-4eac-9944-b34f7c1a188e','寄題義門胡氏華林書院','王禹偁','宋','宋诗','song-poetry','','[]','水閣山齋架碧虛，亭亭華表映門閭。',64,'全唐诗/poet.song.3000.json','["水閣山齋架碧虛，亭亭華表映門閭。", "力田歲取千箱稻，好事家藏萬卷書。", "旋對杯盤燒野筍，別開池沼養溪魚。", "吾生未有林泉計，空愧妨賢卧直廬。"]'),
('46a6ced9-d69f-465d-b39f-4c763ae4e5a1','送毋殿丞赴任齊州','王禹偁','宋','宋诗','song-poetry','','[]','三齊號難治，民瘼待良醫。',48,'全唐诗/poet.song.3000.json','["三齊號難治，民瘼待良醫。", "勿謂人多詐，須教吏不欺。", "魚鹽多近海，桑柘潤連淄。", "御札新頒曆，無忘訓誡詞。"]'),
('087204cb-f744-40e4-b4f4-904a1b538333','送張監察通判餘杭','王禹偁','宋','宋诗','song-poetry','','[]','郡城瀟洒浙江濱，暫輟乘驄慰遠民。',64,'全唐诗/poet.song.3000.json','["郡城瀟洒浙江濱，暫輟乘驄慰遠民。", "莫放霜威誇御史，且收風景屬詩人。", "雪侵樓上迎潮眼，花擁湖中泛月身。", "盡是公餘吟詠處，好飛佳句寄詞臣。"]'),
('2cc703c3-fb62-4899-998c-0c421c49e2d5','送楊屯田通判永興','王禹偁','宋','宋诗','song-poetry','','[]','長安棄廢比藩方，通理猶宜占省郎。',64,'全唐诗/poet.song.3000.json','["長安棄廢比藩方，通理猶宜占省郎。", "入洛才名齊二陸，有唐門戶本三楊。", "袖中丹桂家聲在，道畔豐碑祖德光。", "莫向公餘尋故第，榛蕪難認靖恭坊。"]'),
('7e85a6ad-6a00-455b-b696-0c1ba2dfda68','書齋','王禹偁','宋','宋诗','song-poetry','','[]','年年賃宅住閑坊，也作幽齋著道裝。',64,'全唐诗/poet.song.3000.json','["年年賃宅住閑坊，也作幽齋著道裝。", "守靜便爲生白室，著書兼是草玄堂。", "屏山獨卧千峰雪，御札時開一炷香。", "莫笑未歸田里去，宦途機巧盡能忘。"]'),
('9d995522-cc8c-45e7-92d0-82ff6ce887b5','書懷簡孫何丁謂','王禹偁','宋','宋诗','song-poetry','','[]','三入承明已七年，自慚蹤跡久妨賢。',64,'全唐诗/poet.song.3000.json','["三入承明已七年，自慚蹤跡久妨賢。", "吾子幾時歸鳳閣，病夫方欲買漁船。", "季路旨甘知已矣，潘安毛鬢更皤然。", "舉人自代何由得，歸去東皋種黍田。"]'),
('7c12bf60-d259-421d-a6b9-415224fef514','送柴諫議之任河中','王禹偁','宋','宋诗','song-poetry','','[]','蒲津名郡得名公，諫紙盈箱且罷封。',64,'全唐诗/poet.song.3000.json','["蒲津名郡得名公，諫紙盈箱且罷封。", "紅藥階墀曾吐鳳，綠莎廳事舊鳴蛬。", "下車首謁重華廟，入境先經五老峰。", "見說丘門詩板在，應教回也繼遺蹤。"]'),
('76098b21-39e2-4b4d-a758-edf38339556d','送僕射相公赴西京','王禹偁','宋','宋诗','song-poetry','','[]','五十升端揆，西郊任保釐。',192,'全唐诗/poet.song.3000.json','["五十升端揆，西郊任保釐。", "偶拋三事重，未失百僚師。", "府縣威儀引，宮城管鑰隨。", "粗官嫌出將，劇位是留司。", "櫻筍供筵饌，蜩蟬響路岐。", "碧紗題壁處，晝錦下車時。", "請雨摩騰塔，尋芳白傅祠。", "維嵩過舊隠，禊洛賦新詩。", "禮絕應懸榻，公餘尚讀碑。", "留臺咨拜表，內殿列須知。", "易退甘龍卧，難虛是鳳池。", "兩京全咫尺，三入不參差。", "康濟荒年穀，風標飣座梨。", "弼諧終在我，睠注更同誰。", "溫樹陰猶在，甘棠影暫垂。", "常濡玉堂筆，願草白麻詞。"]'),
('46205d96-8a61-4a8c-87b5-c444d9313442','送李著作','王禹偁','宋','宋诗','song-poetry','','[]','芸閣新銜捧詔歸，歷陽湖畔拜庭闈。',64,'全唐诗/poet.song.3000.json','["芸閣新銜捧詔歸，歷陽湖畔拜庭闈。", "已聞愛子披朱紱，猶學嬰兒著綵衣。", "飯饋海陵紅稻軟，鱠擎淮水白魚肥。", "吾生自失榮親祿，謾踏花磚入北扉。"]'),
('e0b3c74b-5094-41da-9186-56442707259e','送禮部蘇侍郎赴南陽','王禹偁','宋','宋诗','song-poetry','','[]','拜命辭台席，扶親道更光。',120,'全唐诗/poet.song.3000.json','["拜命辭台席，扶親道更光。", "風流在東閣，優逸是南陽。", "治篋排宸翰，行衣带御香。", "袴襦編戶暖，扇枕板輿凉。", "鈴閣留僧飯，書齋著道裝。", "遺蹤尋耿鄧，善政法龔黄。", "潭凈秋收菊，郊平曉坐棠。", "未應淹郡國，即是復巖廊。", "一息同鵬鳥，重來浴鳳皇。", "貳卿三十八，羞殺老馮唐。"]'),
('f64491ae-49b6-4b1b-a2f9-bee81f533198','制除工部郎中出內署','王禹偁','宋','宋诗','song-poetry','','[]','溫樹陰中別玉堂，應星猶得入文昌。',32,'全唐诗/poet.song.3000.json','["溫樹陰中別玉堂，應星猶得入文昌。", "莫嫌工部官曹慢，杜甫才名是外郎。"]'),
('f0178b36-6b52-4232-91d2-6874acbd6719','詔知滁州軍州事因題二首  其一','王禹偁','宋','宋诗','song-poetry','','[]','曉直銀臺作侍臣，暮爲郎吏入埃塵。',64,'全唐诗/poet.song.3000.json','["曉直銀臺作侍臣，暮爲郎吏入埃塵。", "一生大抵如春夢，三黜何妨似古人。", "不稱禁中批紫詔，猶教淮上擁朱輪。", "時清郡小應多暇，感激君恩養病身。"]'),
('852d7c05-a96d-4633-ab18-f61d133e7527','詔知滁州軍州事因題二首  其二','王禹偁','宋','宋诗','song-poetry','','[]','罷直金鑾領一麾，依前顦悴詠江蘺。',64,'全唐诗/poet.song.3000.json','["罷直金鑾領一麾，依前顦悴詠江蘺。", "所嗟吾道關消長，豈爲微軀繫盛衰。", "尚愧臨民爲父母，終當學稼養妻兒。", "自憐此度辭京闕，猶勝商山副使時。"]'),
('e15fe3c2-1130-478c-a7bf-e4af4af5c241','滁州官舍  其一','王禹偁','宋','宋诗','song-poetry','','[]','忽從天上謫人間，知向山州住幾年。',64,'全唐诗/poet.song.3000.json','["忽從天上謫人間，知向山州住幾年。", "俸外不教收果實，公餘多愛入林泉。", "朝簪未解雖妨道，宦路無機即是禪。", "鈴閣悄然私自問，郡齋何異玉堂前。"]'),
('7720debf-63ff-4319-af00-ea460615e5d2','滁州官舍  其二','王禹偁','宋','宋诗','song-poetry','','[]','失職金鑾假一麾，瑯邪山色遶城池。',64,'全唐诗/poet.song.3000.json','["失職金鑾假一麾，瑯邪山色遶城池。", "解龜且作三年調，下馬先吟八絕詩。", "勾檢簿書寧免俗，逢迎使命亦隨時。", "公餘不敢妨吟詠，異日聲名繼至之。"]'),
('65530056-743a-403c-bbe8-4ff0651c74d3','堂前井','王禹偁','宋','宋诗','song-poetry','','[]','公署在山上，鑿泉深且清。',48,'全唐诗/poet.song.3000.json','["公署在山上，鑿泉深且清。", "一杯水溜滿，六月火雲生。", "利物誠堪拜，投錢惡近名。", "飲之何以報，官況與詩情。"]'),
('af4f64ef-30fb-4327-bf07-ead90f201ba3','荒亭晚坐','王禹偁','宋','宋诗','song-poetry','','[]','荒亭秋日沉，獨坐白頭吟。',48,'全唐诗/poet.song.3000.json','["荒亭秋日沉，獨坐白頭吟。", "爲郡殊無味，歸田素有心。", "鵲翻楓葉亂，蛬響菊叢深。", "微物休相聒，幽懷老不禁。"]'),
('f2326c39-df67-43b4-b3bf-a84b8cd1fbe8','身世','王禹偁','宋','宋诗','song-poetry','','[]','淮邊爲小郡，身世復何云。',48,'全唐诗/poet.song.3000.json','["淮邊爲小郡，身世復何云。", "妻病無醫藥，兒癡廢典墳。", "簪裳看似夢，俸祿薄如雲。", "不作歸耕計，何階望致君。"]');
